-- Poems batch 338
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('a3fd9978-0da0-4de7-9881-c65e2da88575','田園四時 春 其二','華鎮','宋','宋诗','song-poetry','','[]','細風吹盡桑黄紫，綠暗柔條添旖旎。',64,'全唐诗/poet.song.60000.json','["細風吹盡桑黄紫，綠暗柔條添旖旎。", "晚來逐伴望林梢，三星便欲當辰巳。", "節過清明未云遠，碎髮新蠶已盈紙。", "遲日融融暖有餘，早晚應須候眠起。"]'),
('6157f2b1-6718-4c5e-b4ee-63311119996b','田園四時 秋 其一','華鎮','宋','宋诗','song-poetry','','[]','萬頃秋來雲葉黄，瓜田起盡築新場。',64,'全唐诗/poet.song.60000.json','["萬頃秋來雲葉黄，瓜田起盡築新場。", "茅簷昨夜微霜下，天高氣爽風日强。", "明星未上腰鐮去，歸路不辭乘月光。", "隴頭薄暮片雲起，明日晴陰未可量。"]'),
('320279e9-ba53-45e9-9b77-9c06b47a0b12','田園四時 秋 其二','華鎮','宋','宋诗','song-poetry','','[]','階頭露草珠盈縷，門前促織分明語。',64,'全唐诗/poet.song.60000.json','["階頭露草珠盈縷，門前促織分明語。", "日午簾帷氣已清，香肌暗喜消殘暑。", "蚊蚋無聲燈火冷，已將紈扇歸巾褚。", "更長便合促鳴機，月白何妨弄砧杵。"]'),
('11ffb7ae-8103-4715-b27f-d2c287897920','田園四時 冬 其一','華鎮','宋','宋诗','song-poetry','','[]','田家歲事霜飛後，五種收成十分有。',64,'全唐诗/poet.song.60000.json','["田家歲事霜飛後，五種收成十分有。", "征輸早了吏不來，柴荆晝掩閒雞狗。", "兒童飽暖歡呼走，堂上樽罍湛春酒。", "力耕歲晚足餘歡，五陵裘馬真遊手。"]'),
('45a9f688-9919-4f71-8f24-13e3da4b485e','田園四時 冬 其二','華鎮','宋','宋诗','song-poetry','','[]','朔風吹水成冰堅，風壯冰堅白於練。',64,'全唐诗/poet.song.60000.json','["朔風吹水成冰堅，風壯冰堅白於練。", "霰雪還隨密雨來，轉眼紛紛滿溝垾。", "陳根凍爛還爲土，土落田中肥一半。", "霜鐮去手即須耕，敢望東風待冰泮。"]'),
('75119d01-ac31-404a-ac3e-aef69a6cdb18','田園四時 冬 其三','華鎮','宋','宋诗','song-poetry','','[]','粉蠟梅梢妝蓓蕾，雪晴烏鵲聲零碎。',64,'全唐诗/poet.song.60000.json','["粉蠟梅梢妝蓓蕾，雪晴烏鵲聲零碎。", "蘭堂晝暖浴蠶天，百果流芳噴寒水。", "春事望春須準擬，臨風不惜呵纖指。", "寒日頻添繡線長，百五光陰已無幾。"]'),
('3428a888-088d-46af-852a-3132931f81ea','題桃源圖','華鎮','宋','宋诗','song-poetry','','[]','枝頭巧語聲高低，波光葱蒨深柔荑。',384,'全唐诗/poet.song.60000.json','["枝頭巧語聲高低，波光葱蒨深柔荑。", "烘爖日暖金鱗動，漁舟蕩漾沿芳隄。", "淡紅片玉滿流水，中有誰家桃李蹊。", "刺棹沿洄忘遠近，山重水轉迷東西。", "金豪瞥見林中犬，玉羽旋聞隴上雞。", "相逢巾屨如圖畫，驚聞有客爭邀携。", "穿花行到花盡處，華鋪晝敞同攀躋。", "簾櫳炫熀鬭金碧，樓閣玲瓏凝紫霓。", "瓊杯石髓甘如醍，碧桃瑩膩堆玻瓈。", "殷勤歷問塵寰事，聞說興替聲如嘶。", "自言疇昔避閭左，鄉鄰負抱謀巖棲。", "入山惟憂山路淺，穿雲涉水隨麏麛。", "山深遂與人境絕，回首但見雲萋萋。", "年年桃花又桃實，不聞劉項鳴鉦鼙。", "當時祇恨棄桑梓，此日却悟凌丹梯。", "酒闌歷覽烟霞外，天風淅淅鵷雛啼。", "塵羈世網遠心目，年齡便可乾坤齊。", "俗緣如瑕滌不去，荆布還念糟糠妻。", "思家欲歸歸却悔，憶路重來來已迷。", "碧砌朱欄無處覓，溪長烟草寒凄凄。", "玉京雲路今何在，千年圖寫傳繒緹。", "高堂衆客一經目，盡願乘景騎狻猊。", "祖龍虐政猛於虎，療饑消渴資黔黎。", "霜髯黄口不相保，四海慘戚如牢狴。"]'),
('aefc81cf-7e72-4691-b795-e6e68348f12a','失題','華鎮','宋','宋诗','song-poetry','','[]','蜂鬚萎蕤花脫萼，粉蝶流鶑何處著。',96,'全唐诗/poet.song.60000.json','["蜂鬚萎蕤花脫萼，粉蝶流鶑何處著。", "暖融密卷玉爲椽，一點明星坐中落。", "猩唇血重鮫綃薄，百出寶蓮金鈿錯。", "蕙蘭不斷起長烟，餘香隨風度羅幕。", "天階漫激鳴籤響，壺中不夜春常若。", "何人天外引長繩，剛愁日下西山脚。"]'),
('6ad630c1-e10a-4384-87ce-5f6015f401a1','嶽麓寺','華鎮','宋','宋诗','song-poetry','','[]','衡嶽到江盡，招提嶽秀中。',48,'全唐诗/poet.song.60000.json','["衡嶽到江盡，招提嶽秀中。", "飛樓上喬木，清梵俯冥鴻。", "鶴去泉猶在，臺存法更雄。", "望終三楚勝，清興迥無窮。"]'),
('73b12c3f-1cb3-40cf-87c8-5b6c84660b4f','道林寺','華鎮','宋','宋诗','song-poetry','','[]','疏鐘到城市，臺殿隠修林。',48,'全唐诗/poet.song.60000.json','["疏鐘到城市，臺殿隠修林。", "訪古多陳迹，探幽愜賞心。", "夜聲寒溜碎，曉色翠烟深。", "自愧縻塵鞅，驪駒又見尋。"]'),
('942a50cb-57b7-40d4-9b78-8462280f1006','齊無己書堂','華鎮','宋','宋诗','song-poetry','','[]','騷客高吟地，山僧指舊基。',48,'全唐诗/poet.song.60000.json','["騷客高吟地，山僧指舊基。", "虛堂非昔搆，清景是當時。", "石甃流泉漫，松軒度日遲。", "鯈魚有餘樂，池上竟誰知。"]'),
('010d56d4-3591-49aa-9cbd-58f7bb2a5ea0','湘江二妃廟','華鎮','宋','宋诗','song-poetry','','[]','帝子靈祠古，秋風更寂寥。',48,'全唐诗/poet.song.60000.json','["帝子靈祠古，秋風更寂寥。", "門臨湘水迥，路指舜陵遥。", "寶瑟知何在，英魂不可招。", "年年添淚竹，遺恨未應消。"]'),
('048c9a24-dd5b-40bf-8c66-7aad40a5f1cb','長沙王廟','華鎮','宋','宋诗','song-poetry','','[]','秦吏方搖毒，君王獨得名。',48,'全唐诗/poet.song.60000.json','["秦吏方搖毒，君王獨得名。", "國雖爲地小，忠亦自天成。", "秘殿儀容粹，玄堂草木榮。", "興亡何足道，青竹有嘉聲。"]'),
('865aea65-ce3c-4a97-a9b6-29aaa5cea878','賈太傅廟','華鎮','宋','宋诗','song-poetry','','[]','夫子生何代，漂流正所宜。',48,'全唐诗/poet.song.60000.json','["夫子生何代，漂流正所宜。", "長鳴那易賞，合抱固難施。", "碧蘚封遺井，丹楓落舊祠。", "日斜飛鵩過，依約賦成時。"]'),
('32fd823d-2d2f-4ff8-ba09-b87522b3b4bd','畫眉鋪','華鎮','宋','宋诗','song-poetry','','[]','湘楚窮愁地，何名得畫眉。',48,'全唐诗/poet.song.60000.json','["湘楚窮愁地，何名得畫眉。", "不因啼鳥目，應記剪燈詩。", "逐客傷憔悴，征人困別離。", "風流京兆尹，寧復此飛馳。"]'),
('ead2a74a-b570-4ada-aad7-86cde8d17dc4','愚溪','華鎮','宋','宋诗','song-poetry','','[]','瀟湘同瀉處，一水亦東傾。',48,'全唐诗/poet.song.60000.json','["瀟湘同瀉處，一水亦東傾。", "屈曲游龍勢，玲瓏戛玉聲。", "傍城無暫濁，當暑有餘清。", "楚俗真懷古，猶傳夢客名。"]'),
('e46e7a32-8d60-4aea-8dbc-0913eade5b70','無生菴','華鎮','宋','宋诗','song-poetry','','[]','大士今何在，空山舊隠存。',48,'全唐诗/poet.song.60000.json','["大士今何在，空山舊隠存。", "百年閑蘚徑，終日敞塵閽。", "砌暖晴添草，窗寒暝叫猿。", "當時團坐客，相顧竟何言。"]'),
('0d6e3a27-2564-431c-992a-bab9022d237c','雜詠','華鎮','宋','宋诗','song-poetry','','[]','上下契如如，忘機示有爲。',48,'全唐诗/poet.song.60000.json','["上下契如如，忘機示有爲。", "室虛窗潔素，塵盡地平夷。", "社燕添新土，春花發舊枝。", "此中君莫問，自有海鷗知。"]'),
('0e0a10d7-f5b9-4163-bdf1-8d6c12ddecb0','永嘉巡檢廳奇竹','華鎮','宋','宋诗','song-poetry','','[]','脩竹趁春陽，猗猗出畫堂。',48,'全唐诗/poet.song.60000.json','["脩竹趁春陽，猗猗出畫堂。", "孤根穿密甃，高幹倚飛梁。", "色潤窗紗綠，烟和印篆香。", "傳聞尤異處，清夜露瀼瀼。"]'),
('77fd65b6-038e-42fd-87a2-9c977efa3309','和孫秀才與弟醉飲','華鎮','宋','宋诗','song-poetry','','[]','醺酣歸至樂，麴糵古來賢。',48,'全唐诗/poet.song.60000.json','["醺酣歸至樂，麴糵古來賢。", "荆樹同株日，蕭齋欲雪天。", "傾頹叔夜玉，臬兀季真船。", "熟覽新詩意，依稀識道筌。"]'),
('a63cf574-a318-4f75-9487-dc388790ede8','題黄主簿足軒','華鎮','宋','宋诗','song-poetry','','[]','枳棘久棲遲，新齋樂有餘。',48,'全唐诗/poet.song.60000.json','["枳棘久棲遲，新齋樂有餘。", "尋垣栽草木，疏沼引龜魚。", "外曲遊塵世，情高適太虛。", "紛紛簿領退，滿目盡琴書。"]'),
('5347184b-f32b-43ef-877c-027ea7e93bd8','東海','華鎮','宋','宋诗','song-poetry','','[]','誰謂滄溟遠，吾家曲檻東。',48,'全唐诗/poet.song.60000.json','["誰謂滄溟遠，吾家曲檻東。", "靈潮隨月長，積水與天通。", "白鳥長沙外，青峰薄霧中。", "星槎在何處，屈指待秋風。"]'),
('1d473c28-34c9-48d1-b0ee-7e11abdbbd57','聞韶亭','華鎮','宋','宋诗','song-poetry','','[]','重華祠宇下，危構壓山椒。',48,'全唐诗/poet.song.60000.json','["重華祠宇下，危構壓山椒。", "壁石因天設，茨茆得舊條。", "雲山排筍簴，風竹度笙簫。", "想見來儀羽，飛飛下泬寥。"]'),
('7ab71db4-9e1d-4d93-aed9-7defea079dd8','會景亭','華鎮','宋','宋诗','song-poetry','','[]','此亭會清景，登眺適襟靈。',48,'全唐诗/poet.song.60000.json','["此亭會清景，登眺適襟靈。", "烟瀨鳴瑶珮，雲峰疊翠屏。", "漁樵分杳靄，鷗鷺上青冥。", "□□□□□，□□□□□。"]'),
('9158e2ac-e01f-413b-bd4c-a8851572cce2','翠微亭','華鎮','宋','宋诗','song-poetry','','[]','虛閣俯蒼麓，飛甍倚碧岑。',48,'全唐诗/poet.song.60000.json','["虛閣俯蒼麓，飛甍倚碧岑。", "鮮英環坐密，青靄抱楹深。", "秀遠開塵目，清明契夙心。", "带星宜所慕，聊此叩徽音。"]'),
('3aa70241-731a-4951-b0d2-bfd9a50dfb67','棲雲閣','華鎮','宋','宋诗','song-poetry','','[]','高閣倚蒼岫，山雲且暮棲。',48,'全唐诗/poet.song.60000.json','["高閣倚蒼岫，山雲且暮棲。", "冷凝半榻穩，濃拂遠燈迷。", "戶轉星樞直，窗移日脚低。", "登臨人莫厭，尋取上天梯。"]'),
('8fcc7a5f-0755-4e90-a413-7ccc2adf64a1','秦淮','華鎮','宋','宋诗','song-poetry','','[]','渺渺方山道，江流一派通。',48,'全唐诗/poet.song.60000.json','["渺渺方山道，江流一派通。", "寒沙翹白鷺，夕靄暝丹楓。", "平截埋金地，虛涵建鄴宮。", "六朝乘王氣，疏鑿竟無功。"]'),
('68eeeece-23c5-4c79-82bb-c51566a8db6c','澄瀾閣','華鎮','宋','宋诗','song-poetry','','[]','飛欄跨喬木，危柱枕蒼磯。',48,'全唐诗/poet.song.60000.json','["飛欄跨喬木，危柱枕蒼磯。", "石潄溪聲碎，林分日影稀。", "正宜逃暑氣，聊用解征衣。", "欲去重回首，清風滿翠微。"]'),
('c0bee369-f876-4120-a0b0-d0cb1d812806','元祐六年秋夜泊震澤時漲潦未盡牽道斷毀仍阻風','華鎮','宋','宋诗','song-poetry','','[]','四顧水天平，扁舟竟日撐。',48,'全唐诗/poet.song.60000.json','["四顧水天平，扁舟竟日撐。", "孤村聊可艤，薄暮不成行。", "雲重魚龍起，風高波浪驚。", "無心就衾枕，坐看月華生。"]'),
('f90dcb4e-ab8d-451b-b0df-463967a11942','君山','華鎮','宋','宋诗','song-poetry','','[]','特秀起平湖，秋空照日孤。',48,'全唐诗/poet.song.60000.json','["特秀起平湖，秋空照日孤。", "無塵接南楚，有路到東吳。", "聚翠時濃淡，長林半有無。", "未能尋勝賞，飛夢遶烟蕪。"]'),
('ae10b063-ad0c-4607-b8e6-dcf44de6602b','狼山','華鎮','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','長江到海處，獨秀峙江干。',48,'全唐诗/poet.song.60000.json','["長江到海處，獨秀峙江干。", "平野根雖闊，驚濤迹未殘。", "高環僧剎穩，翠入郡樓寒。", "千里吳王國，臨窗仔細看。"]'),
('cee166d1-7bdc-4d2a-8c23-7433ee949f27','洞庭','華鎮','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','險固三苗左，茫洋七澤西。',48,'全唐诗/poet.song.60000.json','["險固三苗左，茫洋七澤西。", "山光千疊小，天碧四垂低。", "風便修途近，波驚跬步迷。", "誰知魚鳥樂，不復待鞉鞞。"]'),
('4879cbf3-6a7c-4970-816f-50ad0864585b','李仙姑舊隠','華鎮','宋','宋诗','song-poetry','','[]','雲卧人猶近，團茆迹已空。',48,'全唐诗/poet.song.60000.json','["雲卧人猶近，團茆迹已空。", "秀巖孤海外，修竹冷江風。", "笙鶴今誰賞，星河舊隠通。", "何當見金碧，華采照淮東。"]'),
('2f634bf6-cd20-427f-90e1-b38859a44e30','密雨','華鎮','宋','宋诗','song-poetry','','[]','昨夜好風月，須明陟路岐。',48,'全唐诗/poet.song.60000.json','["昨夜好風月，須明陟路岐。", "陰雲生隴上，密雨滿天涯。", "豈患泥塗惡，難堪僕馬疲。", "却愁期會失，心緒亂如絲。"]'),
('c90267cc-28f3-44a9-ab44-63c057885562','桃竹','華鎮','宋','宋诗','song-poetry','','[]','栽竹不栽桃，非關閬苑遥。',48,'全唐诗/poet.song.60000.json','["栽竹不栽桃，非關閬苑遥。", "桃花半春落，竹葉無時凋。", "照水靜蒼翠，吟風冷飄蕭。", "歲寒筠更綠，雨雪謾瀌瀌。"]'),
('b997fc22-f8d6-47b6-8768-e32583086ef3','早梅花二首  其一','華鎮','宋','宋诗','song-poetry','','[]','早歲越溪上，茆齋欲雪辰。',48,'全唐诗/poet.song.60000.json','["早歲越溪上，茆齋欲雪辰。", "雖無十日飲，常得一枝春。", "不識霄漢路，空緇京洛塵。", "遥憐遠巖壑，芳秀爲誰新。"]'),
('7507b228-1621-4e9e-a014-76671293f03e','早梅花二首  其二','華鎮','宋','宋诗','song-poetry','','[]','畢竟成何事，無端走四方。',48,'全唐诗/poet.song.60000.json','["畢竟成何事，無端走四方。", "年年思素質，歲歲失幽香。", "東國溪雲好，南枝海日長。", "何時一杯酒，相對淺清傍。"]'),
('213b815f-40da-4f78-8b4b-5813c4f3ac85','次韵酬劉處道','華鎮','宋','宋诗','song-poetry','','[]','漂泊人間世，幾鄰耳順年。',48,'全唐诗/poet.song.60000.json','["漂泊人間世，幾鄰耳順年。", "心愚顓直道，步蹇失英躔。", "星列真虛忝，仙枝亦偶然。", "雄飛君未晚，何歉續韋編。"]'),
('a53e7706-2586-4c6e-876e-540c28635181','千瓣二色桃花','華鎮','宋','宋诗','song-poetry','','[]','迥出成蹊類，尤深造物功。',48,'全唐诗/poet.song.60000.json','["迥出成蹊類，尤深造物功。", "細攢重疊瓣，勻賦淺深紅。", "艷質平分異，香心一點同。", "武陵溪上樹，虛占好春風。"]'),
('933fa035-b464-439c-a7e0-f43d8b3ec26a','慶親堂和湖南運使程大卿韵','華鎮','宋','宋诗','song-poetry','','[]','輪奐非謀己，標題慶有親。',48,'全唐诗/poet.song.60000.json','["輪奐非謀己，標題慶有親。", "盈庖欣釜粟，照座得言綸。", "集富稱觴客，寬容戲綵人。", "遥知映階砌，丹桂及芳春。"]'),
('3a18e7ff-2745-48cf-84ab-a16e8de591eb','思歸二首  其一','華鎮','宋','宋诗','song-poetry','','[]','湖光清似鑑，山色翠於眉。',48,'全唐诗/poet.song.60000.json','["湖光清似鑑，山色翠於眉。", "投老身須逸，探幽計莫遲。", "河清不可待，頭白已多時。", "誰謂茆茨陋，求安過一枝。"]'),
('8c6ed405-bdb7-4bab-bb69-dedb42fc476e','思歸二首  其二','華鎮','宋','宋诗','song-poetry','','[]','二頃何時有，鄉園且結廬。',48,'全唐诗/poet.song.60000.json','["二頃何時有，鄉園且結廬。", "憑軒見巖壑，閉戶得琴書。", "雪幌冬鑪暖，風窗夏簟虛。", "非才甘退縮，不是傲簪裾。"]'),
('229e85a1-dc57-40f1-b1d4-afa0206daa54','送道守董朝散','華鎮','宋','宋诗','song-poetry','','[]','史筆傳遺直，經帷起世家。',48,'全唐诗/poet.song.60000.json','["史筆傳遺直，經帷起世家。", "一麾分郡寄，千里藹春華。", "鳴阪方睎驥，言時已及瓜。", "車塵杳難逐，飛夢遶天涯。"]'),
('ad740b33-9b9a-47cf-973a-6846b704dccb','挽兖守程大卿四首  其一','華鎮','宋','宋诗','song-poetry','','[]','名實時方會，君臣德正同。',48,'全唐诗/poet.song.60000.json','["名實時方會，君臣德正同。", "剸裁周庶物，薦擢冠諸公。", "金口褒揚首，丹梯指顧中。", "榮途雖未既，尋尺自初終。"]'),
('04867ee9-f938-4aa7-905d-9926defda1d3','挽兖守程大卿四首  其二','華鎮','宋','宋诗','song-poetry','','[]','徊翔卿寺棘，轉漕楚江舟。',48,'全唐诗/poet.song.60000.json','["徊翔卿寺棘，轉漕楚江舟。", "忠厚臨人大，勤勞結課優。", "丹枝方習慶，梁木忽驚秋。", "天意寧無在，于門必有侯。"]'),
('afe9b4d2-895a-4701-a726-3baf29ab14af','挽兖守程大卿四首  其三','華鎮','宋','宋诗','song-poetry','','[]','交遊敦久要，賞鑒謝先容。',48,'全唐诗/poet.song.60000.json','["交遊敦久要，賞鑒謝先容。", "自愧非王粲，人驚得蔡邕。", "堊漫猶在刃，舟壑已遺蹤。", "不見星躔處，空瞻馬鬣封。"]'),
('fbb52ced-caf2-4325-a348-e0d0be57514f','挽兖守程大卿四首  其四','華鎮','宋','宋诗','song-poetry','','[]','憶昨湘江上，追風送使帆。',48,'全唐诗/poet.song.60000.json','["憶昨湘江上，追風送使帆。", "青雲方滿路，丹旐忽垂縿。", "燕舞難重見，霞杯不復銜。", "遥憐三徑菊，冷落對雙巖。"]'),
('dfef4603-8f90-444d-9d94-c4253e996ef1','壽蔡大資留守','華鎮','宋','宋诗','song-poetry','','[]','四氣成功月，三陽得數辰。',48,'全唐诗/poet.song.60000.json','["四氣成功月，三陽得數辰。", "昴星還輔漢，崧嶽復生申。", "事業乘時會，心源體道真。", "燕來新賜第，相賀八千春。"]'),
('1b35cc18-64a7-4059-9752-04b2daf56afb','挽嚴四府君','華鎮','宋','宋诗','song-poetry','','[]','歲事時無失，先疇手自耘。',48,'全唐诗/poet.song.60000.json','["歲事時無失，先疇手自耘。", "克家親有養，投老意彌勤。", "方羨高年慶，旋驚白日曛。", "可憐墳上土，仍占壠頭雲。"]'),
('825b7fa0-976f-41da-9ebe-2e7b75419109','挽鄭十一府君並夫人','華鎮','宋','宋诗','song-poetry','','[]','君子言無玷，夫人德有鄰。',48,'全唐诗/poet.song.60000.json','["君子言無玷，夫人德有鄰。", "絲桐人世遠，窀穸隴頭新。", "粧閤閑明鏡，吟窗積暗塵。", "西風原上路，鳴鐸爲悲辛。"]'),
('a7f8f580-d5c8-4639-83f4-3ae2ec1d127b','挽蔣尊師','華鎮','宋','宋诗','song-poetry','','[]','少報羽人衣，年耆道更肥。',48,'全唐诗/poet.song.60000.json','["少報羽人衣，年耆道更肥。", "未容青雀至，俄駕白雲歸。", "海上蟠桃熟，人間晚露稀。", "空留墨妙在，鸞鶴自翻飛。"]'),
('b52347f9-9f61-4421-92b1-b5cb115dbc12','挽傅仲溫','華鎮','宋','宋诗','song-poetry','','[]','人是南州老，家傳北地雄。',48,'全唐诗/poet.song.60000.json','["人是南州老，家傳北地雄。", "忽騎箕尾去，不待大丹功。", "華屋閑歌席，長楊慘暮風。", "已符同穴契，寧復念孤桐。"]'),
('3a941b0a-322b-4410-98c3-cf3cbfa701a6','挽馮際道','華鎮','宋','宋诗','song-poetry','','[]','令德稱鄉黨，風流有自來。',48,'全唐诗/poet.song.60000.json','["令德稱鄉黨，風流有自來。", "能仁曾益壽，善計亦豐財。", "鳳羽彌增秀，車門既有開。", "祗憐原上路，松柏莫風哀。"]'),
('0980f91d-9eed-4bda-a954-2d1fb3eb6945','挽周祖文','華鎮','宋','宋诗','song-poetry','','[]','蠲辰臨遠日，祖奠徹中楹。',48,'全唐诗/poet.song.60000.json','["蠲辰臨遠日，祖奠徹中楹。", "寒月銘旌影，霜風晚鐸聲。", "夜臺無曉日，泉路斷回程。", "已矣生前事，空勞問代耕。"]'),
('2edd45c3-4a9b-476f-8505-5ed9a17a1f29','挽馮戶曹','華鎮','宋','宋诗','song-poetry','','[]','干祿名雖嗇，承家實自肥。',48,'全唐诗/poet.song.60000.json','["干祿名雖嗇，承家實自肥。", "身全五福美，數過百年稀。", "有裕居清世，何嗟掩夜扉。", "芝蘭更盈畹，指日見光輝。"]'),
('db6ac1b0-bbb6-4c83-8e11-b19e808aaef6','挽陳朝奉','華鎮','宋','宋诗','song-poetry','','[]','疇昔鄉評事，風流出後生。',48,'全唐诗/poet.song.60000.json','["疇昔鄉評事，風流出後生。", "早聯華萼秀，先得桂枝榮。", "守死尊文墨，持平御重輕。", "已焉休茹恨，三鳳佇飛鳴。"]'),
('e2bc36a0-db8b-482a-b0f0-3bbb6e1d9b22','挽馮通直','華鎮','宋','宋诗','song-poetry','','[]','功名早自期，策足有餘貲。',48,'全唐诗/poet.song.60000.json','["功名早自期，策足有餘貲。", "世路多荆棘，榮途失羽儀。", "素絲寧復理，青眼不勝悲。", "千古秦山路，霜風歲暮時。"]'),
('ccf3d5d8-2791-44ed-ab55-b4738f1a45bf','挽毛夫人','華鎮','宋','宋诗','song-poetry','','[]','守義惟賢婦，夫人更妙年。',48,'全唐诗/poet.song.60000.json','["守義惟賢婦，夫人更妙年。", "紛華人自競，始卒意彌堅。", "善慶曾無爽，家聲既有傳。", "秀眉歸永夜，無愧及重泉。"]'),
('938ce47d-c967-4b7b-ad2a-6b682b103e0a','挽鍾氏夫人','華鎮','宋','宋诗','song-poetry','','[]','處號閨房秀，歸稱內助賢。',48,'全唐诗/poet.song.60000.json','["處號閨房秀，歸稱內助賢。", "豐華歡壯齒，甘旨慶高年。", "鄉譽良人重，家聲嗣子傳。", "道傍多健羨，寧貴一潸然。"]'),
('9bac9314-d7eb-409d-8d49-1f18064a74bc','挽陳氏夫人','華鎮','宋','宋诗','song-poetry','','[]','純貞謝琢磨，報施竟無訛。',48,'全唐诗/poet.song.60000.json','["純貞謝琢磨，報施竟無訛。", "義守三從固，身膺五福多。", "有言貽綵服，無恨屬頹波。", "行路惟稱歎，寧悲薤露歌。"]'),
('6ee4fe43-8495-45a2-82a0-4355382bb9b8','和光道元日書事二首  其一','華鎮','宋','宋诗','song-poetry','','[]','蕪城池苑盡荒殘，春到長思競秀山。',64,'全唐诗/poet.song.60000.json','["蕪城池苑盡荒殘，春到長思競秀山。", "谷口風和鶑已出，天南日轉雁初還。", "千家簾幕峰巒上，百里笙歌水竹間。", "記得當年行樂事，韶光不放片時閒。"]'),
('9869145f-076e-47ce-b7fd-5b537f7234d1','和光道元日書事二首  其二','華鎮','宋','宋诗','song-poetry','','[]','急管妖弦朝暮聞，翠帘下應當壚君。',64,'全唐诗/poet.song.60000.json','["急管妖弦朝暮聞，翠帘下應當壚君。", "叫呼梟盧一百萬，砍削兕脯三千斤。", "孔座嘉客每日滿，楊園細草何須耘。", "夜長秉燭可爲樂，春色三分未一分。"]'),
('be29daae-b818-497b-83b8-bd2c61f06768','元豐六年正月二十九日季壬生徐元立以詩來賀用韵酬之','華鎮','宋','宋诗','song-poetry','','[]','芳荆堂下兩枝長，一本朝來産此旁。',64,'全唐诗/poet.song.60000.json','["芳荆堂下兩枝長，一本朝來産此旁。", "敢謂他年當似驥，且期今日得如岡。", "顧余已免重占虺，聞子還思待弄璋。", "多謝見貽真錦繡，歸時應得衒吾鄉。"]'),
('89127133-aab5-4efd-a95e-002f4791e1a0','石筍','華鎮','宋','宋诗','song-poetry','','[]','小窗西下碧溪隅，片石干雲一筍麤。',64,'全唐诗/poet.song.60000.json','["小窗西下碧溪隅，片石干雲一筍麤。", "蒼蘚長時斑點露，老藤蟠處節痕紆。", "不須凡木裝佳色，自有靈花入畫圖。", "爲美又應勝竹箭，堅高元與衆材殊。"]'),
('b34fbe77-9ab4-45ee-a35e-759bd726a9f5','養竹詩','華鎮','宋','宋诗','song-poetry','','[]','莫笑青青一兩莖，春來次第滿林生。',64,'全唐诗/poet.song.60000.json','["莫笑青青一兩莖，春來次第滿林生。", "露凝節目猶含粉，風過枝梢已有聲。", "拂拭且看霜雪幹，剪裁當見鳳凰鳴。", "繁枝去盡生微逕，幾爲清陰特地行。"]'),
('9fe75829-0ce9-4458-89ae-64ee541e5ee2','和光道春日雨寒','華鎮','宋','宋诗','song-poetry','','[]','細風密雨冷相添，天右餘寒勢未殲。',64,'全唐诗/poet.song.60000.json','["細風密雨冷相添，天右餘寒勢未殲。", "漠漠亂絲凝曠野，涓涓碎玉下重簷。", "凌晨預約陽光發，入夜先聞霰雪兼。", "蝶夢未成欹寶枕，銅壺聲咽凍孤蟾。"]'),
('4009427e-e570-4041-a6c4-cee5a6ea45d7','元豐六年二月檢田凌塘中馬上口占因簡德器主簿','華鎮','宋','宋诗','song-poetry','','[]','强半春光未足看，花心柳眼尚盤桓。',64,'全唐诗/poet.song.60000.json','["强半春光未足看，花心柳眼尚盤桓。", "景陽不放融怡色，密雨猶矜料峭寒。", "借問董工湮沮洳，何如騎馬按岡巒。", "幾番回首自惆悵，可借江南一釣竿。"]'),
('9cd59101-eb58-4dbd-a534-3e6b2d647593','和陳尉見貽二首  其一','華鎮','宋','宋诗','song-poetry','','[]','畫棟塵驚燕子來，芳郊時雨斂輕埃。',64,'全唐诗/poet.song.60000.json','["畫棟塵驚燕子來，芳郊時雨斂輕埃。", "須憐好景分明在，爲把愁顔勉强開。", "仙客有情深賞物，新詩勸我且持杯。", "更言留得花王住，忍放韶光取次回。"]'),
('52321bd9-82f2-4bc5-9243-1d84fd2c2242','和陳尉見貽二首  其二','華鎮','宋','宋诗','song-poetry','','[]','燕語鶑啼次第新，柳綿花錦曲江濱。',64,'全唐诗/poet.song.60000.json','["燕語鶑啼次第新，柳綿花錦曲江濱。", "且將邂逅天涯客，共看芳妍海角春。", "須愛日添隨日線，莫教花笑對花人。", "一杯隨分休辭訴，况有清歌激絳唇。"]'),
('8decc138-7c08-4b8b-b00d-4d1fdc59b436','食櫻桃思越中風俗','華鎮','宋','宋诗','song-poetry','','[]','答答驅禽欲曉天，筠籠輕摘薦芳筵。',64,'全唐诗/poet.song.60000.json','["答答驅禽欲曉天，筠籠輕摘薦芳筵。", "檀唇深注胭脂紫，琪樹勻排火齊圓。", "醇蜜冷和甘益重，小梅青近色增鮮。", "花時南國豪華甚，得爾杯盤更可憐。"]'),
('28d595f7-1cd9-4b10-b245-a05648f9eb26','和陸彥則郊外初夏送客','華鎮','宋','宋诗','song-poetry','','[]','紅英落盡紫荷長，野岸陰陰暗綠楊。',64,'全唐诗/poet.song.60000.json','["紅英落盡紫荷長，野岸陰陰暗綠楊。", "過眼芳菲渾似夢，感時情緒直如狂。", "江皋有客懷雙佩，淮上逢人賦乘黄。", "顧我越吟方自苦，可堪別曲念江鄉。"]'),
('a7b5f98f-d70b-4566-9c05-8eaf7f7e0a26','槿籬','華鎮','宋','宋诗','song-poetry','','[]','移栽野槿密參差，來束乘時作短籬。',64,'全唐诗/poet.song.60000.json','["移栽野槿密參差，來束乘時作短籬。", "樹立已教存大本，彌縫不使去纖枝。", "春殘葉暗青雲合，秋至花繁錦障垂。", "家似長卿惟壁立，不憂鼠竊夜潜窺。"]'),
('d311ca16-cf2a-462c-8a53-cd5b17ac8b7f','題共亭','華鎮','宋','宋诗','song-poetry','','[]','駕鶴峰前山氣佳，煉丹泉上石如排。',64,'全唐诗/poet.song.60000.json','["駕鶴峰前山氣佳，煉丹泉上石如排。", "高低簷宇依叢竹，屈曲梯橋跨斷厓。", "仙客肯教人世得，賢侯還與郡民偕。", "春風日落歌聲散，蘚徑時時有墜釵。"]'),
('5bbec67c-3d7e-43e7-8993-d736ea66daa0','元老十二丈教授就館西城因以寄之','華鎮','宋','宋诗','song-poetry','','[]','誰教蹇步躡丹梯，曾是先生振所迷。',64,'全唐诗/poet.song.60000.json','["誰教蹇步躡丹梯，曾是先生振所迷。", "始喜草廬依郡北，旋聆絳帳出城西。", "儀韶久合爲虞鳳，伏鵠猶勞似魯雞。", "却愛春風嘉樹下，依然還見舊成蹊。"]'),
('6af0aa50-c9c8-4c65-8978-d4055ecf825d','和光道喜和叔得雨兼呈和叔知縣鄉兄','華鎮','宋','宋诗','song-poetry','','[]','精誠一念格明神，時雨經宵即效珍。',64,'全唐诗/poet.song.60000.json','["精誠一念格明神，時雨經宵即效珍。", "政屬士龍真有譽，頌成吉甫更無倫。", "千疇土脈三冬起，百里根荄一日春。", "自古移風由美化，善良從此在吾民。"]'),
('d9650b35-7858-492d-8b12-7306b390fe7b','送左司董郎中出知汾州三首  其一','華鎮','宋','宋诗','song-poetry','','[]','策足年來據要津，漸分符竹寄兵民。',64,'全唐诗/poet.song.60000.json','["策足年來據要津，漸分符竹寄兵民。", "雙旌卷霧輝霜日，駟馬驕風蹀路塵。", "魏晉河山元險固，陶唐風俗本深淳。", "銛鋒爽鑒清夷旦，報政應須笑魯人。"]'),
('e8b9ae02-c15d-45a9-a337-f65d72cbeafc','送左司董郎中出知汾州三首  其二','華鎮','宋','宋诗','song-poetry','','[]','少壯同看桂苑春，白頭相顧等天倫。',64,'全唐诗/poet.song.60000.json','["少壯同看桂苑春，白頭相顧等天倫。", "素風凜凜驚頹俗，高義翛翛媲古人。", "邂逅論情槐棘地，殷勤分袂雪霜晨。", "剖符自是諸侯貴，不學河梁話苦辛。"]'),
('c6ee87d4-c981-4476-bb3e-1079782fa9f9','送左司董郎中出知汾州三首  其三','華鎮','宋','宋诗','song-poetry','','[]','養狙有感誰非是，塞馬無因自去來。',64,'全唐诗/poet.song.60000.json','["養狙有感誰非是，塞馬無因自去來。", "人見終軍持漢節，世聞郭隗上燕臺。", "九門天上雲泥隔，三徑山陰夢想開。", "青瑣黄扉嚴密地，待看旌旆應時回。"]'),
('37e7326b-4471-4794-9ef6-54598f6fb8dc','和李判官','華鎮','宋','宋诗','song-poetry','','[]','衛玉清標未及門，先知和氣襲人溫。',64,'全唐诗/poet.song.60000.json','["衛玉清標未及門，先知和氣襲人溫。", "言高自有精醇味，手敏曾無洗削痕。", "一捧絲綸來幕府，兩迂舟楫過江村。", "已慚無取叨交契，更辱新詩仔細論。"]'),
('ca61964e-0f9b-4e4d-bebb-dcfbaa49884a','雜詠三首  其一','華鎮','宋','宋诗','song-poetry','','[]','相逢邂逅典文場，人世機心一笑忘。',64,'全唐诗/poet.song.60000.json','["相逢邂逅典文場，人世機心一笑忘。", "麗藻滿籯堆錦繡，清談終坐擊琳瑯。", "衣裘不羨公西勝，才術當知賈傅長。", "今日故園聊躑躅，他年要路看騰驤。"]'),
('9bec8acb-83b1-415f-af4b-d8429dee6502','雜詠三首  其二','華鎮','宋','宋诗','song-poetry','','[]','風過依稀聽步虛，穿林度水得清都。',64,'全唐诗/poet.song.60000.json','["風過依稀聽步虛，穿林度水得清都。", "地靈自有烟霞勝，歲久何妨粉墨蕪。", "雙鶴未歸晴晝永，片山長在白雲孤。", "無端塹斷靈源地，王氣寧知屬後湖。"]'),
('1a906a0b-2911-4d41-b137-3da2639bf80f','雜詠三首  其三','華鎮','宋','宋诗','song-poetry','','[]','日曝山頭土欲焦，全家冒日走岧嶢。',64,'全唐诗/poet.song.60000.json','["日曝山頭土欲焦，全家冒日走岧嶢。", "石泉絕澗階千級，嶺路穿雲線一條。", "借問裹糧朝歷險，何如坦腹夜吹簫。", "□□□□□□□，□□□□□□□。"]'),
('bf4048b7-b130-4e0a-90a0-7b46199128ba','鳳凰臺','華鎮','宋','宋诗','song-poetry','','[]','昔吟太白鳳凰詩，此日登臨認故墟。',64,'全唐诗/poet.song.60000.json','["昔吟太白鳳凰詩，此日登臨認故墟。", "丹穴好音今寂寞，碧梧秋葉晚蕭疏。", "訪尋池苑無陳迹，指顧江山似舊書。", "流影逝波何足恨，且聽天籟響虛徐。"]'),
('60f5a83d-479b-4cad-8808-77d149bd3b7e','陪潭倅張朝散江皋觀魚','華鎮','宋','宋诗','song-poetry','','[]','通守陳魚許縱觀，旋開芳宴俯江干。',64,'全唐诗/poet.song.60000.json','["通守陳魚許縱觀，旋開芳宴俯江干。", "合圍緩覺波心遠，數獲豐知網目寬。", "何必姬姜當脆板，自多魴鯉薦琱盤。", "歸舟清興知何限，湘水無風夕月寒。"]'),
('d7c3c06c-b72b-4047-9476-73020576ca02','送史道源往宛丘','華鎮','宋','宋诗','song-poetry','','[]','與君身世本西東，一席虛齋邂逅同。',64,'全唐诗/poet.song.60000.json','["與君身世本西東，一席虛齋邂逅同。", "張尉寬衷無巧詆，陶唐遺俗有淳風。", "座中未閣紅瑶麈，門外還嘶白玉驄。", "來歲金科新榜上，當看名字冠諸公。"]'),
('f2ccf839-11ac-4030-99c9-1e13ed923eef','和陳承事喜雨應祈見賀','華鎮','宋','宋诗','song-poetry','','[]','空階昨夜響淋漓，正是東皋渴雨時。',64,'全唐诗/poet.song.60000.json','["空階昨夜響淋漓，正是東皋渴雨時。", "螻蟻未應能有感，乾坤自是本無私。", "已知協氣通三壤，想見嘉禾秀兩岐。", "更待秋冬高廩後，與君同賦譽堯詩。"]'),
('57ed5d8c-0769-4b2a-bcc2-e1a3eac952b1','送湖南提刑安學士  其一','華鎮','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','洞庭六月暑風長，使者征帆挂短檣。',64,'全唐诗/poet.song.60000.json','["洞庭六月暑風長，使者征帆挂短檣。", "汲引津途多肉食，追隨行路有壺漿。", "南洲自戀涵濡德，北闕方思獻納良。", "更識高門延慶事，綵衣新有桂枝香。"]'),
('b11f1d30-88ba-4bfc-a585-35ccc7d8db8f','送湖南提刑安學士  其二','華鎮','宋','宋诗','song-poetry','','[]','節遇中秋挾日餘，哲人來契夢熊時。',64,'全唐诗/poet.song.60000.json','["節遇中秋挾日餘，哲人來契夢熊時。", "神澄曉露珠凝彩，氣爽秋風桂有枝。", "歌袴始喧清贛曲，使星還照碧湘西。", "太平天子方求舊，但指松椿祝壽祺。"]'),
('c8906c54-2cc5-4df0-a36d-649ac4a56ebe','龍窟寺','華鎮','宋','宋诗','song-poetry','','[]','籃輿薄暮下禪扃，貪看松蘿氣象清。',64,'全唐诗/poet.song.60000.json','["籃輿薄暮下禪扃，貪看松蘿氣象清。", "未與老僧張榻坐，且携稚子繞廊行。", "小堂烟重鐙生暈，遠壑風高水有聲。", "寂寞卧龍無處問，數聲山鳥自飛鳴。"]'),
('70b2b76b-bb48-44eb-bd8b-e522fee91f4a','和純翁新秋夜雨','華鎮','宋','宋诗','song-poetry','','[]','西風吹雨下天涯，還見蕭疏八月期。',64,'全唐诗/poet.song.60000.json','["西風吹雨下天涯，還見蕭疏八月期。", "筠簟驚秋初冷後，蘭缸凝暈未吹時。", "誰人擊節悲秋夜，幾處停針念所思。", "此景多情吟不盡，何郎底事最先知。"]'),
('8576a8c6-dcc0-4c71-a97c-5316097868f9','秋日登戒珠寺','華鎮','宋','宋诗','song-poetry','','[]','幽尋蘭若已多歡，更踏崇山望遠山。',64,'全唐诗/poet.song.60000.json','["幽尋蘭若已多歡，更踏崇山望遠山。", "高閣路餘心未愜，秀巖目盡興初還。", "隴雲凝素晴猶闊，籬菊分金暖尚慳。", "飛蓋不須容易去，且偷閒暇笑談間。"]'),
('705cc8c4-3bc6-4162-9145-831fda9a2151','重過高郵丁志高道路','華鎮','宋','宋诗','song-poetry','','[]','扁舟平日此東西，屈指于今二十期。',64,'全唐诗/poet.song.60000.json','["扁舟平日此東西，屈指于今二十期。", "村落平田添棟宇，人家碧瓦煥茆茨。", "經過自覺風烟好，來往誰知歲月移。", "密柳高槐都似舊，行人雙鬢漸成絲。"]'),
('3b333a46-9438-4331-9aaa-d9db4e857263','壽顧侍郎','華鎮','宋','宋诗','song-poetry','','[]','應鐘司序兩旬時，台座光凝照水湄。',64,'全唐诗/poet.song.60000.json','["應鐘司序兩旬時，台座光凝照水湄。", "善慶遠歸三俊後，哲人來副半千期。", "澄波渺渺韜洪量，喬嶽稜稜挺異姿。", "早晚鈞衡調燮去，鳳池當見老蓮龜。"]'),
('5a720605-3b10-49a4-8c3e-ca970040d607','送敏修赴官鉅鹿','華鎮','宋','宋诗','song-poetry','','[]','蜩鷽悠悠祇可憐，搶榆控地已飄然。',64,'全唐诗/poet.song.60000.json','["蜩鷽悠悠祇可憐，搶榆控地已飄然。", "早聞達識無諸蔽，晚挹清風勝所傳。", "會面已欣渾似舊，開懷還肯便忘年。", "淥波碧草芳春日，忍詠江生送別篇。"]'),
('df2966c4-e643-46f0-88b5-a975edd39208','題王氏清軒','華鎮','宋','宋诗','song-poetry','','[]','開亭後圃號清軒，非逐豪華效兔園。',64,'全唐诗/poet.song.60000.json','["開亭後圃號清軒，非逐豪華效兔園。", "入座馨香惟蕙草，照窗清淺只池源。", "暫來自怪塵埃遠，竟日原無鳥雀喧。", "况是繞垣多翠竹，春風次第長龍孫。"]'),
('9e4da25b-93a1-4ba9-9939-1396c48ad8f7','題明軒','華鎮','宋','宋诗','song-poetry','','[]','兩楹開處面純離，題作明軒得事宜。',64,'全唐诗/poet.song.60000.json','["兩楹開處面純離，題作明軒得事宜。", "計利已居人會地，征商還是日中時。", "平持刀尺無心用，高倚權衡莫我欺。", "達識主人元有大，誰知細故亦無遺。"]'),
('0f8f9b9b-1a52-400f-a28e-d485cb27eb91','題海鶴','華鎮','宋','宋诗','song-poetry','','[]','仙禽西過萬年枝，人道飛鳴是路岐。',64,'全唐诗/poet.song.60000.json','["仙禽西過萬年枝，人道飛鳴是路岐。", "幾向靜中陪振鷺，也曾高處見長離。", "共知天上聞聲韵，直羨風前刷羽儀。", "好與便隨行綴去，舞韶應自有嘉時。"]'),
('87ce16be-1e62-4751-aa93-acec5c13fa55','題西成軒','華鎮','宋','宋诗','song-poetry','','[]','華軒聞在了溪東，軒號西成學老農。',64,'全唐诗/poet.song.60000.json','["華軒聞在了溪東，軒號西成學老農。", "碧玉千峰終日好，黄雲萬頃幾香濃。", "天低每接金仙語，夜迥時聞紫府鐘。", "祇恐主人爲吏去，春來三徑綠苔封。"]'),
('e628ea55-f6f8-484e-9afc-95a1784b80bd','用韵謝越帥程給事','華鎮','宋','宋诗','song-poetry','','[]','大屏元侯重薦論，自慚蹇淺匪多聞。',64,'全唐诗/poet.song.60000.json','["大屏元侯重薦論，自慚蹇淺匪多聞。", "已當壯齒逢清世，敢向南山戀白雲。", "宴以笙簧終永日，寵將珠玉煥新文。", "願憑陶鑄沖天去，黄閣門前拜使君。"]'),
('a8d1ae9a-f29f-4b05-b4b5-86b128239e03','戲呈程民老','華鎮','宋','宋诗','song-poetry','','[]','多才是處走華鑣，問柳尋花九十朝。',64,'全唐诗/poet.song.60000.json','["多才是處走華鑣，問柳尋花九十朝。", "春去光陰祇恨晚，興來行路莫知遥。", "謝安携妓情雖遠，崔烈爲公臭不消。", "應是醉魂傷駘蕩，大歌楚些爲君招。"]'),
('5863c991-73d4-40bb-92cb-66055f0e0bc0','蒙雲叟司戶寵示佳篇若將以功名相勉者再用韵以呈  其一','華鎮','宋','宋诗','song-poetry','','[]','來時春半忽驚秋，思慮關心欲破頭。',64,'全唐诗/poet.song.60000.json','["來時春半忽驚秋，思慮關心欲破頭。", "符竹徒勞乘絕障，輿圖那忍望神州。", "未酬素志終難已，欲問皇天肯斷休。", "樽酒且須澆壘塊，不須更作畔牢愁。"]'),
('a83fff69-95bd-4d4a-ac7f-ed8c93dd075c','蒙雲叟司戶寵示佳篇若將以功名相勉者再用韵以呈  其二','華鎮','宋','宋诗','song-poetry','','[]','直須富貴在何時，到手杯行且莫辭。',64,'全唐诗/poet.song.60000.json','["直須富貴在何時，到手杯行且莫辭。", "未放沈酣千日醉，何妨酬唱百篇詩。", "喜看小雨生新潤，要使閒愁破兩眉。", "景物秋來盡佳句，濡毫會看墨成池。"]'),
('d1c6600e-7469-4855-b53d-91221be560bf','和都城春雪','華鎮','宋','宋诗','song-poetry','','[]','六花飛壓九街塵，應訝人間未覺春。',64,'全唐诗/poet.song.60000.json','["六花飛壓九街塵，應訝人間未覺春。", "天上樓臺銀作屋，雲中車輅玉爲輪。", "三秋狼戾盈倉兆，萬國歡呼擊壤辰。", "寂寞袁門烟火冷，未知誰是扣關人。"]'),
('e2cac858-363a-4ee0-9b77-8403d04e42b7','病中聞梅已放就鄰人求之','華鎮','宋','宋诗','song-poetry','','[]','屈指新春只月餘，園梅聞道已盈枝。',64,'全唐诗/poet.song.60000.json','["屈指新春只月餘，園梅聞道已盈枝。", "暗香便欲朝三嗅，寒笛愁聞夜一吹。", "病眼未能臨翠薄，幽懷還恐失霜枝。", "從君覓取春消息，莫使空吟寄驛詩。"]'),
('af14e06a-7090-4c56-938b-d18dfd0b12e2','次韵和道守曾大夫堂前早梅花','華鎮','宋','宋诗','song-poetry','','[]','畫堂深處臘前開，應笑孤根庾嶺隈。',64,'全唐诗/poet.song.60000.json','["畫堂深處臘前開，應笑孤根庾嶺隈。", "不比一枝隨驛至，肯愁三弄逐風來。", "華繁素逼窗紗月，香重寒銷印篆灰。", "賢守吟看多麗句，清新未羨宛陵梅。"]'),
('9a9b24c9-76cc-4ef3-b163-f945640c8ecc','梅花一首','華鎮','宋','宋诗','song-poetry','','[]','生來幽意酷憐梅，醉眼愁眉見即開。',64,'全唐诗/poet.song.60000.json','["生來幽意酷憐梅，醉眼愁眉見即開。", "案上欲教終日在，林梢令折數枝來。", "輕勻素色欺魚網，瀟灑清香壓麝煤。", "一嗅一觀情一倍，熙熙不啻上春臺。"]'),
('36d8ff3a-60c2-4283-a0f1-d5dc938ddb30','近日','華鎮','宋','宋诗','song-poetry','','[]','近日英雄涉世疏，休言彈鋏便乘輿。',64,'全唐诗/poet.song.60000.json','["近日英雄涉世疏，休言彈鋏便乘輿。", "晝操板艇穿溝徑，夜爇蘆薪閱簿書。", "似此小心紆若綬，何如闊步曳長裾。", "江南若有扁舟便，不待秋風始憶魚。"]'),
('598626d8-4dc3-40e6-9a1a-1902556f5b79','列子觀','華鎮','宋','宋诗','song-poetry','','[]','日日雞聲馬上聞，鑑中不是少年身。',64,'全唐诗/poet.song.60000.json','["日日雞聲馬上聞，鑑中不是少年身。", "倦從客路長搖轡，喜得真祠暫拂塵。", "仙馭不歸風自好，遺編長誦意彌親。", "隋珠輕用彈黄雀，愧汝當年辭粟人。"]'),
('547ad55a-ae03-4639-9667-82acb6def118','紫薇花','華鎮','宋','宋诗','song-poetry','','[]','雨餘庭下紫薇芳，簾幙風清發早凉。',64,'全唐诗/poet.song.60000.json','["雨餘庭下紫薇芳，簾幙風清發早凉。", "細葉密攢紅縠皺，纖枝交曳彩霞長。", "清都舊許分星號，西掖曾容對省郎。", "悵望日邊承露掌，何時相與照秋光。"]'),
('731bac62-d015-4a29-8515-656a8d244ead','野岸白蓮','華鎮','宋','宋诗','song-poetry','','[]','越溪深處楚江湄，玉刻冰裁一兩枝。',64,'全唐诗/poet.song.60000.json','["越溪深處楚江湄，玉刻冰裁一兩枝。", "天借明蟾滋秀色，雲垂清露潤豐肌。", "解知潔素風神遠，始覺紅鮮品格卑。", "何日曲池亭檻上，細看朝暮弄輕颸。"]'),
('18c9aaf2-694c-43cd-8271-ca6525b15613','高麗扇','華鎮','宋','宋诗','song-poetry','','[]','排筠貼楮綴南金，舒卷乘時巧思深。',64,'全唐诗/poet.song.60000.json','["排筠貼楮綴南金，舒卷乘時巧思深。", "何必月團裁尺素，自多清爽滌煩襟。", "揮來振鷺全開羽，疊去栟櫚未展心。", "利用已宜勤賞重，更堪精製出雞林。"]'),
('4d7217d2-47cf-4801-9319-14c727131bc2','病起酬廷老傅十三丈','華鎮','宋','宋诗','song-poetry','','[]','既有吾身似老聃，却無道術類蘇耽。',64,'全唐诗/poet.song.60000.json','["既有吾身似老聃，却無道術類蘇耽。", "陰陽授氣還非壯，濕燥因時豈易堪。", "動戒荒嬉情謾切，坐膺消渴理宜甘。", "見貽藥石誠多愧，鄉黨無徵只自慚。"]'),
('8de0e3ba-57f9-42f6-a037-bb8ca6ee1758','元祐三年八月初六日得報已有代者歸期可數喜動於中載形歌詠','華鎮','宋','宋诗','song-poetry','','[]','郡符朝下報新官，不覺津津喜見顔。',64,'全唐诗/poet.song.60000.json','["郡符朝下報新官，不覺津津喜見顔。", "但怪鵲聲連日好，誰知鴻翼過年還。", "心游象魏三秋後，步入庭闈數月間。", "別去祇憐風月夜，不聞山溜響潺潺。"]'),
('99fd4de4-bd1a-4b0a-99f9-44042cdafedc','送邦彥赴闕','華鎮','宋','宋诗','song-poetry','','[]','士林休復歎棲鸞，已向青雲刷羽翰。',64,'全唐诗/poet.song.60000.json','["士林休復歎棲鸞，已向青雲刷羽翰。", "漢殿舊聞稱錦繡，燕堂當見擢芝蘭。", "張帆正值霜風勁，策馬何辭曉月寒。", "解道此行須特達，傾囊却愧乏琅玕。"]'),
('b406f044-5e3d-4d8b-8d22-3d03f77c6049','和李子約戶曹四紀權室','華鎮','宋','宋诗','song-poetry','','[]','主人才術照幾先，虛室端居宰利權。',64,'全唐诗/poet.song.60000.json','["主人才術照幾先，虛室端居宰利權。", "誰覺市征非往日，自知歲課埒當年。", "高梧六月生秋色，修竹三冬起紫烟。", "平日紛紛譏識地，不妨澄寂事經禪。"]'),
('22aa286e-b72a-4e2a-9705-354ecbb08e4d','和楊中行朝散別試日院中即事','華鎮','宋','宋诗','song-poetry','','[]','多士分袍日造庭，談經議法與論兵。',64,'全唐诗/poet.song.60000.json','["多士分袍日造庭，談經議法與論兵。", "不辭寒夜程文冗，喜見明時道化行。", "此日人懷平旦氣，他時中有少年卿。", "鳳毛已飽籯金術，佇聽傳家振大名。"]'),
('e3f3c40a-29d9-4677-848a-2264ffb222f5','試院中聞初平別頭預上舍選作詩二章以貽之  其一','華鎮','宋','宋诗','song-poetry','','[]','拂曉文闈報捷音，傳家始見勝籯金。',64,'全唐诗/poet.song.60000.json','["拂曉文闈報捷音，傳家始見勝籯金。", "不隨門戶炎凉異，須識膠庠德澤深。", "日月光華今際會，歲時風物莫侵尋。", "欲知報稱君親處，惟有忠嘉一片心。"]'),
('59ab2496-f503-439a-9785-ddee51c4e32f','試院中聞初平別頭預上舍選作詩二章以貽之  其二','華鎮','宋','宋诗','song-poetry','','[]','龍頭本是我青氈，寂寞風流數百年。',64,'全唐诗/poet.song.60000.json','["龍頭本是我青氈，寂寞風流數百年。", "素業久慚吾未振，遺芳今喜汝能傳。", "九光瑞日纔披霧，千里修途要著鞭。", "竹素紀名男子事，莫令風味愧吾先。"]'),
('730ada6f-72a2-48f9-be54-44148d957780','出院有日用前韵與諸公敘別','華鎮','宋','宋诗','song-poetry','','[]','頻年承乏選賢關，自惜生居黍谷寒。',64,'全唐诗/poet.song.60000.json','["頻年承乏選賢關，自惜生居黍谷寒。", "讎盡加三難自暇，聽殘敲五敢求安。", "蒙恩邂逅真多樂，已事分飛亦足歡。", "從此塵勞能脫否，待尋蜀客試占看。"]'),
('82c88541-7c2f-41b3-bea2-7da38afff4c8','和林安聖承議別試所即事','華鎮','宋','宋诗','song-poetry','','[]','驟阻文闈密密關，不堪霖雨作新寒。',64,'全唐诗/poet.song.60000.json','["驟阻文闈密密關，不堪霖雨作新寒。", "暫違塵鞅閒還好，喜得朋簪靜可安。", "樽俎不陳無過舉，笑談相酢有餘歡。", "共知佳節行相近，須把程文繼日看。"]'),
('1a619c1b-6099-4bb7-8444-67a1b1b839e0','再和','華鎮','宋','宋诗','song-poetry','','[]','陶家門戶本常關，澤室肌膚雅耐寒。',64,'全唐诗/poet.song.60000.json','["陶家門戶本常關，澤室肌膚雅耐寒。", "不惜春秋參貢舉，况聞早晚報平安。", "款陪盛集無窮樂，細閱雄文有益歡。", "未必重陽虛過了，黄花十日尚堪看。"]'),
('95dfb9bb-8db9-4df6-b0a2-bb8afa3a2aa3','歐陽叔向見余試院中詩卷作詩見譽次韵酬之','華鎮','宋','宋诗','song-poetry','','[]','未歷藩籬見少陵，索塗擿埴愧冥行。',64,'全唐诗/poet.song.60000.json','["未歷藩籬見少陵，索塗擿埴愧冥行。", "滿懷驟獲連城貺，溢耳惟聞中律鳴。", "思巧本慚彫楮手，心雄方怯棄繻生。", "十年世路師良賈，今日纔驚利有贏。"]'),
('b0109f5c-1eea-419e-80a7-1a970d1f892e','再酬叔向見謝','華鎮','宋','宋诗','song-poetry','','[]','詞鋒筆力勢憑凌，高共飛雲天上行。',64,'全唐诗/poet.song.60000.json','["詞鋒筆力勢憑凌，高共飛雲天上行。", "清夜幾通康樂夢，嘉時還嗣孟郊鳴。", "人間雅道時無喪，海內才流世有生。", "欲識篇章精密處，搜奇抉隠語無贏。"]'),
('1030177a-d84f-454b-a172-f38b3876251f','次韵酬叔向','華鎮','宋','宋诗','song-poetry','','[]','卞玉塵多氣已低，可能符采壓虹霓。',64,'全唐诗/poet.song.60000.json','["卞玉塵多氣已低，可能符采壓虹霓。", "晉人自識三都麗，襄野誰教七聖迷。", "謾說違時清似水，且謀終日醉如泥。", "秦關自昔稱天府，何事雄誇十二齊。"]'),
('bb2d88e3-8583-4fdf-aa87-3be9852ff4e8','壽潭帥李金部二首  其一','華鎮','宋','宋诗','song-poetry','','[]','慶緒綿綿嗣伯陽，何時熊夢契嘉祥。',64,'全唐诗/poet.song.60000.json','["慶緒綿綿嗣伯陽，何時熊夢契嘉祥。", "月低蓂莢光猶滿，風入林鍾景正長。", "出去懷金參九列，歸來畫迺得三湘。", "遥知當日瞻佳氣，還似茲辰賭壽香。"]'),
('614489f4-4555-4b5c-8e8b-e9da2ebc2c04','壽潭帥李金部二首  其二','華鎮','宋','宋诗','song-poetry','','[]','汎汎薰風入舜弦，西樓晚月十分圓。',64,'全唐诗/poet.song.60000.json','["汎汎薰風入舜弦，西樓晚月十分圓。", "懸弧門下占祥日，仗節湘南出師年。", "善誦詠歌盈玉葉，壽觴頻舉倒金蓮。", "紫泥褒詔知非晚，行看雙旌上日邊。"]'),
('a6418f68-70d7-4f00-975d-a4905b1cd2fb','漸堂','華鎮','宋','宋诗','song-poetry','','[]','君家仲季樂天長，書史優游共一堂。',64,'全唐诗/poet.song.60000.json','["君家仲季樂天長，書史優游共一堂。", "雁序此時詳進止，鴒原異日竟軒昂。", "階前蘭菊幽香遠，座上塤篪逸韵長。", "肅穆清風在華榜，可令進躁坐銷亡。"]'),
('4616357c-6b4e-48ff-b621-ef6bd04e8c80','舂陵聞雁','華鎮','宋','宋诗','song-poetry','','[]','擁衾欹枕未成眠，歷歷鴻聲到枕前。',64,'全唐诗/poet.song.60000.json','["擁衾欹枕未成眠，歷歷鴻聲到枕前。", "十月高風方永夜，三更疏雨欲寒天。", "衡陽亭榭真虛爾，潁水篇章是偶然。", "萬里天南共爲客，北書從此喜須傳。"]'),
('ad054195-d6e1-422e-a12c-c145c1f8d631','和純翁聞新雁','華鎮','宋','宋诗','song-poetry','','[]','出門無緒看飛蓬，入夜還驚度早鴻。',64,'全唐诗/poet.song.60000.json','["出門無緒看飛蓬，入夜還驚度早鴻。", "塞外長蘆應已斷，天涯尺素竟難通。", "青熒疏幌遮寒燼，窸窣高梧弄夕風。", "今夜只應欹枕後，夢魂隨汝到江東。"]'),
('f7b3a43b-58fe-43d7-a2d9-951aaf08ccfa','和都城臘日雪','華鎮','宋','宋诗','song-poetry','','[]','同雲爲瑞上圓清，臘日飛花落帝城。',64,'全唐诗/poet.song.60000.json','["同雲爲瑞上圓清，臘日飛花落帝城。", "雙闕漸迷鴛瓦碧，九街勻罩麴塵輕。", "戴溪有月舟方遠，袁巷無人路自平。", "却愛馬卿詞賦好，梁園一座盡知傾。"]'),
('d3a4d046-2a70-447e-9d14-89d3acf0656f','和高郵監稅李光道承務  其一','華鎮','宋','宋诗','song-poetry','','[]','論交未必須白頭，邂逅相逢轄屢投。',64,'全唐诗/poet.song.60000.json','["論交未必須白頭，邂逅相逢轄屢投。", "識似方諸能鑒物，言非蘐草自忘憂。", "詩書已見勤追琢，筦庫何妨暫滯留。", "但喜荒齋得佳詠，清風和氣日休休。"]'),
('7ae2653e-169c-48b9-a1a6-1f0d14fb3a64','和高郵監稅李光道承務  其二','華鎮','宋','宋诗','song-poetry','','[]','蘭玉才華夙有芳，撝謙高韵慕循牆。',64,'全唐诗/poet.song.60000.json','["蘭玉才華夙有芳，撝謙高韵慕循牆。", "風流自與迂疏厚，澹泊應須氣味長。", "屢見清談能破的，行看素業驟成章。", "日生鞅掌雖無盡，投隙當來語大方。"]'),
('8d735394-eae9-4ea2-96ec-b4b71aea0cb8','落帽山','華鎮','宋','宋诗','song-poetry','','[]','落帽山頭雨脚長，消愁還是感河陽。',64,'全唐诗/poet.song.60000.json','["落帽山頭雨脚長，消愁還是感河陽。", "勞歌不解凄凉意，小飲難投酩酊鄉。", "共恨今秋辜綵菊，相期來歲沃霞觴。", "須知四美人間少，一笑千金未易償。"]'),
('fa2491a4-635a-4bc6-b015-dea72ffa86c5','壽蔡大資','華鎮','宋','宋诗','song-poetry','','[]','巖巖巨鎮瞻維嶽，落落喬松棟幹姿。',64,'全唐诗/poet.song.60000.json','["巖巖巨鎮瞻維嶽，落落喬松棟幹姿。", "物外風神時遠鶴，幾先識斷世元龜。", "還逢周寢占熊旦，恰是商巖肖象時。", "願醖東溟爲壽酒，一年一獻一瑶巵。"]'),
('ee8019b5-f5e8-4586-99b1-781b42bddf0c','項王廟','華鎮','宋','宋诗','song-poetry','','[]','劉氏功名未足多，謾將带礪指山河。',64,'全唐诗/poet.song.60000.json','["劉氏功名未足多，謾將带礪指山河。", "楚宮一夜雖虛壘，漢殿百年還藝禾。", "今日祠堂皆寂寞，當時江水自逶迤。", "有靈若憶生前事，應悔初爲蓋世歌。"]'),
('af50d800-21d0-452a-9aea-c86ef4aa30a8','用韵贈陳縣丞','華鎮','宋','宋诗','song-poetry','','[]','明明真理與時紛，曾把清心仔細論。',64,'全唐诗/poet.song.60000.json','["明明真理與時紛，曾把清心仔細論。", "百慮已知歸妙道，一塵無復寄靈根。", "時來或可紆藍綬，興盡還思杜席門。", "異日儻能追逸駕，相忘不必近林園。"]'),
('da90defd-79fa-494d-9cde-d085bca7d7bf','湖南運使程大卿壽','華鎮','宋','宋诗','song-poetry','','[]','時來嘉會一陽新，慶屬高門誕哲人。',64,'全唐诗/poet.song.60000.json','["時來嘉會一陽新，慶屬高門誕哲人。", "杞梓挺材周世用，珪璋含德足天純。", "酒熏愛日凝和氣，香觸寒梅發早春。", "密運陰功方寸地，默增遐算有明神。"]'),
('1efd67a1-2c7f-447c-a750-a02367f1f920','崇寧元年五月十六日天漢橋月下閒步','華鎮','宋','宋诗','song-poetry','','[]','閒來步月上銀潢，天宇無塵夜色凉。',64,'全唐诗/poet.song.60000.json','["閒來步月上銀潢，天宇無塵夜色凉。", "雙闕高尋佳氣聳，三街平襯綠槐長。", "沈沈琳館東西迥，褭褭珠樓左右光。", "歸去不須尋蜀客，莫教知到斗牛傍。"]'),
('c5329959-9eb4-489f-9f24-81cb816d75c0','高郵張生出所得詩畫一軸求余作詩因書','華鎮','宋','宋诗','song-poetry','','[]','千巖秀處有扁舟，不駕樵風欲五秋。',64,'全唐诗/poet.song.60000.json','["千巖秀處有扁舟，不駕樵風欲五秋。", "金咮未應甘腐鼠，霜翎時自下崑邱。", "塵埃漠漠長扃戶，雲月漫漫獨倚樓。", "好事古來常恨少，碧霄清思爲君搜。"]'),
('17d1bb00-7ed3-4031-92b0-36657ceabd65','宿西禪寺詩','華鎮','宋','宋诗','song-poetry','','[]','湖湘跋涉今猶近，淮海漂流昔早曾。',64,'全唐诗/poet.song.60000.json','["湖湘跋涉今猶近，淮海漂流昔早曾。", "擾擾未能逃鞅掌，星星祇見變鬅鬙。", "驅車曠野猶飛雪，稅駕閒窗已上燈。", "瓶錫不移緣累息，須知人世盡輸僧。"]'),
('1e36e215-3a62-43d7-8411-bed6ff001a7b','送道守董朝散','華鎮','宋','宋诗','song-poetry','','[]','香穗氤氳雜瑞烟，條風新轉早春天。',64,'全唐诗/poet.song.60000.json','["香穗氤氳雜瑞烟，條風新轉早春天。", "桑蓬慶集侯門日，銅竹榮居郡閤年。", "清曉十分圓玉兔，寒宵萬斛照金蓮。", "祝詩聊致官曹意，上古靈椿自八千。"]'),
('ef8a09d2-7afe-40e9-b582-ff1ee139de04','錢秀才索詩用韵酬之','華鎮','宋','宋诗','song-poetry','','[]','新詩字字脫埃塵，幾效中郎歎受辛。',64,'全唐诗/poet.song.60000.json','["新詩字字脫埃塵，幾效中郎歎受辛。", "他日合爲仙桂客，此時何愧布衣身。", "更無狐貉原非恥，直有簞瓢不是貧。", "霧豹南山饑不下，未慚尺蠖解求伸。"]'),
('dab9416f-0e85-4164-b55b-56f28c3a407d','次韵和潭州尹節推陪同年運使大卿知府安撫少卿知郡大夫飲會','華鎮','宋','宋诗','song-poetry','','[]','一聲渾化未來宮，當日聯飛真乘龍。',64,'全唐诗/poet.song.60000.json','["一聲渾化未來宮，當日聯飛真乘龍。", "策足津途趨要切，掞庭華藻稱纖穠。", "青雲榮貫誰同得，白首朋樽此幸逢。", "樂事晚生曾未識，强賡佳句想形容。"]'),
('94806c90-7a9f-449a-bdf4-8fd70f6cb56f','題朱中老宣德墓亭','華鎮','宋','宋诗','song-poetry','','[]','不矜鄉版早爲賓，不歎恩綸晚及身。',64,'全唐诗/poet.song.60000.json','["不矜鄉版早爲賓，不歎恩綸晚及身。", "物識儻來忘世累，學隨所遇澤吾民。", "鴻冥輕舉閒刀刃，舟壑潜移冷隙塵。", "今日戶庭皆似舊，共知君有克家人。"]'),
('46235907-2f90-444e-9073-f600318569d3','贈孫純臣居士','華鎮','宋','宋诗','song-poetry','','[]','鼓腹酣歌七十餘，卧龍山北寄蓬廬。',64,'全唐诗/poet.song.60000.json','["鼓腹酣歌七十餘，卧龍山北寄蓬廬。", "滿堂常見斑衣舞，填巷時來長者車。", "負郭稻田周歲計，還家蘭圃足晨蔬。", "閑窗盡日無餘事，時展青囊一卷書。"]'),
('1ea6e216-55e3-4ab7-a79e-bb044904d6e3','上南都權府提刑孫大監二首  其一','華鎮','宋','宋诗','song-poetry','','[]','聲華籍籍冠諸公，三十年前淛水東。',64,'全唐诗/poet.song.60000.json','["聲華籍籍冠諸公，三十年前淛水東。", "造次談經皆振玉，從容遇事盡成風。", "心遊迥出青塵外，名品橫飛碧落中。", "留鑰憲臺雖重寄，方看平步入鵷鴻。"]'),
('177152d8-7fb5-4c98-a861-f4e0c15e2bd6','上南都權府提刑孫大監二首  其二','華鎮','宋','宋诗','song-poetry','','[]','摳衣平昔登門下，曾許橫經近絳紗。',64,'全唐诗/poet.song.60000.json','["摳衣平昔登門下，曾許橫經近絳紗。", "江上一言冰玉遠，天涯長歎水雲賒。", "不才漫忝朱爲紱，承學終慚髮已華。", "今日姓名猶見齒，尚因提奬得靈槎。"]'),
('d7513bdd-edfb-4d00-84e7-d2e44caded0b','舟中望金山寺','華鎮','宋','宋诗','song-poetry','','[]','小山蒼翠出江流，山上精廬望外幽。',64,'全唐诗/poet.song.60000.json','["小山蒼翠出江流，山上精廬望外幽。", "午影樓臺連北固，夜聲鐘磬到揚州。", "客帆飛過朱欄角，沙鳥歸棲碧瓦溝。", "南去北來長擾擾，畫橈何日暫遲留。"]'),
('b10c1184-6df6-483c-8cf9-9917d88d45da','送德器移光州仙居令','華鎮','宋','宋诗','song-poetry','','[]','邂逅舊慚無半面，追隨今恨只三旬。',64,'全唐诗/poet.song.60000.json','["邂逅舊慚無半面，追隨今恨只三旬。", "高才鋒穎凌長劍，和氣舒遲壓九春。", "百里莫言猶偪仄，三年亦可薄經綸。", "古丹應有遺方在，好使靈功被此民。"]'),
('18d57ced-dfd6-4dbb-a9d0-9972676313b2','奉酬劉令見懷','華鎮','宋','宋诗','song-poetry','','[]','世路差池懶自嗟，眼前隨分過年華。',64,'全唐诗/poet.song.60000.json','["世路差池懶自嗟，眼前隨分過年華。", "山中尋藥援青嶂，海上將鷗踏淺沙。", "懷舊愛君交態厚，題詩寄我素封斜。", "爭知節物隨人冷，十月東籬未有花。"]'),
('0882b86b-e137-455a-9a75-687041e509ee','臘後感懷和光道韵','華鎮','宋','宋诗','song-poetry','','[]','達人蔑視千鍾祿，曲士驚談五石瓢。',64,'全唐诗/poet.song.60000.json','["達人蔑視千鍾祿，曲士驚談五石瓢。", "臘盡自憐春氣近，月明誰念美人遥。", "鉛華次第開梅萼，金色依稀著柳條。", "莫問陰山更陰處，數峰殘雪未全銷。"]'),
('b447e006-003b-483a-b650-3f1e78d8470c','過魯太師廟','華鎮','宋','宋诗','song-poetry','','[]','漢家循吏得民深，素業流風尚可尋。',64,'全唐诗/poet.song.60000.json','["漢家循吏得民深，素業流風尚可尋。", "愧在盛時操短刃，遠來鄰壤效鳴琴。", "敢論異事追前事，所喜仁心契本心。", "振轡再經馴雉境，一瞻道廟想徽音。"]'),
('98f0bbd5-6d95-4dcf-8100-50930cb4e9ad','題普照寺','華鎮','宋','宋诗','song-poetry','','[]','剛趁閒情逐隊行，忽逢蕭寺眼前明。',64,'全唐诗/poet.song.60000.json','["剛趁閒情逐隊行，忽逢蕭寺眼前明。", "修廊有蔭僧趺坐，古殿無人雀啄聲。", "咫尺都城塵不到，尋常林木境還清。", "憑君試問輪蹄客，過此如何不解驚。"]'),
('a23e46bb-4b85-47e7-abc0-b53a1c4c4de6','高風','華鎮','宋','宋诗','song-poetry','','[]','一傳肯來忘暑月，兩旬輕舉薄雲霄。',64,'全唐诗/poet.song.60000.json','["一傳肯來忘暑月，兩旬輕舉薄雲霄。", "非關漢水魚盈釣，不爲宜城酒滿瓢。", "方外采真欣淡泊，人間知足得逍遥。", "高風可是陶彭澤，歸去田園爲折腰。"]'),
('2f75b831-d8c0-4d44-8d6a-6de859e9e457','陸彥則索詩寄之四韵','華鎮','宋','宋诗','song-poetry','','[]','解官才喜此身輕，忍以冥搜損性情。',64,'全唐诗/poet.song.60000.json','["解官才喜此身輕，忍以冥搜損性情。", "疏懶舊來高叔夜，虛閒今日似淵明。", "願酬美意情雖切，强綴狂歌曲不成。", "應有朱侯偷笑我，壯年不解請長纓。"]'),
('6f596113-63e2-4ff5-a85b-ad0c1f6be966','壽柯運使  其一','華鎮','宋','宋诗','song-poetry','','[]','九十韶光纔十九，高門曾是弄瑶璋。',64,'全唐诗/poet.song.60000.json','["九十韶光纔十九，高門曾是弄瑶璋。", "熊羆夢寐當時吉，龜鶴年齡此日長。", "劉晏已知豐外計，曹參行見趣歸裝。", "更看德善流芳處，濟濟斑衣滿畫堂。"]'),
('17c1d181-cdac-471b-a7ee-cb03131d2805','壽柯運使  其二','華鎮','宋','宋诗','song-poetry','','[]','曉來遲日上高堂，珠箔玲瓏錦席張。',64,'全唐诗/poet.song.60000.json','["曉來遲日上高堂，珠箔玲瓏錦席張。", "玉斝騰波行旨酒，金爐生穗起真香。", "融融喜氣凝庭戶，拂拂歌塵下棟梁。", "許步桃蹊無以報，但祈眉壽獻篇章。"]'),
('a1499170-6017-4bc9-ba8b-d0735ee937a0','趙防禦新闢小齋詩以貽之','華鎮','宋','宋诗','song-poetry','','[]','隠操真全不待山，小齋新闢戶常關。',64,'全唐诗/poet.song.60000.json','["隠操真全不待山，小齋新闢戶常關。", "窗延晝白明丹府，鑪養春和潤玉顔。", "何必金絲喧曉夕，祇將槌拂伴虛閑。", "人間興味元恬淡，不見輪飛倦後還。"]'),
('650d08f0-4b8b-439d-952c-4e6679c686e6','代湖南張運使賀蔡右丞','華鎮','宋','宋诗','song-poetry','','[]','高步英躔恰妙齡，曙華相照有餘榮。',64,'全唐诗/poet.song.60000.json','["高步英躔恰妙齡，曙華相照有餘榮。", "早逢周室遵儒雅，親見文公迓太平。", "可但清標稱玉潤，共知具體得金聲。", "廟堂方契千年會，側聽康哉語載賡。"]'),
('166f2705-efba-4fc3-ac6a-758767809f17','送傅彬老檢討赴宜興簿','華鎮','宋','宋诗','song-poetry','','[]','不是雙翎羽未齊，天門欲到失雲梯。',64,'全唐诗/poet.song.60000.json','["不是雙翎羽未齊，天門欲到失雲梯。", "眼前且看神仙府，身外休論枳棘棲。", "百草讓茶先有味，一缾挹水近通携。", "扁舟邂逅須乘興，細看東風罨畫溪。"]'),
('e82400b8-1322-4589-95d8-bc0fccff0a76','次韵湖南張運判會春園新亭之什','華鎮','宋','宋诗','song-poetry','','[]','落落長松滿古園，沈沈碧水侵新軒。',64,'全唐诗/poet.song.60000.json','["落落長松滿古園，沈沈碧水侵新軒。", "於今人物情雖別，平昔池臺跡未昏。", "身外無塵紅入座，眼前有酒綠盈樽。", "更將好樂無荒意，深入無生不二門。"]'),
('d57074b9-1b2b-4d2f-a4f5-795e2abac629','田家二首  其一','華鎮','宋','宋诗','song-poetry','','[]','莫笑田家物象微，柴荆未肯愧朱扉。',64,'全唐诗/poet.song.60000.json','["莫笑田家物象微，柴荆未肯愧朱扉。", "槿籬花發錦步障，莎逕葉齊絲地衣。", "葭葦吟風環竹屋，鴛鴦浴水傍苔磯。", "藜羹黍酒有餘味，笑看庭陰密又稀。"]'),
('07b2d546-5653-427e-9f08-4006a2851381','田家二首  其二','華鎮','宋','宋诗','song-poetry','','[]','繞舍澄溝玉色方，夾隄密樹儼修廊。',64,'全唐诗/poet.song.60000.json','["繞舍澄溝玉色方，夾隄密樹儼修廊。", "霜遲留得穠陰綠，秋冷全無潦水黄。", "獨木短橋通別圃，攢蘆新廩出高牆。", "終年飽暖人生足，何必崎嶇走異鄉。"]'),
('25004067-8dfc-4d2d-a70d-aa7224d8d2dc','卜居','華鎮','宋','宋诗','song-poetry','','[]','桑弧蓬矢是男兒，故國松楸亦重違。',64,'全唐诗/poet.song.60000.json','["桑弧蓬矢是男兒，故國松楸亦重違。", "架搆自知惟壁立，綢繆誰敢羨翬飛。", "桑麻地狹妻孥笑，堂廡簷低燕雀稀。", "清世薄才何所用，求田問舍未應非。"]'),
('84ef53db-1f60-4034-b7cf-4b529d85fa33','詩酒六首  其一','華鎮','宋','宋诗','song-poetry','','[]','大雅讀書勤苦外，肯來文會盍簪中。',64,'全唐诗/poet.song.60000.json','["大雅讀書勤苦外，肯來文會盍簪中。", "詛盟吾欲出三物，續社君當圖九翁。", "綠橘未題霜降顆，黄楊纔長閏餘叢。", "後成若援蘭亭例，金谷樽看誰罰空。"]'),
('a41c8f78-2ef9-4650-81fd-40f632f42079','詩酒六首  其二','華鎮','宋','宋诗','song-poetry','','[]','文力尤能草上風，後生橫槊鬭詩中。',64,'全唐诗/poet.song.60000.json','["文力尤能草上風，後生橫槊鬭詩中。", "諸君共利先登將，一我甘爲左次翁。", "水至細流皆入海，材爲直木必由叢。", "筆端衮衮淳于夥，未覓膏油炙轂空。"]'),
('1ac541b0-c1ad-4bc8-87cc-196d407796a5','詩酒六首  其三','華鎮','宋','宋诗','song-poetry','','[]','辭宦各歸千里外，滿城不出數家中。',64,'全唐诗/poet.song.60000.json','["辭宦各歸千里外，滿城不出數家中。", "得詩夜共嘲騷客，次韵時來寄子翁。", "已分鷺鸞垂翠葆，尚能魚目鬭珠叢。", "人生閒裏還無此，白首光陰過莫空。"]'),
('6aa68e30-a860-45c2-872a-6dc55dd42b7c','詩酒六首  其四','華鎮','宋','宋诗','song-poetry','','[]','已在淵明歸去後，只消長慶醉吟中。',64,'全唐诗/poet.song.60000.json','["已在淵明歸去後，只消長慶醉吟中。", "詩名未到出藍者，酒德忘爲垂白翁。", "刻燭分題喉每噤，揮杯多酌指如叢。", "攔街拍手兒童笑，十日醒無一日空。"]'),
('0c8ded31-2e4a-4a6e-a15e-8fd560aac754','詩酒六首  其五','華鎮','宋','宋诗','song-poetry','','[]','殘醉偶思京輦下，戲言堪入和章中。',64,'全唐诗/poet.song.60000.json','["殘醉偶思京輦下，戲言堪入和章中。", "詞因公度李道可，印借夢卿成孺翁。", "荒怪定逾詩律外，風流誰筆笑林叢。", "張而不弛非文武，莞爾牛刀未可空。"]'),
('0d0011be-5b22-4261-8292-1e7d41bf13a5','詩酒六首  其六','華鎮','宋','宋诗','song-poetry','','[]','商搉文章論要公，切雲千仞將壇中。',64,'全唐诗/poet.song.60000.json','["商搉文章論要公，切雲千仞將壇中。", "詩人何地可安我，醜婦今朝纔拜翁。", "彫玉苦心爲楮葉，繡衣謾眼束柴叢。", "南鄰寄謝梁兵部，險韵無勞獨斷空。"]'),
('2b04f569-e547-4b68-91b7-231e89dd77c3','暖齋詩','華鎮','宋','宋诗','song-poetry','','[]','至足無求觸處同，小齋和氣日沖融。',64,'全唐诗/poet.song.60000.json','["至足無求觸處同，小齋和氣日沖融。", "几筵已得嘯歌地，赤白何須繪畫工。", "况有午簷容愛日，曾無北戶召寒風。", "清心迥出塵埃外，詎見高堂數仞崇。"]'),
('ed734bc4-484a-42f6-ab4d-07311e676aa2','雪中寄徐主簿','華鎮','宋','宋诗','song-poetry','','[]','出門四幕雲垂地，舉目千花雪映天。',64,'全唐诗/poet.song.60000.json','["出門四幕雲垂地，舉目千花雪映天。", "况是光陰猶故臘，何妨時日在新年。", "不辭登頓行長道，但喜豐穰屬大田。", "遥羨風流栖枳客，一焚檀篆達誠虔。"]'),
('619744af-6d58-46fc-b728-2816cd48cc78','次韵酬道州同官雪中召飲','華鎮','宋','宋诗','song-poetry','','[]','千林臘雪綴玫瑰，爲送豐年好信來。',64,'全唐诗/poet.song.60000.json','["千林臘雪綴玫瑰，爲送豐年好信來。", "有客倚樓吹玉笛，何人立馬傍銀臺。", "書齋喜白臨窗紙，妝閣驚藏照臉梅。", "清景可憐佳句重，爲君隨分把金杯。"]'),
('52a221d9-4ac6-4d87-ba68-b45792d28a5c','和石太傅錢清僧舍圍爐余時先往蕭山不預其會','華鎮','宋','宋诗','song-poetry','','[]','後進多年仰碩膚，相逢如恨日將晡。',64,'全唐诗/poet.song.60000.json','["後進多年仰碩膚，相逢如恨日將晡。", "懽懷想不辭醇酎，高論應須出大鑪。", "麗藻舊欽梁上客，清風今識漢潜夫。", "初慚不預芝蘭列，和得陽春愧已無。"]'),
('7087ea18-f4f1-47e7-9db1-ff1ac5ad6ab3','題畫鷹','華鎮','宋','宋诗','song-poetry','','[]','高飛遠走可人情，上蔡東青舊有名。',64,'全唐诗/poet.song.60000.json','["高飛遠走可人情，上蔡東青舊有名。", "誰在華堂饜鼎俎，自甘平野掠柴荆。", "心憂狐兔紛難盡，眼看豺狼恣不平。", "莫倚絲繩金縼美，弓藏鳥盡汝須驚。"]'),
('9f083139-ef91-4c0c-a6d9-89b96512d8e3','失題  其一','華鎮','宋','宋诗','song-poetry','','[]','暑往寒來春復秋，東西南北一萍浮。',64,'全唐诗/poet.song.60000.json','["暑往寒來春復秋，東西南北一萍浮。", "吳鈎越劍雖常淬，梁苑秦關祇浪遊。", "場屋同盟多列鼎，鄉閭小子亦封侯。", "十年窗下勞螢雪，今日明時漫白頭。"]'),
('de3eafc1-aeab-433b-91bc-a3b63915073e','失題  其二','華鎮','宋','宋诗','song-poetry','','[]','分宜浪迹學希夷，豈合將身涉事爲。',64,'全唐诗/poet.song.60000.json','["分宜浪迹學希夷，豈合將身涉事爲。", "無外縱知皆是幻，有中寧免强隨時。", "懶於中散人誰覺，貧過原思已自知。", "若有一廛容定省，肯將塵鞅自羈縻。"]'),
('9ab8410b-53ac-41e3-b879-40d754d4a74a','挽張約之','華鎮','宋','宋诗','song-poetry','','[]','盜跖有年顔子夭，千秋此理竟難昭。',64,'全唐诗/poet.song.60000.json','["盜跖有年顔子夭，千秋此理竟難昭。", "一枝仙果方成實，三葉階蘭已盡凋。", "壯志永違祇自恨，清魂一去更誰招。", "猶勝伯道終身後，應得幽冥慰寂寥。"]'),
('5226e3e7-9af1-4cd7-adc6-29295f6138a0','元夕','華鎮','宋','宋诗','song-poetry','','[]','節物隨時好，元宵興味多。',240,'全唐诗/poet.song.60000.json','["節物隨時好，元宵興味多。", "常年苦風雨，今夕偶晴和。", "天宇消氛翳，星華侵月波。", "六街紛合遝，兩觀迥嵯峨。", "平昔財多裕，歡心慮靡他。", "深沈閉閬苑，窈窕引巫娥。", "百斛澄瑶碧，千枝列芰荷。", "珠咽激清脆，霓袖競婆娑。", "頡頏將雛態，綿蠻命友歌。", "涓涓催急箭，殷殷尚鳴鼉。", "縹緲飛華幰，丁東振寶珂。", "東西歷登覽，南北遞經過。", "不惜雲罍罄，祇看牛影俄。", "恨無夸父足，擬擲魯陽戈。", "出入心忘計，晨昏用有那。", "佳時徒共樂，歡事不同科。", "牽率調弦管，安排具綺羅。", "有虞虛腹餒，那作醉顔酡。", "不見三千履，難逢十二梭。", "寂寥塵陌上，誰問夜如何。"]'),
('dad42d97-5e1f-47da-bbdc-e98b3f899144','贈越倅胡郎中','華鎮','宋','宋诗','song-poetry','','[]','天上元宵後，中階瑞氣豪。',72,'全唐诗/poet.song.60000.json','["天上元宵後，中階瑞氣豪。", "乾坤扶睿哲，山嶽孕英髦。", "識量東溟闊，才華北斗高。", "序遷登半刺，清選陟諸曹。", "慶旦回新律，邦人薦壽醪。", "椿齡祈永固，榮應呂虔刀。"]'),
('fe09e5c0-02fc-4836-839b-33408a905c30','寄焦公澤','華鎮','宋','宋诗','song-poetry','','[]','身世旋蓬轉，年華激矢忙。',288,'全唐诗/poet.song.60000.json','["身世旋蓬轉，年華激矢忙。", "漂流輕楚越，契闊易參商。", "竊預三千日，行幾二十霜。", "金聲留逸響，玉潤有餘光。", "仕路雖叨踐，心蹊未敢荒。", "軒昂遺俗物，感激企前芳。", "燕雀驚鴻鵠，鴟鳶嚇鳳凰。", "傾都無孟子，通國毀匡章。", "曾席雖云遠，韓門未見忘。", "鑠金頻減價，投杼幾循牆。", "素履微難任，流言衆覺强。", "箴言曾展轉，攻鼓或相將。", "睠想周賓裔，來居禹計鄉。", "一門如旅燕，三世寄飛梁。", "何地逢遺秉，誰垣有樹桑。", "釜魚時肖范，儲石每矜揚。", "儒術資斑見，鄉評假寸長。", "芹藜經伏臘，蘋藻備烝嘗。", "紵絮虧冬褐，丹鉛薄曉妝。", "晚蟬無重翼，瀌雪有驕陽。", "唐彀虛曾入，齊飛宛未翔。", "十年勞俛仰，三釜足凄凉。", "懷刺終思重，車塵舊恥望。", "有慚猗頓富，徒效老萊裝。"]'),
('66952e85-67e7-4859-b280-90da3ea291e3','送湖南運判張朝散','華鎮','宋','宋诗','song-poetry','','[]','幽野葽含秀，周朝麥薦新。',120,'全唐诗/poet.song.60000.json','["幽野葽含秀，周朝麥薦新。", "祇園纔浴像，嵩嶽復凝神。", "鵲印天休裔，書林世貴人。", "江山分秀氣，珪璧粉天真。", "三篋傳遺緒，前籌起逸塵。", "人間欣得瑞，席上藹爲珍。", "平步游英彀，長驅歷要津。", "星軺聊按指，元鼎佇經綸。", "熊夢祥占日，斑衣色養辰。", "雲鵬方萬里，海鶴本千春。"]'),
('cdb1a656-94d4-40f5-b96f-304504368269','壽蔡大資','華鎮','宋','宋诗','song-poetry','','[]','德緒先流慶，高門早誕賢。',180,'全唐诗/poet.song.60000.json','["德緒先流慶，高門早誕賢。", "星杓方歷次，羲馭欲周天。", "博大天殊稟，高明道有傳。", "逢原從左右，中禮在周旋。", "網轄提携早，樞機委寄專。", "先猷重有作，廟筭遠無前。", "避寵辭帷幄，分華出澗瀍。", "條流圖外事，談笑握中權。", "吏膽銷精密，民心適靜便。", "旆閒清洛日，牙聳碧嵩烟。", "世路觀無跡，神機體善淵。", "弦歌隨絳帳，筆削起韋編。", "已覺留司久，彌增注想堅。", "鈞衡終所倚，衮繡佇來還。", "今日知祈禱，靈椿比大年。"]'),
('788dcfa4-1193-4533-a901-067bbbd339e3','水壁','華鎮','宋','宋诗','song-poetry','','[]','畫手聞曹霸，伊人豈裔孫。',240,'全唐诗/poet.song.60000.json','["畫手聞曹霸，伊人豈裔孫。", "窮神邈江海，遺迹在牆垣。", "發地驚濤起，扶椽疊浪翻。", "來非自胥怒，去不爲鯨吞。", "咫尺重淵險，尋常萬里奔。", "氣疑烝宇宙，勢欲浸乾坤。", "但見揮長筆，誰能測巨源。", "汪洋須駭矚，漥突幾驚捫。", "湛湛將澄處，悠悠疊細痕。", "輕颸掠伊洛，闊岸漫湘沅。", "怒勢功尤壯，飛瀾地欲掀。", "滄溟擁神島，窮髮運游鵾。", "槃礴應無顧，安排自有門。", "夙成參造化，無用契胚渾。", "歲久人雖遠，塵侵墨未昏。", "依稀逢海若，彷彿弔湘魂。", "倦客縈多累，乘桴特未援。", "時來觀浩蕩，聊用滌塵煩。", "莫使蝸涎蠹，常令墨妙存。", "不勞浮渤澥，已似陟崑崙。"]'),
('695aa699-4e7f-4a73-ad50-fd3a67d0f31a','送新廣西提刑曹司勳','華鎮','宋','宋诗','song-poetry','','[]','勳業平陽重，才華子建先。',288,'全唐诗/poet.song.60000.json','["勳業平陽重，才華子建先。", "高風延世濟，大筆得家傳。", "事至皆游刃，辭新盡應弦。", "從容登桂籍，慷慨躐英躔。", "不下文彌蔚，曾磨質更堅。", "鵷鴻傾義路，旒扆賞辭編。", "善誘恢師範，良圖悚幕蓮。", "雄鳴聲闊達，高舉勢騰騫。", "中外資裁制，交遊喜薦延。", "入趨蘭省祕，出擁繡衣鮮。", "封域三苗舊，江山五嶺連。", "楚風輕有素，蠻俗混難銓。", "飛輓歸豐羨，經營出靜便。", "霜威嚴不試，鏡照朗無前。", "玉石胸中判，龍蛇度外捐。", "冥心投至理，寓興起新篇。", "不羨懷沙潔，羞稱賦鵩賢。", "團茆方息駕，隠几欲忘筌。", "杯水澄朝彩，爐香炷久烟。", "有餘論墨妙，無問及筳篿。", "華實湖湘外，聲名日月邊。", "泥封俄迅激，竹律未周旋。", "畏景明流石，薰飈穆汎弦。", "星車躔嶺徼，虎節起湘川。"]'),
('d27f8b30-f4f9-4fa1-8560-2388b9dfa5db','魚戲動新荷','華鎮','宋','宋诗','song-poetry','','[]','風日向清和，游魚水面多。',72,'全唐诗/poet.song.60000.json','["風日向清和，游魚水面多。", "逶迤浮巨壑，搖漾動新荷。", "密倚纖茄轉，輕翻綠影俄。", "參差吹弱藻，瀲灧起微波。", "躍躍同盈沼，洋洋類舞河。", "因知濠上意，不羨越溪歌。"]'),
('ac483559-354d-4207-b1a6-1677df11f3ac','嶧陽孤桐','華鎮','宋','宋诗','song-poetry','','[]','大樂潜生氣，徐方暗結融。',240,'全唐诗/poet.song.60000.json','["大樂潜生氣，徐方暗結融。", "嶧陽鍾異物，山木得孤桐。", "特幹千尋聳，清陰十畝豐。", "夜聲通渤澥，午影到崆峒。", "雨露偏垂德，陰陽曲致工。", "和音來象外，懿質孕區中。", "不羨樗無用，常卑桂有叢。", "人期瞻舜日，自信達堯聰。", "動植奚難感，神明庶可通。", "鏗鏘雖固有，翦拂未曾蒙。", "合梓纔知美，弦絲乃見功。", "名嘗叨禹紀，材實待夔攻。", "埋沒如邕爨，栽培異楚宮。", "山禽曾不識，丹鳳每來同。", "沆瀣凝朝氣，滄凉汎曉曈。", "發揚羞谷黍，疏散愧江楓。", "誓與簫韶並，寧隨曆草空。", "儻教承搏拊，焉敢避磨礲。", "功用施清廟，聲華發大東。", "知音何以報，願爲奏南風。"]'),
('d2e50836-2386-444c-a318-f94926343527','送越州僉判徐狀元赴闕','華鎮','宋','宋诗','song-poetry','','[]','彼美司刑士，言辭越幕賓。',288,'全唐诗/poet.song.60000.json','["彼美司刑士，言辭越幕賓。", "斑衣登彩舫，羅袖擁雕輪。", "重過千年會，輕捐萬壑春。", "拂檣風習習，汎楫水鱗鱗。", "仰念當朝律，高還治古淳。", "嘉猷皆建置，弊法不因循。", "食餠無容畫，觀龍必貴真。", "進賢非積累，懷寶免湮淪。", "徒步升黄閣，元台出渭濱。", "昔年書舊史，今日在嚴宸。", "志士休歌鳳，鴻儒罷泣麟。", "不愁長待價，祇恐未能仁。", "盛世當千士，明公第一人。", "詞場無大敵，桂苑絕前塵。", "雅譽多材藝，雄居要路津。", "規爲真大器，薦擢易常倫。", "紺髮年方壯，清光日向親。", "橫飛朝鼎鼐，跬步職絲綸。", "學問功無愧，經綸志必伸。", "善將兼海內，澤可下天民。", "既得風雲便，應爲柱石臣。", "已知材似杞，惟貴壽如椿。", "猥似卑凡質，同居晏粲辰。", "問年雖魯衛，語士迺齊秦。"]'),
('88d69974-df90-4852-b4cd-67e757b8cd12','送越倅胡郎中入京','華鎮','宋','宋诗','song-poetry','','[]','雄鎮揚州域，前聞越絕靈。',288,'全唐诗/poet.song.60000.json','["雄鎮揚州域，前聞越絕靈。", "天文直牛女，地勢壓滄溟。", "霸業雖陳迹，王圖乃舊經。", "遺風終樸素，彌世慎儀刑。", "紆綬皆英彀，乘軒盡德馨。", "迄今無僭濫，自古底安寧。", "碩德居華旦，清資應列星。", "司城新進秩，別乘舊揚軨。", "妙譽高藩翰，嘉名藹闕廷。", "自堪剖符竹，猶此駕箳篂。", "裨替無遺恨，平反得所聽。", "威儀嚴肅穆，文雅煥青熒。", "裁决真穿縞，經綸甚建瓴。", "屬城嘗乏守，茂績可書屏。", "完士終何感，丹心獨願銘。", "淪埋脫吳阪，知賞謬柯亭。", "述業知晞驥，多聞媿識鼮。", "成風非匠石，合舞謝庖丁。", "濫擬窺場藿，叨曾食野苹。", "禹門俄暴鬣，陶夢輒摧翎。", "捧檄終堪喜，彈冠詎可停。", "未能餐沆瀣，安敢卧清泠。", "山藪容樗櫟，川河納渭涇。", "不教長在澗，還許預充庭。"]'),
('7a53cb3c-a4a7-417e-b410-1794ce6ee241','送湖南提舉梁朝散','華鎮','宋','宋诗','song-poetry','','[]','公族流芳遠，侯門積慶長。',120,'全唐诗/poet.song.60000.json','["公族流芳遠，侯門積慶長。", "玉田收地寶，蘭畹毓天香。", "岐嶷英姿妙，魁梧德宇强。", "嶽靈分秀氣，昴宿注祥光。", "世濟居彌厚，官成動有章。", "題輿高右陝，持節重西湘。", "二九朝陽永，中秋夕月凉。", "誕彌迎節至，嘉慶肆筵芳。", "檀篆金爲鼎，榴花玉作觴。", "願言齊鶴壽，平步冠鵷行。"]'),
('93fcc5e8-2cab-4d19-8152-8f13c748d09d','和通州李判官','華鎮','宋','宋诗','song-poetry','','[]','憶昔元豐第二春，叨陪逸駕預官論。',96,'全唐诗/poet.song.60000.json','["憶昔元豐第二春，叨陪逸駕預官論。", "頻煩州縣徒勞職，未報君親罔極恩。", "居與莞蒲依海角，出隨雁鶩走江村。", "閑心祇合尋三徑，倦翼寧堪憩九門。", "羊棗幸占如養志，萊衣欣有喚翁孫。", "他時未免煩陶鑄，只就同年丐漆園。"]'),
('0b369e50-f0be-4518-ac00-90de10dbe531','送越帥程給事赴詔','華鎮','宋','宋诗','song-poetry','','[]','清華仙殿圖書府，貴近東臺侍從郎。',384,'全唐诗/poet.song.60000.json','["清華仙殿圖書府，貴近東臺侍從郎。", "寵被買臣榮遇紱，來臨安石宴遊鄉。", "下車建設先條教，暖席施爲盡紀綱。", "鑑物浄明齊上水，臨機鋒銳踰干將。", "威稜直爲摧姦宄，德惠陰知佑善良。", "意匠經營真有趣，軸機裁處動非常。", "謹嚴庭訟情無失，檢察民輸弊已亡。", "坐使姦胥難用巧，默令雅俗盡知方。", "淳和只有興廉遜，肅治應無敢寇攘。", "蓮幕終朝閒筆削，圜扉經歲絕桁楊。", "精藍振起都城美，新館增延使者光。", "翦拂散材充大匠，吹噓寒谷變春陽。", "三年治最騰歌頌，千里聲和協雨暘。", "何但編氓稱五袴，已令比屋有千箱。", "風流自得篇章樂，閒暇人驚日月長。", "彩舫有時羅綺繡，朱轓到處擁絲簧。", "尋窮萬壑幽深趣，踏徧千巖紫翠芳。", "絕唱未饒元相國，遺風獨揖賀知章。", "香山圖畫知嘗預，魏闕心誠想未忘。", "下國可能留近侍，雄材自合在巖廊。", "祥光一夜生台座，優詔平明出未央。", "漢殿果深思董賈，越人那久得龔黄。", "丹書東下隨秋雁，畫鷁西征拂曉霜。", "不獨飛章留去轍，况多扶老擁歸艎。"]'),
('e137e718-a968-4104-9682-d2700f5fc385','次韵酬桂陽石知監懷鄉見寄','華鎮','宋','宋诗','song-poetry','','[]','南北周旋事屢更，剖符纔喜慰蒼生。',128,'全唐诗/poet.song.60000.json','["南北周旋事屢更，剖符纔喜慰蒼生。", "米鹽無滯綱條密，雀鼠難欺獄訟平。", "樽俎有餘今北海，篇章多暇古宣城。", "桃源善慶時難擬，金谷風流世有名。", "榮擁雙旌忘自得，永懷三徑念同情。", "鄉閭分義千鈞重，筆墨才華一座傾。", "官異微之慚未稱，報殊平子愧非精。", "折腰寂寞將何遣，稔聽龔黄布政聲。"]'),
('0d4f9301-dd15-4766-af71-586595fa90f4','湖南運使柯少卿壽','華鎮','宋','宋诗','song-poetry','','[]','星杓旋指始回寅，遲日烘天欲再旬。',160,'全唐诗/poet.song.60000.json','["星杓旋指始回寅，遲日烘天欲再旬。", "安寢熊羆通吉夢，高門弧矢見成人。", "江山孕美寬爲量，奎壁騰芒秀入神。", "學苑遠窮三篋富，辭林榮占一枝春。", "分麾閩越閒餘刃，賜筆中臺播逸塵。", "棘寺入陪鵷列久，湘源來著繡衣新。", "笑談已集金糧最，眄睞無遺玉石真。", "不憚高才親遠使，更將和氣裕斯民。", "華資分合歸無已，眉壽陰須付有仁。", "幕下晚生欣庇德，强歌精意指靈椿。"]'),
('86a40f1d-a542-4ddd-8cfd-0096ed8007a9','用石桂陽韵謝左判官陳司理見寄','華鎮','宋','宋诗','song-poetry','','[]','曾挹清談僕屢更，解頤聊足慰平生。',128,'全唐诗/poet.song.60000.json','["曾挹清談僕屢更，解頤聊足慰平生。", "共觀雲物懷虞帝，爲引漁翁問屈平。", "一逐曉風分客路，兩逢春雨暗山城。", "寒林不見遷鶑語，古壁多逢逐客名。", "懷寄遠隨賢守句，愛忘深識故人情。", "參軍筆力湘山峭，幕府辭源峽水傾。", "刻燭賦詩曾有意，臨池掃帚未能精。", "强將西缶臨風擊，終遜玲瓏戛玉聲。"]'),
('7949d379-937a-49d6-b572-d20d16c561a9','挽宗嶽張尊師','華鎮','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','神仙去住本無家，此日人間漫歎嗟。',224,'全唐诗/poet.song.60000.json','["神仙去住本無家，此日人間漫歎嗟。", "華表舊傳歸白鶴，洞庭誰見袖青蛇。", "道山兩拂談經麈，滄海頻乘犯斗槎。", "雙玉佩沾天上露，五銖衣識洞中霞。", "林泉投老心猶壯，京國歸來鬢未華。", "短製從今牽薜荔，雜耕依舊種胡麻。", "風生謝傅團團扇，花隠堯夫小小車。", "逸興逍遥舟不繫，新詩妙絕玉無瑕。", "松邊對酒依盤石，竹裏分泉洗落花。", "一自青冥餐沆瀣，更誰黄犢侶麏麚。", "丹初封鼎雲猶濕，棋未收枰日已斜。", "每過竹軒深有恨，獨憐溪閣靜無譁。", "匣中不見龍三尺，畫裏空餘雪兩髽。", "回首方蓬歸路遠，五雲愁殺樹交加。"]'),
('86c8d79c-06c0-4051-bdfa-aa84d80c20a9','宮使蔡太師壽詩','華鎮','宋','宋诗','song-poetry','','[]','天貽真宰贊重熙，何日來符命世期。',128,'全唐诗/poet.song.60000.json','["天貽真宰贊重熙，何日來符命世期。", "五夜燕遊元夕後，三陽交泰上春時。", "維師事業前無呂，先覺心靈世有伊。", "首斡化機熙帝載，暫休祠館動民思。", "和羹終付鹽梅手，仗節難稽柱石姿。", "華屋早開丞相第，衮衣新賦我公詩。", "緗桃滿院光風轉，素李成蹊淑景遲。", "鼎席具瞻何所願，祝公眉壽等蓮龜。"]'),
('46f4794e-045f-4334-b096-0636ca19af94','謝成都楊匯秀才惠邛州竹杖二首  其一','華鎮','宋','宋诗','song-poetry','','[]','臨邛石上老龍孫，雪抱霜封有舊痕。',32,'全唐诗/poet.song.60000.json','["臨邛石上老龍孫，雪抱霜封有舊痕。", "聳削已知非俗物，更堪來自草玄門。"]'),
('b97d0c2f-78cd-485a-aaa6-f43dfe382dae','謝成都楊匯秀才惠邛州竹杖二首  其二','華鎮','宋','宋诗','song-poetry','','[]','邂逅相逢又別離，驟承佳貺意何其。',32,'全唐诗/poet.song.60000.json','["邂逅相逢又別離，驟承佳貺意何其。", "應憐越絕閑雲客，酷似臨邛瘦竹枝。"]'),
('e089423a-cc15-4954-8689-068d9c241d73','過澗','華鎮','宋','宋诗','song-poetry','','[]','兩山分處水橫流，渡水登山趣更幽。',32,'全唐诗/poet.song.60000.json','["兩山分處水橫流，渡水登山趣更幽。", "却憶當年謝康樂，等閒羈束爲封侯。"]'),
('ff769266-bdf9-49a6-a987-975fb5ec3f4b','河上','華鎮','宋','宋诗','song-poetry','','[]','沙頭兩兩飛歸雁，水面茸茸長綠蒲。',32,'全唐诗/poet.song.60000.json','["沙頭兩兩飛歸雁，水面茸茸長綠蒲。", "知是人間好時節，不妨河上弄泥塗。"]'),
('b131110c-a7ad-44b2-966f-bb2f83816e0f','聞歌','華鎮','宋','宋诗','song-poetry','','[]','來時梅萼粘殘雪，歸日桃花簇絳羅。',32,'全唐诗/poet.song.60000.json','["來時梅萼粘殘雪，歸日桃花簇絳羅。", "農事不妨河事了，齊聲連路踏春歌。"]'),
('5c087424-1edc-49ea-9271-972b76d8263e','秋風','華鎮','宋','宋诗','song-poetry','','[]','秋風昨夜落前林，放出千巖秀色深。',32,'全唐诗/poet.song.60000.json','["秋風昨夜落前林，放出千巖秀色深。", "欲結草廬歸未得，倚欄空負季鷹心。"]'),
('2944067f-b54c-4f5f-a6ec-aef073316bb8','上顧侍郎詩','華鎮','宋','宋诗','song-poetry','','[]','西漢風流古到今，油油巵酒待青襟。',32,'全唐诗/poet.song.60000.json','["西漢風流古到今，油油巵酒待青襟。", "後堂不許聞歌舞，始覺先生見與深。"]'),
('52a35516-7adb-49e6-81aa-9b5b0d618c4b','渡嶺','華鎮','宋','宋诗','song-poetry','','[]','嶺路林梢一線通，肩輿直上破林風。',32,'全唐诗/poet.song.60000.json','["嶺路林梢一線通，肩輿直上破林風。", "眼前遥見東山樹，却顧青衫愧謝公。"]'),
('a73c0a3c-fe72-48d5-883f-e93fcf4e0bf9','四海','華鎮','宋','宋诗','song-poetry','','[]','四海田廬自有餘，置錐無地欲尤誰。',32,'全唐诗/poet.song.60000.json','["四海田廬自有餘，置錐無地欲尤誰。", "鷦鷯莫厭一枝少，更有寄巢無一枝。"]'),
('5e59bc7f-492f-4e80-8754-f15ba157b102','歷陽道中','華鎮','宋','宋诗','song-poetry','','[]','江北江南未定時，襟喉此地繫安危。',32,'全唐诗/poet.song.60000.json','["江北江南未定時，襟喉此地繫安危。", "頹營故壘皆蕪沒，日落寒生楓樹枝。"]'),
('825178d4-0aa9-4a71-a7f2-9f564b64fa6f','江南湖陽','華鎮','宋','宋诗','song-poetry','','[]','末俗頹風正可悲，當時强項是男兒。',32,'全唐诗/poet.song.60000.json','["末俗頹風正可悲，當時强項是男兒。", "君王不似南陽日，此事寧教女子知。"]'),
('02890bac-f89d-4b51-84d0-58c7011986c6','石磧漢高帝廟','華鎮','宋','宋诗','song-poetry','','[]','黄屋何曾駐未央，十年關外蹀寒霜。',32,'全唐诗/poet.song.60000.json','["黄屋何曾駐未央，十年關外蹀寒霜。", "靈祠今日秋江上，門鏁丹楓似楚王。"]'),
('e5817456-64a8-4f37-9466-87737ff38b80','緱氏道中口占','華鎮','宋','宋诗','song-poetry','','[]','人道自有上天梯，塵暗靈襟路却迷。',32,'全唐诗/poet.song.60000.json','["人道自有上天梯，塵暗靈襟路却迷。", "不見吹笙王子晉，獨乘玄鶴碧嵩西。"]'),
('00b249f1-1ecc-4cd7-b781-5458ab43345a','立春日雪  其一','華鎮','宋','宋诗','song-poetry','','[]','金絲未徧千門柳，玉葉纔分五嶺梅。',32,'全唐诗/poet.song.60000.json','["金絲未徧千門柳，玉葉纔分五嶺梅。", "青帝似憐芳信少，更教春日六花開。"]'),
('35a94eea-5a86-4f1e-8fd9-578f453c167e','立春日雪  其二','華鎮','宋','宋诗','song-poetry','','[]','斜入芳筵沾綵勝，密鋪幽徑點蘭芽。',32,'全唐诗/poet.song.60000.json','["斜入芳筵沾綵勝，密鋪幽徑點蘭芽。", "謝娘子細臨看取，不是楊花是雪花。"]'),
('bc8cd07c-f2e3-4661-80e9-cff98e21ccf0','挽饒法主','華鎮','宋','宋诗','song-poetry','','[]','緇服薰修九十春，法筵長爲指通津。',32,'全唐诗/poet.song.60000.json','["緇服薰修九十春，法筵長爲指通津。", "經窗未冷銅爐火，已作他方應化身。"]'),
('9ba079bf-7908-4964-a0bb-3a9de45b8832','方城道中值雨','華鎮','宋','宋诗','song-poetry','','[]','重雲三日鎖前山，麥隴泥塗尚未乾。',32,'全唐诗/poet.song.60000.json','["重雲三日鎖前山，麥隴泥塗尚未乾。", "行路春光已𢬵棄，任從風雨作輕寒。"]'),
('5501e530-7ee1-4fdf-a52c-98a83f28d1cc','和叔凭惜春  其一','華鎮','宋','宋诗','song-poetry','','[]','無計可能留永日，有情何用惜芳春。',32,'全唐诗/poet.song.60000.json','["無計可能留永日，有情何用惜芳春。", "明年還似今年好，𢬵作花前把酒人。"]'),
('666d2c63-93f3-4feb-a6e5-692400cc6b94','和叔凭惜春  其二','華鎮','宋','宋诗','song-poetry','','[]','柳暗曉鶑鳴樹底，簾垂午燕簇樓頭。',32,'全唐诗/poet.song.60000.json','["柳暗曉鶑鳴樹底，簾垂午燕簇樓頭。", "東君暫去無多日，且放殘紅逐水流。"]'),
