('3ba367a7-04d3-49fe-8ab3-289fcf5f7713','題滴水巖','席汝明','宋','宋诗','song-poetry','','[]','塞上風埃撲眼多，飛泉欣見此巖阿。',64,'全唐诗/poet.song.61000.json','["塞上風埃撲眼多，飛泉欣見此巖阿。", "冰絲不斷銀潢脈，珠滴長圓月窟波。", "暫轉杯觴閑屈曲，忽爲霖雨下霶𩃱。", "形容好景須詩筆，萬古蒼崖始一磨。"]'),
('c226452e-e7a3-42a7-8cf9-fc1a47b53f19','題滴水巖','常傳正','宋','宋诗','song-poetry','','[]','朦朧秋月助光輝，飄泊春風濺客衣。',64,'全唐诗/poet.song.61000.json','["朦朧秋月助光輝，飄泊春風濺客衣。", "百尺水晶簾不捲，數峰巫峽雨長飛。", "羽觴脩禊行將近，蠟屐登山定不稀。", "自恨雲巖跡如掃，仗君借眼矚芳菲。"]'),
('47f0c375-dc28-43b6-89ff-23e0e867f49e','送程給事知越州  其一','畢仲連','宋','宋诗','song-poetry','','[]','玉籍殊科四十秋，徊翔藩翰幾淹留。',64,'全唐诗/poet.song.61000.json','["玉籍殊科四十秋，徊翔藩翰幾淹留。", "五羊舊治功尤著，百越新恩志已酬。", "健節亭亭心益壯，清吟一一思如流。", "壺漿滿道爭迎處，晝錦應先駐虎邱。"]'),
('099ef647-90e7-4dab-b90e-6767a8bacd25','送程給事知越州  其二','畢仲連','宋','宋诗','song-poetry','','[]','鐃鼓喧喧逐迅流，旆旌明滅擁行舟。',64,'全唐诗/poet.song.61000.json','["鐃鼓喧喧逐迅流，旆旌明滅擁行舟。", "三吳作鎮侯藩重，一道提兵帝澤優。", "錦里江山歸興逸，鑑湖風月到時秋。", "祇應圖任須元老，促召猶能駐虎丘。"]'),
('96afab5b-d985-415e-94c4-5e2c44be2250','送程給事知越州','謝惇','宋','宋诗','song-poetry','','[]','夕郎暫去赤墀班，寵佩藩符出漢關。',64,'全唐诗/poet.song.61000.json','["夕郎暫去赤墀班，寵佩藩符出漢關。", "江國正逢鱸味美，里閭先著錦衣還。", "賞追賀監湖邊月，醉陟秦王甕畔山。", "萬壑千巖常在眼，詩情應喜訟庭閑。"]'),
('e7b58763-8c35-4b7a-a4c4-8865f56d47c9','詩一首','仵磐','宋','宋诗','song-poetry','','[]','太一峰前是我家，滿床書籍舊生涯。',32,'全唐诗/poet.song.61000.json','["太一峰前是我家，滿床書籍舊生涯。", "春城戀酒不歸去，老却碧桃無限花。"]'),
('00bf1107-ed48-4bb1-8299-3dbfedc9be85','四景樓','李愿','宋','宋诗','song-poetry','','[]','縱目有佳處，須登四景樓。',48,'全唐诗/poet.song.61000.json','["縱目有佳處，須登四景樓。", "輸蹄喧市井，桑穀暗郊丘。", "翠蓋雲生裏，滄溟天盡頭。", "闌干知幾曲，徙倚恣清愁。"]'),
('7acf7b77-303d-41f4-a4ce-0dbd19047751','望仙門','李愿','宋','宋诗','song-poetry','','[]','樓影空門裏，門開望衆仙。',48,'全唐诗/poet.song.61000.json','["樓影空門裏，門開望衆仙。", "綠鬟雲漠漠，翠黛月娟娟。", "烟駕知何處，星槎記昔年。", "夕陽孤鳥畔，緲緲海浮天。"]'),
('aea3a1de-c197-4409-8118-e1cb3b6b94b8','寄張芸叟','喻陟','宋','宋诗','song-poetry','','[]','越客思歸黯不平，閑持長笛寫秦聲。',64,'全唐诗/poet.song.61000.json','["越客思歸黯不平，閑持長笛寫秦聲。", "羨君氣海如斯壯，博我詞鋒孰敢爭。", "江上梅花開又落，隴頭流水咽還驚。", "豈知不寐鰥魚眼，獨坐山堂對月明。"]'),
('6b7b8a4e-7696-4841-91cf-a9cb890392d6','題呂元圭詩後','喻陟','宋','宋诗','song-poetry','','[]','黄鶴樓邊橫笛吹，石亭窗上更題詩。',32,'全唐诗/poet.song.61000.json','["黄鶴樓邊橫笛吹，石亭窗上更題詩。", "世人不識還歸去，江水雲山空渺瀰。"]'),
('cf43b82c-dee9-49f1-8689-c098e4c83862','賀种太守破鬼章  其一','喻陟','宋','宋诗','song-poetry','','[]','捷報下岷洮，威傳萬里遥。',48,'全唐诗/poet.song.61000.json','["捷報下岷洮，威傳萬里遥。", "渠魁咸面縛，氛祲即時銷。", "聖算百王上，神功千古超。", "從茲荒忽地，無復恣凶驕。"]'),
('09c27a1c-97ab-45b0-8498-475782f187fb','賀种太守破鬼章  其二','喻陟','宋','宋诗','song-poetry','','[]','黠鹵方千軌，王師薄有征。',48,'全唐诗/poet.song.61000.json','["黠鹵方千軌，王師薄有征。", "摧枯祇俄頃，破竹不留行。", "殺氣收貔虎，清風捲旆旌。", "遥瞻紫宸闕，稱賀浹歡聲。"]'),
('da48bece-d177-46a6-92ce-e47d533322b8','賀种太守破鬼章  其三','喻陟','宋','宋诗','song-poetry','','[]','周后持盈日，戎夷負固年。',48,'全唐诗/poet.song.61000.json','["周后持盈日，戎夷負固年。", "廟謨期必勝，閫略制於先。", "不假天山箭，行聞杕杜篇。", "凱還俘馘獻，圖像有凌烟。"]'),
('f74b94d6-05cd-4abb-9c97-28a0ce7f5d25','句  其一','喻陟','宋','宋诗','song-poetry','','[]','黄鶴仙人隔千古，太白英靈在何許。',16,'全唐诗/poet.song.61000.json','["黄鶴仙人隔千古，太白英靈在何許。"]'),
('f79a74bf-109b-4ab1-bed2-fb8a6c246f15','句  其二','喻陟','宋','宋诗','song-poetry','','[]','費禕丁令亦何之。',8,'全唐诗/poet.song.61000.json','["費禕丁令亦何之。"]'),
('9c201492-7adb-4f8a-a882-3d2eef447269','句  其三','喻陟','宋','宋诗','song-poetry','','[]','游蜂與狂蝶，無計旁檀心。',12,'全唐诗/poet.song.61000.json','["游蜂與狂蝶，無計旁檀心。"]'),
('767af282-2892-41ff-8281-33809fd0cee0','遊終南山雜詠 草堂','李騊','宋','宋诗','song-poetry','','["\u7ec8\u5357\u5c71"]','入門脩竹聳琅玕，坐久香風拂畫欄。',64,'全唐诗/poet.song.61000.json','["入門脩竹聳琅玕，坐久香風拂畫欄。", "春色正穠雙檜靜，朝光初上一峰寒。", "翠縈虛室塵襟闊，冷逼疏窗夜夢殘。", "物外閑心殊未愜，殷勤重上白雲端。"]'),
('c5209fb4-785d-496b-a9da-b57d5b47a98e','遊終南山雜詠 宿紫閣','李騊','宋','宋诗','song-poetry','','["\u7ec8\u5357\u5c71"]','石磴溪橋傍翠巒，分明深入畫圖間。',64,'全唐诗/poet.song.61000.json','["石磴溪橋傍翠巒，分明深入畫圖間。", "遠繞禪剎疑無景，迥出群峰別有山。", "微雨欲來雲影亂，輕風不斷鳥聲閑。", "嵐光可是清人骨，更待中宵一夢還。"]'),
('0143d30d-9aa0-4f71-862c-d8486de30a17','遊終南山雜詠 雨後紫閣晚望','李騊','宋','宋诗','song-poetry','','["\u7ec8\u5357\u5c71"]','小雨初回作暮寒，斷崖壁立夕陽間。',32,'全唐诗/poet.song.61000.json','["小雨初回作暮寒，斷崖壁立夕陽間。", "一襟清興無人語，旋拂禪床卧看山。"]'),
('4431b1bd-3a70-487b-aae9-100682240e8c','遊終南山雜詠 雲際院','李騊','宋','宋诗','song-poetry','','["\u7ec8\u5357\u5c71"]','蔽日芳林迷去路，被蹊落葉誤行蹤。',32,'全唐诗/poet.song.61000.json','["蔽日芳林迷去路，被蹊落葉誤行蹤。", "轉巖却見層巒出，知是仙山第幾重。"]'),
('e08d0763-dcdb-432c-88c2-371655859a0a','遊終南山雜詠 長嘯洞','李騊','宋','宋诗','song-poetry','','["\u7ec8\u5357\u5c71"]','西風壁立蒼崖瘦，一水湍流怒浪翻。',32,'全唐诗/poet.song.61000.json','["西風壁立蒼崖瘦，一水湍流怒浪翻。", "雲外不須求紫府，祇應此景是桃源。"]'),
('47f84504-dfe9-4474-9fff-d6aa096cc62c','遊終南山雜詠 宿重雲山寺','李騊','宋','宋诗','song-poetry','','["\u7ec8\u5357\u5c71"]','漸侵晚景尤便靜，不出忙中豈愛閑。',32,'全唐诗/poet.song.61000.json','["漸侵晚景尤便靜，不出忙中豈愛閑。", "休問驊騮與蛙黽，會須投紱老青山。"]'),
('490b21f8-d714-43a1-8174-d37bb85a6b33','遊終南山雜詠 重雲道中海棠','李騊','宋','宋诗','song-poetry','','["\u7ec8\u5357\u5c71"]','萬點梢頭爛曉霞，謾隨閑世鬭春華。',32,'全唐诗/poet.song.61000.json','["萬點梢頭爛曉霞，謾隨閑世鬭春華。", "孤根自是生窮僻，未必輕輸別圃花。"]'),
('202a8d89-8846-49c1-840d-86de22180dac','遊終南山雜詠 宿白雲明日之鄠縣','李騊','宋','宋诗','song-poetry','','["\u7ec8\u5357\u5c71"]','蔽空穠綠門前路，匝地疏苗戶外村。',32,'全唐诗/poet.song.61000.json','["蔽空穠綠門前路，匝地疏苗戶外村。", "暫宿雲房叩虛寂，紅塵意味不堪論。"]'),
('3231e974-791d-4275-a53a-96cdc6f89c4b','遊終南山雜詠 渼陂','李騊','宋','宋诗','song-poetry','','["\u7ec8\u5357\u5c71"]','望極空蒙清滿懷，更尋遺跡步高臺。',64,'全唐诗/poet.song.61000.json','["望極空蒙清滿懷，更尋遺跡步高臺。", "日斜林杪增光去，風靜山尖倒影來。", "萬頃澄瀾春漲碧，一川秀色暝陰開。", "坐中自有江湖興，未放陂南畫舸回。"]'),
('5a6d553c-a32d-4696-9e00-4cb0142967d6','送程給事知越州','莫淵','宋','宋诗','song-poetry','','[]','北虜分庭正，東藩得郡優。',240,'全唐诗/poet.song.61000.json','["北虜分庭正，東藩得郡優。", "兼曹拋玉殿，重閣指蓬邱。", "節制連江海，封疆直斗牛。", "地雖鄰故里，人始識元侯。", "合浦珠還日，長河虎渡秋。", "溪山歸勝覽，風月入冥搜。", "使旆天邊去，樓船鑑裏遊。", "茶槍香泛泛，竹箭綠修修。", "樂苑花猶卉，蘭亭水尚流。", "千尋經石簣，八月看潮頭。", "蕭寺逢支遁，山陰憶子猷。", "昔賢嘗縱樂，太守好銷憂。", "倒載何妨作，扁舟未可謀。", "朝綱須急治，民瘼俟全瘳。", "青瑣從虛位，朱旛且少留。", "行當宣室召，還應傅巖求。", "德望終歸用，愚蒙祇自愁。", "官資卑執戟，身勢類浮鷗。", "每玷鄉人薦，長思國士酬。", "那堪聞疊鼓，惆悵送行輈。"]'),
('af1de086-3a16-495f-8f16-288c7f0e1399','遊虎丘','趙知章','宋','宋诗','song-poetry','','[]','神光在牛斗，空賦白雲篇。',48,'全唐诗/poet.song.61000.json','["神光在牛斗，空賦白雲篇。", "地坼龍泓冷，天分錦石圓。", "悠悠蕉鹿夢，的的露牛禪。", "再見窗中雪，應知宿有緣。"]'),
('a2f531cb-eff8-42bd-8270-0f885e1dba85','次韵奉和楊聖咨題李長者舊居','郭時亮','宋','宋诗','song-poetry','','[]','李氏當年著佛書，此邦猶記舊居廬。',32,'全唐诗/poet.song.61000.json','["李氏當年著佛書，此邦猶記舊居廬。", "因公尋訪松生語，不識何人爲守株。"]'),
('543b0edc-1537-46b6-9989-38aecdf16eb8','觀稼閣','鄭永中','宋','宋诗','song-poetry','','[]','公餘乘興步危樓，十里如雲翠欲流。',64,'全唐诗/poet.song.61000.json','["公餘乘興步危樓，十里如雲翠欲流。", "多稼芃芃天外闊，平湖渺渺望中浮。", "方忻民樂庭無訟，更聽農歌歲有秋。", "吏責已寬聊自得，待憑詩酒寓優游。"]'),
('ff204c00-2a1e-4b55-9679-8f5ced3f980e','重修岳陽樓','鄭民瞻','宋','宋诗','song-poetry','','["\u5cb3\u9633\u697c"]','偏歷江山祇此樓，名傳自古又今修。',64,'全唐诗/poet.song.61000.json','["偏歷江山祇此樓，名傳自古又今修。", "却觀湘水浮新景，重對君山記舊遊。", "風月依然如故友，軒窗今復冠南州。", "遠迢張相滕侯迹，幸躡前規壯勝遊。"]'),
('9543083d-b0d4-40f7-b4d2-f6b8bd476679','句','朱戴上','宋','宋诗','song-poetry','','[]','官閑無一事，蝴蝶飛上階。',12,'全唐诗/poet.song.61000.json','["官閑無一事，蝴蝶飛上階。"]'),
('c8472c25-6632-4941-90ca-fee8b95f0852','送蘇錄事赴虢州','郭霖','宋','宋诗','song-poetry','','[]','白首舊相知，茅津此去時。',48,'全唐诗/poet.song.61000.json','["白首舊相知，茅津此去時。", "馬驕青草色，柳綰綠烟絲。", "落日曹瞞壘，荒城虢仲祠。", "聖朝深雨澤，寧必嘆衰遲。"]'),
('814dc9c4-739a-4c58-b7a8-d4dc5e13929d','西耕','郭霖','宋','宋诗','song-poetry','','[]','鑿田喜得傍湖堤，湖水春來好灌畦。',32,'全唐诗/poet.song.61000.json','["鑿田喜得傍湖堤，湖水春來好灌畦。", "躬稼自甘名姓沒，不妨寂寞老巖棲。"]'),
('cae23241-a517-493b-a67c-9b4e9a572281','繇三茅直抵紫陽觀','郭霖','宋','宋诗','song-poetry','','[]','一上雲山思便幽，長松怪石坐淹留。',32,'全唐诗/poet.song.61000.json','["一上雲山思便幽，長松怪石坐淹留。", "乘風直造神仙窟，零落烟霞滿杖頭。"]'),
('de176601-066b-4233-b943-23fc9a8b662a','句','張楚民','宋','宋诗','song-poetry','','[]','香山正在岷山麓，一派流泉萬竿竹。',16,'全唐诗/poet.song.61000.json','["香山正在岷山麓，一派流泉萬竿竹。"]'),
('569d38ce-12a4-4043-a385-d906dc5b0541','泊舟','吳公敏','宋','宋诗','song-poetry','','[]','潭影靜沈沈，維舟傍竹林。',48,'全唐诗/poet.song.61000.json','["潭影靜沈沈，維舟傍竹林。", "鄉心寄孤雁，寒信起疏砧。", "犬吠人家近，燈明樹影侵。", "客愁元不寐，夜雨更蛩吟。"]'),
('f962bdb3-2f1b-42cf-9109-ff3c3a8f3a23','提刑都講頒賜題古楠寺佳篇伏讀翫味詞旨豪肆感歎戰汗不揆淺拙仰次嚴韵','楊庭傑','宋','宋诗','song-poetry','','[]','城南古寺舊林泉，使馭觀遊絕頂巔。',64,'全唐诗/poet.song.61000.json','["城南古寺舊林泉，使馭觀遊絕頂巔。", "幸綴華軒到清境，深慚凡骨逐真仙。", "不愁落日歸鞍促，更許新詩翠石鎸。", "猶有題名千載後，與他巴水字相連。"]'),
('44338f16-1679-452c-82a2-b86f7f38ffe5','後月餘因用前韵','楊庭傑','宋','宋诗','song-poetry','','[]','谷隠楩楠澗有泉，烟村幽曠遠□□。',64,'全唐诗/poet.song.61000.json','["谷隠楩楠澗有泉，烟村幽曠遠□□。", "□□□□□難盡，雞犬時來亦恐仙。", "危壁謾□□□□，□□□是五丁鎸。", "回歸未出深巖半，□□□□□□□。"]'),
('0a9e61ec-382e-4a47-ade9-3ad0d0cdf5a0','次韵龐茶使郫縣塔','楊天惠','宋','宋诗','song-poetry','','[]','平生閱巨麗，茲塔咤何雄。',240,'全唐诗/poet.song.61000.json','["平生閱巨麗，茲塔咤何雄。", "因地如無地，平空不礙空。", "寧從佛土徙，幾歷劫灰窮。", "落趾鷄關北，明標玉壘東。", "經營本龍象，負輓僦烟虹。", "畚築纔驅石，觚稜欻倚風。", "妙高分絕域，峻極倒中嵩。", "已幻花臺巧，並規鷲嶺嵷。", "仰窗平月殿，橫級俯蛟宮。", "未覺諸天隔，惟看一氣融。", "恒沙寸眸攝，多寡片心通。", "澒洞遺凡界，虛疏徹外幪。", "身邊揖先聖，眼外洗塵雺。", "井直參連壤，秦開漢拓功。", "真乘對時出，休運與天崇。", "締構雖人力，扶持亦化工。", "長生老西崦，諸葛死南隆。", "但了薰香灺，姑儲㲲布筒。", "狂歌留白日，醉舞屬冥鴻。", "莫漫百年事，空成一禿翁。"]'),
('9e5b26a4-2f5b-47c5-90d4-599dbad879cb','次韵吳帥題保福壁二首  其一','楊天惠','宋','宋诗','song-poetry','','[]','浄瓶猶貯近頒冰，拄杖還扶舊醉藤。',32,'全唐诗/poet.song.61000.json','["浄瓶猶貯近頒冰，拄杖還扶舊醉藤。", "遮莫簪花倩天女，未妨燕坐折談僧。"]'),
('1d43b8ef-3ebc-4d6c-867c-2ad47f2da2ad','次韵吳帥題保福壁二首  其二','楊天惠','宋','宋诗','song-poetry','','[]','由來世諦即菩提，吾道元東祖自西。',32,'全唐诗/poet.song.61000.json','["由來世諦即菩提，吾道元東祖自西。", "恰似蒼圓好頭相，可容破裂作阿梨。"]'),
('3f3fddd8-2eab-46d1-ab3d-7bdacc03301a','送孫正忠臣移成都小漕','楊天惠','宋','宋诗','song-poetry','','[]','升平芝菌效神奇，況乃賢豪用世資。',128,'全唐诗/poet.song.61000.json','["升平芝菌效神奇，況乃賢豪用世資。", "人物熙寧中興日，風流荆國適同時。", "起家便作三公客，乘傳何爲九折馳。", "少府但分新賜節，石渠猶借舊官儀。", "素心久辨經綸計，妙意前知遇合期。", "聊與西南成勝事，暫將清獻續良規。", "橋橫萬里重開府，水接雙流共去思。", "怊悵參卿無限意，道旁索筆强題詩。"]'),
('fbef2686-6aa4-4920-a96d-06eb0d6c457d','多病簡出偶成呈郫令張盤公大夫','楊天惠','宋','宋诗','song-poetry','','[]','相從一笑忘蹉跎，三過秋風錦水波。',64,'全唐诗/poet.song.61000.json','["相從一笑忘蹉跎，三過秋風錦水波。", "游子依人仰眉睫，令兄愛客費弦歌。", "思歸仙鶴方驚露，欲起病鳬還避羅。", "共感烏紗能愛老，長長遮護兩蒼皤。"]'),
('7b95adab-84d5-4794-9fba-4aa572938275','溫江縣二瑞頌','楊天惠','宋','宋诗','song-poetry','','[]','於皇御極，百志惟敘。',170,'全唐诗/poet.song.61000.json','["於皇御極，百志惟敘。", "曰農而農，曰士而士。", "爾安迺宮，爾寧迺畝。", "恩詔數下，仁滂德膴。", "農飽以歌，士喜式舞。", "協氣從之，祥嘏如雨。", "迺産嘉禾，以慶農扈。", "迺降甘露，以幸士子。", "其慶伊何，珠穗紛舉。", "俾爾甌窶，戶有億秭。", "其幸維何，雲液醲湑。", "俾爾膏馥，濡及嬰孺。", "維明明后，博臨下土。", "相彼多禾，均此靈露。", "道拜稽首，誕告奔走。", "惠拜稽首，盱衡語語。", "敢獻稗官，以贊矇瞽。"]'),
('b6d69523-6348-455b-87c4-52a7d819764e','次呂給事安昌岩避暑','楊天惠','宋','宋诗','song-poetry','','[]','懇乞魚書得梓潼，曾司紫誥駮斜封。',32,'全唐诗/poet.song.61000.json','["懇乞魚書得梓潼，曾司紫誥駮斜封。", "江山似解邀康樂，傅瑞時來訪彥龍。"]'),
('0d3fed0d-9d46-4e1a-8a20-b1e818b8373d','句  其一','楊天惠','宋','宋诗','song-poetry','','[]','清凉洞裏無蚊蚋。',8,'全唐诗/poet.song.61000.json','["清凉洞裏無蚊蚋。"]'),
('66022af4-bd75-4d57-85ec-fac6fe1e22a4','句  其二','楊天惠','宋','宋诗','song-poetry','','[]','魚蝦敢涴方池潔，蚊蚋誰禁勝地寒。',16,'全唐诗/poet.song.61000.json','["魚蝦敢涴方池潔，蚊蚋誰禁勝地寒。"]'),
('9b6561d4-67c4-4457-a77f-91ea205b98b5','句  其三','楊天惠','宋','宋诗','song-poetry','','[]','北郭雲山接巴閬，東城雪水瀉文龍。',16,'全唐诗/poet.song.61000.json','["北郭雲山接巴閬，東城雪水瀉文龍。"]'),
('2e3ae010-3455-4476-939d-6dd2d1ff7200','句  其四','楊天惠','宋','宋诗','song-poetry','','[]','道聞資水靈山高，仙人羽客時相遭。',16,'全唐诗/poet.song.61000.json','["道聞資水靈山高，仙人羽客時相遭。"]'),
('d62553c2-86fd-4547-b543-0e7a9cda052e','句','段高','宋','宋诗','song-poetry','','[]','寸心如畫筆，到處寫江山。',12,'全唐诗/poet.song.61000.json','["寸心如畫筆，到處寫江山。"]'),
('bb8468d3-548b-4ceb-991a-dd743af87be5','送程給事知越州','謝忱','宋','宋诗','song-poetry','','[]','垂髫騎竹戲江濱，束髮區區走路塵。',64,'全唐诗/poet.song.61000.json','["垂髫騎竹戲江濱，束髮區區走路塵。", "憶別稽山無去夢，樂聞鑑水欲歸人。", "棹歌停檝千詩送，帆影乘風百尺伸。", "行矣東南寄滋重，越民遠爾待頒春。"]'),
('0ea23a2a-509d-46c7-8e4f-01b730dad974','靈巖','鮮于頡','宋','宋诗','song-poetry','','[]','松門十里蒼山曲，宮殿參差倚巖腹。',112,'全唐诗/poet.song.61000.json','["松門十里蒼山曲，宮殿參差倚巖腹。", "盤盤一逕入雲中，又登絕頂最高峰。", "石壁蒼然起秋色，遠溪深處時聞鐘。", "磴道崎危達巖下，幾派清泉在澗瀉。", "月色朦朧出遠山，忽驚星斗在簷前。", "倦客遊來不知返，清光皎皎嚴霜寒。", "一出禪林復回顧，白雲已滿山頭路。"]'),
('44413dfb-0519-43e3-9bdc-41bcf8acc7df','題樓觀南樓','大中','宋','宋诗','song-poetry','','[]','紛紛塵事日嬰懷，一見南山眼暫開。',32,'全唐诗/poet.song.61000.json','["紛紛塵事日嬰懷，一見南山眼暫開。", "好是晚雲收拾盡，半天蒼翠望中來。"]'),
('db22b9c9-faf8-4e07-9579-4e8f412d5797','伏睹適公詩贊觀世音菩薩果應所懇具述於前拱不揆淺拙謹吟一章同贊聖德','黄拱','宋','宋诗','song-poetry','','[]','菩薩慈悲行願深，徧游沙界拯枯沉。',64,'全唐诗/poet.song.61000.json','["菩薩慈悲行願深，徧游沙界拯枯沉。", "衆生得度隨形化，說法開迷震梵音。", "眉現毫光同率土，手持楊柳攝羣心。", "我今稽首虔誠禮，願賜慈光與照臨。"]'),
('7fc8011e-3f6d-4382-acb2-63a2f12dba5b','還鄉偶書  其一','黄拱','宋','宋诗','song-poetry','','[]','離別家鄉歲月多，歸來人事半消磨。',32,'全唐诗/poet.song.61000.json','["離別家鄉歲月多，歸來人事半消磨。", "惟有門前鑑湖水，春風不減舊時波。"]'),
('569ef0e1-887d-4d98-b869-9634f099c8e9','還鄉偶書  其二','黄拱','宋','宋诗','song-poetry','','["\u4e8c\u5e74\u7ea7\u4e0a\u518c", "\u5510\u8bd7\u4e09\u767e\u9996", "\u4f24\u8001", "\u4e03\u8a00\u7edd\u53e5", "\u601d\u4e61", "\u611f\u6168"]','少小離家老大回，鄉音難改鬢毛衰。',32,'全唐诗/poet.song.61000.json','["少小離家老大回，鄉音難改鬢毛衰。", "兒童相見不相識，借問客從何處來。"]'),
('9a5c0863-1228-4337-b269-b5f136cfd0f3','絕句','三朵花','宋','宋诗','song-poetry','','[]','戴花三朵鎮長春，誰識玄中不二門。',32,'全唐诗/poet.song.61000.json','["戴花三朵鎮長春，誰識玄中不二門。", "醉裏自傳神似活，終當不老看乾坤。"]'),
('1b7c67e2-5ec5-4f08-85cb-0dc45a3f5a0e','靈巖十二景 置寺殿','釋仁欽','宋','宋诗','song-poetry','','[]','青蛇引路破樵徑，二虎馱經莫厭頻。',32,'全唐诗/poet.song.61000.json','["青蛇引路破樵徑，二虎馱經莫厭頻。", "周漢魏時於此住，年過八百又重新。"]'),
('27901129-a0d2-4d87-b396-2cec2d8c9779','靈巖十二景 般舟殿','釋仁欽','宋','宋诗','song-poetry','','[]','般舟古殿最先風，運載含靈不可窮。',32,'全唐诗/poet.song.61000.json','["般舟古殿最先風，運載含靈不可窮。", "生死海中波浪險，莫教沉溺失前功。"]'),
('925f1da8-50f4-47bb-b4da-c159ee9735dc','靈巖十二景 鐵袈裟','釋仁欽','宋','宋诗','song-poetry','','[]','我佛慈悲鐵作衣，誰知方便示禪機。',32,'全唐诗/poet.song.61000.json','["我佛慈悲鐵作衣，誰知方便示禪機。", "昔年庾嶺家風在，直到如今識者稀。"]'),
('9116f916-c769-4216-aeeb-3f5c1cf0037e','靈巖十二景 朗公山','釋仁欽','宋','宋诗','song-poetry','','[]','萬象森羅古此峰，傳來幾世朗公容。',32,'全唐诗/poet.song.61000.json','["萬象森羅古此峰，傳來幾世朗公容。", "知音會遇無先後，今日依前舊日蹤。"]'),
('e5b8ddf0-c245-4122-893e-0e96f1cdfa89','靈巖十二景 明孔山','釋仁欽','宋','宋诗','song-poetry','','[]','鑿開靈巖玲瓏曉，一竅圓光似月明。',32,'全唐诗/poet.song.61000.json','["鑿開靈巖玲瓏曉，一竅圓光似月明。", "照古照今傳萬代，不知誰向此安名。"]'),
('0f3c48dd-e234-4f31-90de-a4da9cbadfa9','靈巖十二景 絕景亭','釋仁欽','宋','宋诗','song-poetry','','[]','四顧林巒似列屏，一源流水響泠泠。',32,'全唐诗/poet.song.61000.json','["四顧林巒似列屏，一源流水響泠泠。", "遊人到此忘歸去，名稱虛堂絕景亭。"]'),
('78d505c0-ef05-4c14-83f4-4670fed32be9','靈巖十二景 甘露泉','釋仁欽','宋','宋诗','song-poetry','','[]','甘露香泉竟日流，有時天旱四方求。',32,'全唐诗/poet.song.61000.json','["甘露香泉竟日流，有時天旱四方求。", "隨緣赴感無偏黨，古往今來不記秋。"]'),
('ab09a960-128b-4451-9fd7-0785eaaa60cc','靈巖十二景 石龜泉','釋仁欽','宋','宋诗','song-poetry','','[]','團團特石鑿靈龜，口內噴流世莫疑。',32,'全唐诗/poet.song.61000.json','["團團特石鑿靈龜，口內噴流世莫疑。", "造化始知心所有，幾人到此亂針錐。"]'),
('03eb4585-8706-4fde-9d30-a9c068432f63','靈巖十二景 錫杖泉','釋仁欽','宋','宋诗','song-poetry','','[]','歷歷金鐶振一聲，滔滔千古迸流清。',32,'全唐诗/poet.song.61000.json','["歷歷金鐶振一聲，滔滔千古迸流清。", "香厨日用無窮竭，飲者甘和悅衆情。"]'),
('573deb6a-b644-43f9-80cd-7f7b7202d404','靈巖十二景 白鶴泉','釋仁欽','宋','宋诗','song-poetry','','[]','雲鶴雙飛去幾年，遺蹤依舊涌靈泉。',32,'全唐诗/poet.song.61000.json','["雲鶴雙飛去幾年，遺蹤依舊涌靈泉。", "澄澄皎潔無增減，石銚煎茶味更全。"]'),
('05ea83db-aee9-4ac4-980f-17d7c4d8463f','靈巖十二景 雞鳴山','釋仁欽','宋','宋诗','song-poetry','','[]','雞鳴欲曉驚行路，回首思量却再來。',32,'全唐诗/poet.song.61000.json','["雞鳴欲曉驚行路，回首思量却再來。", "兩兩三三皆省覺，一人獨上妙高臺。"]'),
('21f08ebf-7d8d-4c80-a2a3-00a17ffcc52e','靈巖十二景 證明殿','釋仁欽','宋','宋诗','song-poetry','','[]','萬丈巖前作證明，十方檀信等空平。',32,'全唐诗/poet.song.61000.json','["萬丈巖前作證明，十方檀信等空平。", "一針一草無遺漏，百劫千生果自成。"]'),
('f59192f0-d0e4-4d54-8e8a-0b1b1a62bc94','寒食飲梨花下得愁字','侯穆','宋','宋诗','song-poetry','','[]','共飲梨花下，梨花插滿頭。',48,'全唐诗/poet.song.61000.json','["共飲梨花下，梨花插滿頭。", "清香來玉樹，白蟻泛金甌。", "妝靚青蛾妬，光凝粉蝶羞。", "年年寒食夜，吟繞不勝愁。"]'),
('837fe0f6-8d2c-4ddb-9536-61a39a0d8759','句  其一','黄知微','宋','宋诗','song-poetry','','[]','溪雲拂地送殘雨，谷鳥向人啼落花。',16,'全唐诗/poet.song.61000.json','["溪雲拂地送殘雨，谷鳥向人啼落花。"]'),
('c888f1be-28bc-4f98-98d4-9191f79caee2','句  其二','黄知微','宋','宋诗','song-poetry','','[]','萬里碧雲開暮色，一條銀漢在秋天。',16,'全唐诗/poet.song.61000.json','["萬里碧雲開暮色，一條銀漢在秋天。"]'),
('f1cfa1ba-15f5-4ea5-bf81-d69866b41b28','贈縣令','建陽舉子','宋','宋诗','song-poetry','','[]','寒儒登第十三年，衝替歸來賣盡田。',32,'全唐诗/poet.song.61000.json','["寒儒登第十三年，衝替歸來賣盡田。", "除却職田清俸外，不知何處遇神仙。"]'),
('7214a030-dfc4-4675-bb6c-bb8374178e0a','和李巨川清風樓','呂當','宋','宋诗','song-poetry','','[]','祁陽要郡冠邊州，池壘深高北控幽。',64,'全唐诗/poet.song.61000.json','["祁陽要郡冠邊州，池壘深高北控幽。", "欹岸綠楊浮水面，銜山紅日照簷頭。", "立功慷慨思投筆，鬻己卑污耻飯牛。", "獨使燕然銘漢德，百年忠憤遣人愁。"]'),
('c7235be5-975a-426a-b9a0-e3c97c862b3f','和華安仁花村二首  其一','趙逢','宋','宋诗','song-poetry','','[]','格是而今老有餘，行行真欠瘦筇扶。',32,'全唐诗/poet.song.61000.json','["格是而今老有餘，行行真欠瘦筇扶。", "不將心絮隨風起，一恁閑花有似無。"]'),
('5839e172-d022-4311-a0cc-6f9fbe236275','和華安仁花村二首  其二','趙逢','宋','宋诗','song-poetry','','[]','路入前村認杏花，門前水積半溪沙。',32,'全唐诗/poet.song.61000.json','["路入前村認杏花，門前水積半溪沙。", "風流彷彿朱陳俗，白酒黄雞姓兩家。"]'),
('854f515d-cc98-46a6-85ef-1759c2b6bf41','句','石太傅','宋','宋诗','song-poetry','','[]','芝蘭相照皆佳士。',8,'全唐诗/poet.song.61000.json','["芝蘭相照皆佳士。"]'),
('6343276a-561b-4d5a-a6ba-fe18e3dab169','雪霽月明獨步梅花下','麴貞','宋','宋诗','song-poetry','','[]','雪晴月白梅花芬，朗行恍在瓊瑶京。',96,'全唐诗/poet.song.61000.json','["雪晴月白梅花芬，朗行恍在瓊瑶京。", "光搖燦燦玉宇浄，香浮靄靄銀河明。", "乾坤元氣正澄澈，林巒景色何晶熒。", "風神顧我精爽逼，襟懷頓覺塵囂清。", "憑高忽爾發長嘯，千山響振鸞鳳鳴。", "夜深一望五湖白，何當跨鶴遊蓬瀛。"]'),
('3decae9d-84f7-46c1-8162-36f3ac16e5bd','歲暮篇寄無礙居士','麴貞','宋','宋诗','song-poetry','','[]','羲和不停馭，年華迅轉轂。',179,'全唐诗/poet.song.61000.json','["羲和不停馭，年華迅轉轂。", "春陽萬卉菲，忽驚遂凄肅。", "人生那得壽盈百，轉眼光陰如過客。", "夙齡壯志日蹉跎，黑鬒蕭蕭又云晳。", "年來年去機中梭，去日苦多其奈何。", "君不見古來神智稱姜公，賣漿屠肆成奇窮。", "岐周王氣時不發，渭濱槁死終漁翁。", "人生代謝如四序，陵陽松喬在何許。", "功名富貴一浮塵，濩落饑寒向誰語。", "向誰語，爲君言，寒氣凜冽陽和旋，得失不羈大化全。", "樽前有酒同偓佺，明朝且笑雲山巔。"]'),
('1c68465c-456a-44e0-946f-08c67046cd32','句','余卞','宋','宋诗','song-poetry','','[]','君山一點青螺髻，知是滄溟第幾洲。',16,'全唐诗/poet.song.61000.json','["君山一點青螺髻，知是滄溟第幾洲。"]'),
('4911bf3f-94b8-43cb-b916-619ca8c39c8d','石橋  其一','余爽','宋','宋诗','song-poetry','','[]','雲藏鐘鼓霧埋林，龍護山花雀散金。',32,'全唐诗/poet.song.61000.json','["雲藏鐘鼓霧埋林，龍護山花雀散金。", "知道有人橋外住，青崖遮斷不教尋。"]'),
('93c870ec-513d-48be-9020-1ca98037df64','石橋  其二','余爽','宋','宋诗','song-poetry','','[]','蒼崖清澗竹嬋娟，紫閣丹樓磴道連。',32,'全唐诗/poet.song.61000.json','["蒼崖清澗竹嬋娟，紫閣丹樓磴道連。", "我是夢中曾到此，故將香火記他年。"]'),
('7646c5ca-7288-4c24-96b7-6e0285d6f177','桐柏崇道觀','余爽','宋','宋诗','song-poetry','','[]','乘風御雲氣，來訪真人家。',264,'全唐诗/poet.song.61000.json','["乘風御雲氣，來訪真人家。", "玉闕散朝景，瓊臺煥晨霞。", "高臨太元天，下眄赤水涯。", "陰魄位霜采，陽精發丹華。", "桐君奉玄書，姥女弄絳紗。", "祥虹混五色，神芝秀三葩。", "煌煌王母居，飄飄紫皇車。", "飆輪動無跡，風馬去亦賒。", "矯首揖浮丘，躡屐追皇媧。", "珠宮俯台斗，石梁礙流槎。", "操持却日鞭，跨踏食月蛙。", "龍旗拂烟霧，鶴袂策雲斜。", "清都隠虛無，金庭鬰嵯峨。", "橫霄雜美氣，空界流浩波。", "囊籥勞吹噓，吐納煩羲和。", "倏爾度灰劫，超然絕塵羅。", "靈簫步何徐，玉斧鬢已皤。", "飛駕逐鳳吹，斑驎奏鸞歌。", "甯留飯青精，幸我栽胡麻。", "交梨瑩肝膽，火棗醒齒牙。", "咽潄華池津，咀嚼碧柰花。", "有待越三井，思慮無由邪。"]'),
('15315a27-2a4e-4129-8edc-b97ca8937be9','玉京洞  其一','余爽','宋','宋诗','song-poetry','','[]','羽駕歸來洞已扃，洞門深鎖讀殘經。',32,'全唐诗/poet.song.61000.json','["羽駕歸來洞已扃，洞門深鎖讀殘經。", "瓊臺一覺仙都夢，不覺松根長茯苓。"]'),
('297f22f7-c016-4a82-a575-d7b52d6afc11','玉京洞  其二','余爽','宋','宋诗','song-poetry','','[]','東臨滄海宴羣仙，誤入桃源小洞天。',32,'全唐诗/poet.song.61000.json','["東臨滄海宴羣仙，誤入桃源小洞天。", "一局殘棋銷幾刻，老龍鱗甲已蒼然。"]'),
('200bae4b-05b9-4a69-8dbe-13981f2172a1','玉京洞  其三','余爽','宋','宋诗','song-poetry','','[]','半山松柏散天聲，芝蓋當年憩赤城。',32,'全唐诗/poet.song.61000.json','["半山松柏散天聲，芝蓋當年憩赤城。", "我是上皇芸閣吏，玉京應有舊題名。"]'),
('ad41304a-8d09-4dc4-bb9b-96c3794d18d4','福聖觀  其一','余爽','宋','宋诗','song-poetry','','[]','九峰回合抱瓊田，石蘂雲英潄瀑泉。',32,'全唐诗/poet.song.61000.json','["九峰回合抱瓊田，石蘂雲英潄瀑泉。", "聞說丹成從此路，玉虹芝駕上青天。"]'),
('6e9f6d7e-4079-4eaa-9c21-5d5d918ebe20','福聖觀  其二','余爽','宋','宋诗','song-poetry','','[]','紫府金庭太帝宮，露壇蒼檜響天風。',32,'全唐诗/poet.song.61000.json','["紫府金庭太帝宮，露壇蒼檜響天風。", "上清神虎何年見，雲錦空傳兩玉童。"]'),
('161c4ae0-1c13-4dc0-bce9-4c8aed3c1023','福聖觀  其三','余爽','宋','宋诗','song-poetry','','[]','子晉鸞飛侍帝班，吹臺今在碧雲閒。',32,'全唐诗/poet.song.61000.json','["子晉鸞飛侍帝班，吹臺今在碧雲閒。", "高秋白月霜風夜，時有笙簫赴洛還。"]'),
('20c8e4a3-c413-48c2-9ffe-60caaabe0922','秋雨歎','許彥國','宋','宋诗','song-poetry','','[]','霖雨不出動隔旬，門前秋草長於人。',64,'全唐诗/poet.song.61000.json','["霖雨不出動隔旬，門前秋草長於人。", "江湖浩渺欲無岸，錦石最小猶生雲。", "微陽片月何曾見，只有莓苔昏筆硯。", "田家黍穗未暇悲，茅屋且爲螢火飛。"]'),
('e6878179-5efc-4870-b9a2-106dc5f7a26c','紫騮馬','許彥國','宋','宋诗','song-poetry','','[]','黄金絡頭玉爲觼，蜀錦障泥亂雲葉。',67,'全唐诗/poet.song.61000.json','["黄金絡頭玉爲觼，蜀錦障泥亂雲葉。", "花間顧影驕不行，萬里龍駒空汗血。", "露床秋粟飽不食，青芻苜蓿無顔色。", "君不見東郊瘦馬百戰場，天寒日暮烏啄瘡。"]'),
('6777df2f-9aa2-4f71-8fa8-90d5277d6688','虞美人草行','許彥國','宋','宋诗','song-poetry','','[]','鴻門玉斗紛如雪，十萬降兵夜流血。',160,'全唐诗/poet.song.61000.json','["鴻門玉斗紛如雪，十萬降兵夜流血。", "咸陽宮殿三月紅，霸業已隨烟燼滅。", "剛强必死仁義王，陰陵失道非天亡。", "英雄本學萬人敵，何須屑屑悲紅妝。", "三軍敗盡旌旗倒，玉帳佳人坐中老。", "香魂夜逐劍光飛，清血化爲原上草。", "芳心寂寞寄寒枝，舊曲聞來似斂眉。", "哀怨徘徊愁不語，恰如初聽楚歌時。", "滔滔逝水流今古，楚漢興亡兩丘土。", "當年遺事總成空，慷慨尊前爲誰舞。"]'),
('f19e14f1-fd59-4f30-b525-82dc98cad965','東門行','許彥國','宋','宋诗','song-poetry','','[]','東門楊柳暗藏鴉，東門行客欲離家。',96,'全唐诗/poet.song.61000.json','["東門楊柳暗藏鴉，東門行客欲離家。", "樹頭春風草頭露，鴉自不飛人自去。", "妾家南浦桂爲堂，房櫳珉玉簾夜光。", "沈爐烟多綺羅重，水檻風入笙簫凉。", "歡娛未畢車輪遠，方寸秋絲紛百繭。", "願郎功業落人閒，長使春閨女無怨。"]'),
('ac8626b1-b336-491a-9bc9-ce00bd820ab6','采蓮吟','許彥國','宋','宋诗','song-poetry','','[]','湖邊日落鴛鴦飛，羅衣香轉蘭舟移，蓮根斷處手滿絲。',40,'全唐诗/poet.song.61000.json','["湖邊日落鴛鴦飛，羅衣香轉蘭舟移，蓮根斷處手滿絲。", "手滿絲，不能理，秋雲深，隔君子。"]'),
('cf4f1b97-cfa0-4147-b935-39c1eeeafb82','臨高臺','許彥國','宋','宋诗','song-poetry','','[]','高臺跨崇岡，簷宇鎖空霧。',72,'全唐诗/poet.song.61000.json','["高臺跨崇岡，簷宇鎖空霧。", "新晴洗雙目，千里在跬步。", "霏霏漁浦烟，冉冉富春樹。", "風花不我私，何以理愁緒。", "誰疏白玉窗，中有浮雲度。", "浮雲吹不開，不見行人去。"]'),
('de3b9ecf-ca24-4c21-a7b5-e17e08deff94','漁父','許彥國','宋','宋诗','song-poetry','','[]','榮辱從來總不知，幾間茅屋對漁磯。',32,'全唐诗/poet.song.61000.json','["榮辱從來總不知，幾間茅屋對漁磯。", "江鷗散處夜無伴，荷葉老時秋有衣。"]'),
('3c92ddb0-7417-4866-8044-5837c004f1d4','晚宿江漲橋','許彥國','宋','宋诗','song-poetry','','[]','鳥徑青山外，人家苦竹邊。',48,'全唐诗/poet.song.61000.json','["鳥徑青山外，人家苦竹邊。", "江城懸夜鎖，魚市散空船。", "岸靜涵秋月，林昏宿水烟。", "又尋僧榻卧，夜冷欲無眠。"]'),
('f257ae5c-f70c-489a-9927-79b85e90fc1e','長夜吟','許彥國','宋','宋诗','song-poetry','','[]','南鄰燈火冷，三起愁夜永。',40,'全唐诗/poet.song.61000.json','["南鄰燈火冷，三起愁夜永。", "北鄰歌未終，已驚初日紅。", "不知晝夜誰主管，一種春宵有長短。"]'),
('be5f62d0-4085-483e-812b-ec9d9f7bf471','寄沂水宰','許彥國','宋','宋诗','song-poetry','','[]','楚甸齊封自此分，穆陵遺俗久猶存。',64,'全唐诗/poet.song.61000.json','["楚甸齊封自此分，穆陵遺俗久猶存。", "豈知今日鳴琴宰，即是當年賜履孫。", "且有清風消酷暑，更無驚犬吠黄昏。", "畏人客子成安枕，獨宿荒村不閉門。"]'),
('1cb39958-8b79-4b2b-95e4-7ff35f818e34','詠項籍廟二首  其一','許彥國','宋','宋诗','song-poetry','','[]','曾被秦人笑沐猴，錦衣東去更何求。',32,'全唐诗/poet.song.61000.json','["曾被秦人笑沐猴，錦衣東去更何求。", "可憐瞭瞭重瞳子，不見山河繞雍州。"]'),
('6f52c28d-a843-4131-b2c5-f606cd0dbfb7','詠項籍廟二首  其二','許彥國','宋','宋诗','song-poetry','','[]','千古興亡莫浪愁，漢家功業亦荒丘。',32,'全唐诗/poet.song.61000.json','["千古興亡莫浪愁，漢家功業亦荒丘。", "空餘原上虞姬草，舞盡春風未肯休。"]'),
('3747af9e-1baa-4e40-b187-8faf8cda7d75','句  其一','許彥國','宋','宋诗','song-poetry','','[]','白鳥有情驚不去，青山無約望還來。',16,'全唐诗/poet.song.61000.json','["白鳥有情驚不去，青山無約望還來。"]'),
('7d063b9e-5bb5-415e-abf3-0d2c8722b577','句  其二','許彥國','宋','宋诗','song-poetry','','[]','午夜夢飛滄海外，一年春在落花中。',16,'全唐诗/poet.song.61000.json','["午夜夢飛滄海外，一年春在落花中。"]'),
('c80bff9c-cc45-4994-82bb-bbbd18812597','句  其三','許彥國','宋','宋诗','song-poetry','','[]','北方野客不慣見，明月滿衣猶倚欄。',16,'全唐诗/poet.song.61000.json','["北方野客不慣見，明月滿衣猶倚欄。"]'),
('98c462af-11e7-4783-9c28-f0f498fff26b','句  其四','許彥國','宋','宋诗','song-poetry','','[]','燕薊餘民宜自省，百年陷虜直愁人。',24,'全唐诗/poet.song.61000.json','["燕薊餘民宜自省，百年陷虜直愁人。", "勿怨肩輿事洪靖。"]'),
('c2aabb46-2adb-445c-ba7c-0602dcac9bf5','句  其五','許彥國','宋','宋诗','song-poetry','','[]','蹉跎已甘分。',6,'全唐诗/poet.song.61000.json','["蹉跎已甘分。"]'),
('73d6e501-a217-4136-b63b-d6c9e2811451','題紫霄觀','王嚮','宋','宋诗','song-poetry','','[]','薜蘿縈拂道巘斜，高入層霄殘紫霞。',64,'全唐诗/poet.song.61000.json','["薜蘿縈拂道巘斜，高入層霄殘紫霞。", "地長杉篁環羽蓋，風兼簫鼓落仙家。", "危峰自照當巖月，絕壁堪通上漢槎。", "人世不知真跡好，只尋流水訪殘花。"]'),
('c2dabc60-7677-4cae-af1d-294d8e4528ad','雜詩  其一','李復','宋','宋诗','song-poetry','','[]','猗蘭生幽林，秀葉凝綠滋。',72,'全唐诗/poet.song.61000.json','["猗蘭生幽林，秀葉凝綠滋。", "含芬靜不發，默與清風期。", "美人閑婉孌，遺世從雲螭。", "袖中雙珠明，照人冰玉姿。", "羣動溺憂患，閟光無同嘻。", "寂寥歲將晚，獨往歌紫芝。"]'),
('41131e03-d0c1-4704-bdc5-39876429911d','雜詩  其二','李復','宋','宋诗','song-poetry','','[]','應龍出重淵，矯矯昇天行。',96,'全唐诗/poet.song.61000.json','["應龍出重淵，矯矯昇天行。", "奮迅彌宇宙，雨施品物形。", "收藏入無間，脗合元氣冥。", "神變不可測，乃知至陽精。", "聖人鍊陰魄，調御元功成。", "乘時萬類睹，廓然日月明。", "體用符龍變，潜躍惟時亨。", "顔伏德方求，舜見位已升。"]'),
('a666d080-4a10-4771-83e7-2e37ee5ec1d9','雜詩  其三','李復','宋','宋诗','song-poetry','','[]','霜葉下高枝，紛紛擁寒根。',96,'全唐诗/poet.song.61000.json','["霜葉下高枝，紛紛擁寒根。", "驚風度虛庭，槭槭愁飛翻。", "草木雖無知，養本亦足論。", "人生感元化，道貴窮性原。", "滋口芬羶亂，悅耳聲音繁。", "衆攻日外戰，目暗天地昏。", "不問昆侖清，但愛長波渾。", "神馳正氣潰，白日鬼瞰門。"]'),
('e225b897-2c73-4518-801a-57fa308c4c3f','雜詩  其四','李復','宋','宋诗','song-poetry','','[]','春鳩啄晴屋，露蟬吟高枝。',48,'全唐诗/poet.song.61000.json','["春鳩啄晴屋，露蟬吟高枝。", "羣物感氣動，飛鳴不自知。", "冥心觀物化，浩劫密推移。", "欲從扶桑翁，雲間玩陽曦。"]'),
('3605d067-1c5b-4f56-ad64-8f27b2e61924','雜詩  其五','李復','宋','宋诗','song-poetry','','[]','珍圖出榮河，八卦開奧秘。',144,'全唐诗/poet.song.61000.json','["珍圖出榮河，八卦開奧秘。", "聖人重因襲，已極露隠細。", "大衍四十九，周流通一氣。", "陰陽窮必變，往反無終始。", "元化密推移，消長先默契。", "鬼神無遁情，垂詔億萬世。", "如何揚子雲，求名誇譎詭。", "藻繪太初歷，設畫隨啟閉。", "盈縮無常運，踦贏謾擬議。", "安得宇宙間，別更有天地。", "文字但艱苦，白首困心志。", "侯芭何所知，枝指徒爲贅。"]'),
('0200aa23-e81f-45e8-9894-54f6d07863bd','雜詩  其六','李復','宋','宋诗','song-poetry','','[]','陽剛形發輝，陰凝體受照。',48,'全唐诗/poet.song.61000.json','["陽剛形發輝，陰凝體受照。", "金魄遡火烏，進退見朒朓。", "氣引潮海壯，象推介蟲小。", "南北應坎離，東西正昏曉。"]'),
('73945431-74df-46cb-bdf8-4cc4a2f5a5d6','雜詩  其七','李復','宋','宋诗','song-poetry','','[]','萬物忘我難，聖人出同憂。',96,'全唐诗/poet.song.61000.json','["萬物忘我難，聖人出同憂。", "女媧斷鼇足，軒轅殛蚩尤。", "禹命洪水乂，稷播百穀修。", "元德與天通，珍符告帝休。", "起皆不得已，本非功業謀。", "應龍潜深淵，睢盱寒水秋。", "乘時御風雷，雨施化形流。", "體異靈氣同，默契神變求。"]'),
('7157a799-808b-4ce3-90cf-ac368a608e0c','雜詩  其八','李復','宋','宋诗','song-poetry','','[]','陰陽體合氣，氛氳極無際。',108,'全唐诗/poet.song.61000.json','["陰陽體合氣，氛氳極無際。", "卦氣交孕毓，旁滋六爻備。", "聖人繫爻辭，鈎賾推母子。", "觀應以知來，隨方推象類。", "靈龜通火志，黄牛革得地。", "復應乾龍潜，兌乘履虎尾。", "周流紛參錯，往來精妙義。", "懵懵妄穿鑿，執一千百廢。", "孰能訪太極，與遊兩儀外。"]'),
('e29e2e32-643e-4faa-babe-ac1d0043585f','雜詩  其九','李復','宋','宋诗','song-poetry','','[]','衆輻共一轂，利用本在無。',48,'全唐诗/poet.song.61000.json','["衆輻共一轂，利用本在無。", "制法應世變，欲返民心愚。", "巧智起頹波，但逐末流趨。", "鳥亂畢弋多，真風日更疏。"]'),
('7e4ca741-385b-4cd6-aa6f-de1596bbf314','雜詩  其一○','李復','宋','宋诗','song-poetry','','[]','一氣偶暫聚，靈府含虛明。',48,'全唐诗/poet.song.61000.json','["一氣偶暫聚，靈府含虛明。", "至人遺世氛，妙靜無將迎。", "索珠迷罔象，鼓琴有虧成。", "淼淼千海波，全潮浮漚輕。"]'),
('ddd6d1db-af58-4658-bb91-e1151759b5ce','雜詩  其一一','李復','宋','宋诗','song-poetry','','[]','杯水入滄溟，浩浩通無際。',60,'全唐诗/poet.song.61000.json','["杯水入滄溟，浩浩通無際。", "原心方寸間，混合周天地。", "后稷勤稼穡，顔淵甘簞食。", "行己在一時，流芳播萬世。", "至道不遠人，安行近且易。"]'),
('a1f7776c-1148-41f3-b16a-e50e4caa3569','雜詩  其一二','李復','宋','宋诗','song-poetry','','[]','高松懷正氣，挺特入空碧。',96,'全唐诗/poet.song.61000.json','["高松懷正氣，挺特入空碧。", "短棘無直枝，千鉤未成尺。", "松生倚雲岡，棘散傍道側。", "道側侵行人，牽衣去不得。", "絲蔓亂附託，狐貍喜偃息。", "美惡類相感，庸詎分知識。", "秋風葉落時，礙眼如矛戟。", "斤斧不得施，悵然空歎息。"]'),
('433280fd-296b-4790-90d2-3e663e59eb48','雜詩  其一三','李復','宋','宋诗','song-poetry','','[]','翩翩雲間鳥，翠羽光葳蕤。',84,'全唐诗/poet.song.61000.json','["翩翩雲間鳥，翠羽光葳蕤。", "結巢占遠林，意與深靜期。", "盲飈忽號怒，萬木無停枝。", "欹搖不容息，簸蕩孤巢危。", "遐睇崑崙岡，玉樹蔚仙姿。", "溟海皆震蕩，秀立影不移。", "空懷高舉心，感歎鼓翼遲。"]'),
('367ddd94-798f-4462-bf4a-322f5246e012','雜詩  其一四','李復','宋','宋诗','song-poetry','','[]','晨炊未登盤，饑腸已戚戚。',96,'全唐诗/poet.song.61000.json','["晨炊未登盤，饑腸已戚戚。", "欲問堂上人，先聞發歎息。", "苟念一餉饑，况艱終歲食。", "茫茫九州間，幾人悲罄室。", "吾欲呼天工，驅雷駕雲龍。", "十日一風雨，五穀年常豐。", "佩刀化爲農，孫哺百歲翁。", "完助陰陽功，不顧吾盤空。"]'),
('8f8e0f44-4699-43f9-a1ad-4922650d3d89','雜詩  其一五','李復','宋','宋诗','song-poetry','','[]','沙虛路傍泉，江通石上井。',48,'全唐诗/poet.song.61000.json','["沙虛路傍泉，江通石上井。", "泉挹淺沙黄，井汲深江冷。", "六月火雲生，旱烏炎午影。", "煩心欲清滌，呼兒問修綆。"]'),
('5f03be2f-83f0-4e6b-87de-348291570b54','雜詩  其一六','李復','宋','宋诗','song-poetry','','[]','黄河走東溟，不知幾萬里。',144,'全唐诗/poet.song.61000.json','["黄河走東溟，不知幾萬里。", "奔騰鼓風雷，勢欲卷厚地。", "百川隨呼吸，渾渾失氣類。", "正德不可亂，橫絕見清濟。", "詭士富縱橫，機辯回天地。", "觀其投說時，揣摩探人意。", "高論未能窺，茫然何所試。", "彷彿一隙開，洶湧驚濤起。", "陰闔拒其惡，陽開示其喜。", "危冠揖時君，擔簦擅國勢。", "六印黄金多，雙璧連城貴。", "歲晚客子來，傾變心若死。"]'),
('8bef695b-30f0-4137-8974-c86a1b971672','雜詩  其一七','李復','宋','宋诗','song-poetry','','[]','權利爲禍根，苟合非純士。',108,'全唐诗/poet.song.61000.json','["權利爲禍根，苟合非純士。", "嗟哉憑軾生，行見烹齊市。", "晴鳩不逐婦，猛虎不食子。", "魏國將樂羊，齊人疑吳起。", "凶險甚鳥獸，妻子自烹死。", "嗚呼天壤間，親無骨肉比。", "殘毒就功名，于君安可恃。", "中山昔置相，嘗取放麑翁。", "異類猶有恩，事君必致忠。"]'),
('ff154ae7-cdf2-4893-971b-8312010ae6b6','雜詩  其一八','李復','宋','宋诗','song-poetry','','[]','經界廢已久，王者無尺土。',48,'全唐诗/poet.song.61000.json','["經界廢已久，王者無尺土。", "强力喜饕吞，含血不肯吐。", "孱弱困道傍，性命輕毫縷。", "爲政須務本，析薪何匪斧。"]'),
('f90e4a85-c71b-433d-be34-dcd20c18a60d','雜詩  其一九','李復','宋','宋诗','song-poetry','','[]','浚泉少汲水，汲多泉水汙。',48,'全唐诗/poet.song.61000.json','["浚泉少汲水，汲多泉水汙。", "力穡莫揠苗，揠苗苗必枯。", "心清事自簡，氣和體必舒。", "古人有至言，治民如烹魚。"]'),
('c068ced9-4fca-4475-9cbd-fe7d27a80bb6','雜詩  其二○','李復','宋','宋诗','song-poetry','','[]','先王急民事，分吏察壠畝。',48,'全唐诗/poet.song.61000.json','["先王急民事，分吏察壠畝。", "田荒宅無毛，置法責粟布。", "壤壤一歲勤，暴暴三年聚。", "農政久不修，幾家有禾黍。"]'),
('e9e9e357-5af9-46fd-b0c6-f0274c3cb3a9','雜詩  其二一','李復','宋','宋诗','song-poetry','','[]','當路莫張機，張機不可行。',48,'全唐诗/poet.song.61000.json','["當路莫張機，張機不可行。", "潜深巢高杪，魚鳥知愛生。", "立義禁爲非，意欲求無刑。", "刻核苟太至，視死心亦輕。"]'),
('f05c9bf1-3a8e-49a5-b663-8b03ded21655','雜詩  其二二','李復','宋','宋诗','song-poetry','','[]','善學必探本，知本貴善養。',48,'全唐诗/poet.song.61000.json','["善學必探本，知本貴善養。", "種木既得地，柯葉日滋長。", "紛紛綺語工，汩汩良心喪。", "多聞竟無益，不如雞犬放。"]'),
('8d6cf965-7b98-4809-ae89-cc2448a6177a','雜詩  其二三','李復','宋','宋诗','song-poetry','','[]','姬旦相孺子，不爲召公知。',48,'全唐诗/poet.song.61000.json','["姬旦相孺子，不爲召公知。", "洛陽賈年少，豈免絳灌疑。", "論遠必爲迂，舉高遂有危。", "更無反禾風，但起弔湘悲。"]'),
('f041601d-828e-48df-b6bd-8021e8c8bf8a','讀陶淵明詩','李復','宋','宋诗','song-poetry','','[]','淵明才力高，詩語最蕭散。',108,'全唐诗/poet.song.61000.json','["淵明才力高，詩語最蕭散。", "矯首捐末事，闊步探幽遠。", "初若不相屬，再味意方見。", "曠然閑寂中，奇趣高蹇嵼。", "衆辭肆滂葩，姦怪露舒慘。", "彫刻雖云工，真風在平澹。", "距今幾百年，有作皆媿赧。", "予嘗跂清塵，忽忽氣相感。", "安得起從遊，絕頂與同覽。"]'),
('4f7062ed-819f-4c17-9ca0-fb7ed1f4a48d','明月入我牖','李復','宋','宋诗','song-poetry','','[]','明月入我牖，娟娟滿衣裳。',96,'全唐诗/poet.song.61000.json','["明月入我牖，娟娟滿衣裳。", "驚風飄疏竹，凌亂舞清光。", "靜坐不能眠，稍知秋夜長。", "却思古人書，探編開縹囊。", "一讀三四反，人遠心茫茫。", "投編出庭宇，回步影徜徉。", "長空散白露，暗落點青黄。", "肅肅晨氣動，滿地自爲霜。"]'),
('b9b077de-63b8-4875-8a8b-cf872a6b97b7','山中有桂樹題得綠字','李復','宋','宋诗','song-poetry','','[]','山中有桂樹，樛虬散巖曲。',72,'全唐诗/poet.song.61000.json','["山中有桂樹，樛虬散巖曲。", "高枝動秋風，霜凝不改綠。", "美人與世遠，嘯歌樂幽獨。", "揮手弄浮雲，寒光滿空谷。", "忽忽自搔首，神馳逐清躅。", "何時山下泉，一濯飛塵足。"]'),
('3a2f2b21-520f-4197-a857-85c3a3460801','和人子夜四時歌  其一','李復','宋','宋诗','song-poetry','','[]','井上梧桐樹，花黄落點衣。',36,'全唐诗/poet.song.61000.json','["井上梧桐樹，花黄落點衣。", "夜深花裏鳥，相並不相離。", "美人朝汲水，驚起却雙飛。"]'),
('962d8963-0d85-4ab8-a06c-2c153295a0d0','和人子夜四時歌  其二','李復','宋','宋诗','song-poetry','','[]','繰絲絲縷長，當窗織流黄。',36,'全唐诗/poet.song.61000.json','["繰絲絲縷長，當窗織流黄。", "纖纖弄龍杼，不作舞衣裳。", "裁縫付邊使，豈待見秋霜。"]'),
('a7b1dc62-b1b1-4dbf-9644-8b412c629db4','和人子夜四時歌  其三','李復','宋','宋诗','song-poetry','','[]','蕭蕭庭下柳，曾學舞腰支。',36,'全唐诗/poet.song.61000.json','["蕭蕭庭下柳，曾學舞腰支。", "秋風吹暮夜，半落小蛾眉。", "人生自無定，空歎葉辭枝。"]'),
('40589975-3d41-42cc-8cde-1df1bd1dd965','和人子夜四時歌  其四','李復','宋','宋诗','song-poetry','','[]','窈窕月華來，對月理瑶箏。',36,'全唐诗/poet.song.61000.json','["窈窕月華來，對月理瑶箏。", "將心託絃語，幾弄未成聲。", "非關霜氣澀，不忍苦分明。"]'),
('d5bfb14c-828e-4ab5-b82e-d8ce9a4840ec','有客山中來','李復','宋','宋诗','song-poetry','','[]','有客山中來，遺我雙雲松。',96,'全唐诗/poet.song.61000.json','["有客山中來，遺我雙雲松。", "身雖咫尺長，勢有百丈容。", "空庭土花碧，不種夭桃紅。", "春悲香魄盡，秋怨綠枝空。", "喜見石上根，移從最高峰。", "愛植朝暮勤，待看凌霜風。", "何時舊山雲，出隨淵中龍。", "沛然灑好雨，助我栽培功。"]'),
('671e8a3c-eee4-4724-8007-30a400b43b54','翠碧','李復','宋','宋诗','song-poetry','','[]','翠碧曳長啼，翩然上庭樹。',96,'全唐诗/poet.song.61000.json','["翠碧曳長啼，翩然上庭樹。", "花枝搖未定，驚顧却飛去。", "豈不愛芳陰，自憐好毛羽。", "苦爲艷粧求，刻鏤點金素。", "五陵遊俠兒，挾彈馳長路。", "華狨毛垂金，豐豹文濯霧。", "懷珠蚌必剖，戴角犀多忤。", "志士無懷璧，懷璧出逢怒。"]'),
('72dbf276-7805-437b-8fe9-cac81ea09eaf','病目','李復','宋','宋诗','song-poetry','','[]','昔年勤細書，廣博求多益。',192,'全唐诗/poet.song.61000.json','["昔年勤細書，廣博求多益。", "謂經手一抄，可勝讀數百。", "矻矻三十年，嘗廢寢與食。", "磨墨見硯穿，敗筆如丘積。", "高編連大軸，不知幾萬億。", "當時氣血盛，未覺損目力。", "今年四十六，百病乘其隙。", "雙瞳舊勞甚，凝血聚成脈。", "虛炎更上攻，常若包芒棘。", "遠視但䨥䨥，浮空亂花黑。", "少功跂前修，鑽仰極窺測。", "志欲繼絕學，九萬希鵬翼。", "求於形器外，脫然有所得。", "上友千古魂，神遇展良覿。", "年來老且病，筋骸當少息。", "六物已熬成，昏氣須清滌。"]'),
('56c47458-1a4d-4cd7-94f8-6385dd53a226','物我','李復','宋','宋诗','song-poetry','','[]','萬物生芸芸，與我本同氣。',48,'全唐诗/poet.song.61000.json','["萬物生芸芸，與我本同氣。", "氤氳隨所感，形體偶然異。", "丘嶽孰爲高，塵粒孰爲細。", "忘物亦忘我，優游何所覬。"]'),
('44252a6e-6cf3-4947-82bb-e9ec3d3c682c','自省','李復','宋','宋诗','song-poetry','','[]','理容本求妍，造次遽成醜。',48,'全唐诗/poet.song.61000.json','["理容本求妍，造次遽成醜。", "兢兢早夜思，猶或失於偶。", "放而不知察，美種雜稂莠。", "吾居日三省，參也吾所友。"]'),
('c05e4323-b72a-4646-ad85-c3bae70107be','自訟','李復','宋','宋诗','song-poetry','','[]','前善後隨非，失於任私意。',48,'全唐诗/poet.song.61000.json','["前善後隨非，失於任私意。", "短長莫可欺，明者未免蔽。", "改過心每憚，責人夫何易。", "芸苗捨己田，無獲亦蹈厲。"]'),
('9c1e75cd-38e5-44ba-8152-84f6c8e7be04','自暴','李復','宋','宋诗','song-poetry','','[]','交際知其心，莫良占辭氣。',48,'全唐诗/poet.song.61000.json','["交際知其心，莫良占辭氣。", "聲音施施然，已拒弗肯至。", "忿戾無少容，安能喻美意。", "人懼有失言，恝爾絕于世。"]'),
('2187fcb6-3c0c-40f3-8df6-942557e8084e','白日','李復','宋','宋诗','song-poetry','','[]','白日懸虛空，春秋變寒暄。',48,'全唐诗/poet.song.61000.json','["白日懸虛空，春秋變寒暄。", "但流地上影，不照地下魂。", "慘慘暗陋巷，炎炎曜蓽門。", "浮生蕩無根，萬古悲黄昏。"]'),
('da5956fd-9ff9-4127-9a89-4c4a4198f945','感春  其一','李復','宋','宋诗','song-poetry','','[]','新槐未成陰，藤花如紫雲。',48,'全唐诗/poet.song.61000.json','["新槐未成陰，藤花如紫雲。", "蒙羃出高杪，花葉不可分。", "雙鳩接翼飛，搖蕩花紛紛。", "曦車不肯留，感嘆愁夕曛。"]'),
('59b06faf-1629-4699-b2c4-41a8b8ca7758','感春  其二','李復','宋','宋诗','song-poetry','','[]','三月無餘旬，此日足可惜。',84,'全唐诗/poet.song.61000.json','["三月無餘旬，此日足可惜。", "桃李不自由，相期偶相失。", "黄黄蕪菁花，青青陵陂麥。", "林間晚蝶飛，翩翩竟何益。", "前晨遊百花，夭艷鬭顔色。", "柳枝弱而細，閑垂亦自得。", "今日偶再來，羣枝空寂寂。"]'),
('96567bc3-c0b3-4838-8bb3-2b5f1f9ab18a','感春  其三','李復','宋','宋诗','song-poetry','','[]','桐花開最晚，香泛已羃羃。',72,'全唐诗/poet.song.61000.json','["桐花開最晚，香泛已羃羃。", "高榆散枯錢，狼藉走荒陌。", "聞歌情亦倦，對酒意不懌。", "非傷春遽回，第覺老相逼。", "願訴東皇君，撫轡留歸迹。", "百年雖無多，亦稍緩偪側。"]'),
('f6814634-7f8f-4116-90bc-29c83cbb8828','早起','李復','宋','宋诗','song-poetry','','[]','羣鳩啄屋鳴，亂雀翻簷噪。',156,'全唐诗/poet.song.61000.json','["羣鳩啄屋鳴，亂雀翻簷噪。", "喜呼怒爭逐，往來競酣鬧。", "陽氣動飛潜，得意相陵暴。", "曉枕不能眠，開門適情好。", "酌泉供清盥，短髮巾野帽。", "中心曠無事，焚香誦真誥。", "人生襲元精，含和百神抱。", "失足落陰界，久困羣邪耗。", "漂溺孰能回，浩劫沉波潦。", "玉鏡動悲雲，慈航引清櫂。", "惟予久冥寞，區區謝初少。", "三疊舞胎僊，八景駐霞翿。", "稽首躡祖風，中天延羲照。"]'),
('63fb3812-d3fc-4b14-b9a9-152753402e1f','登上黨郡樓','李復','宋','宋诗','song-poetry','','[]','羣山合沓來，回抱東林缺。',48,'全唐诗/poet.song.61000.json','["羣山合沓來，回抱東林缺。", "紫翠不可解，環城如玉玦。", "龍飛晉水清，天轉旄頭滅。", "蕭蕭古戰場，春耕擁殘雪。"]'),
('fad099fb-6159-4325-bd4d-067b019f385b','正月五日遊曲江','李復','宋','宋诗','song-poetry','','[]','今日意何適，出遊曲江湄。',120,'全唐诗/poet.song.61000.json','["今日意何適，出遊曲江湄。", "野晴天澄穆，風柔物閒熙。", "淺岸冰已盡，長原麥含滋。", "躍鱗向日光，浴羽侵水嬉。", "悠悠南山雲，浮空久不移。", "斕斑壠東雉，鳴呼聲喔咿。", "春序茲方交，春物已若斯。", "眷予同來者，酌酒衣淋漓。", "莫學少陵翁，淚點吞聲垂。", "且效陶淵明，爲題斜川詩。"]'),
('33103adf-e3c2-4b90-8505-52d624eb1c22','樂遊原','李復','宋','宋诗','song-poetry','','[]','重岡带南山，起伏波濤驚。',48,'全唐诗/poet.song.61000.json','["重岡带南山，起伏波濤驚。", "古原枕隑洲，森爽東西橫。", "陰宿忽自開，秦川一半明。", "莫動興廢悲，惟喜禾黍晴。"]'),
('f6dcc87c-993f-4347-ba59-51f93f15e549','過彈箏峽','李復','宋','宋诗','song-poetry','','[]','悠悠薄洛水，東出彈箏峽。',120,'全唐诗/poet.song.61000.json','["悠悠薄洛水，東出彈箏峽。", "昔人感秋聲，舞躍中音節。", "我來跨官馬，屢渡隨曲折。", "水寒石齒澀，鳴調苦悲咽。", "應有征人淚，泠然灑清血。", "含恨變舊音，冷照關山月。", "衮衮東入海，餘情流未歇。", "掩耳不能聽，揮鞭急超越。", "穿雲望前壘，晚路山雨滑。", "去遠猶自聞，回腸危欲絕。"]'),
('f2bfca60-5d69-413b-aae7-f6face3d6334','曲江','李復','宋','宋诗','song-poetry','','[]','唐址莽荆榛，安知秦宮殿。',48,'全唐诗/poet.song.61000.json','["唐址莽荆榛，安知秦宮殿。", "常因秋雨多，時有微泉泫。", "菰蒲春自生，鳬鶩秋猶戀。", "千古蔽一言，物極理必變。"]'),
('c70b55c9-369a-4350-8e4f-5364e8dfa709','玄都觀','李復','宋','宋诗','song-poetry','','[]','龜刻露蘚暗，石壇霜草黄。',48,'全唐诗/poet.song.61000.json','["龜刻露蘚暗，石壇霜草黄。", "斷瓦出耕土，猶有金碧光。", "甘泉分遠脈，來自惠山長。", "桃花久不開，空餘葵麥荒。"]'),
('89eab815-7429-4a96-ad03-98ab2fb9928c','清明渠','李復','宋','宋诗','song-poetry','','[]','清明三十里，疏鑿高下通。',48,'全唐诗/poet.song.61000.json','["清明三十里，疏鑿高下通。", "西南引潏水，北入太極宮。", "居民昔爲利，舊跡今可窮。", "時見斷石甃，龍盤戲雲風。"]'),
('b694b9d3-abc4-40c5-8d1c-7bb66b7ea996','登高丘望遠海','李復','宋','宋诗','song-poetry','','[]','登高望遠海，冥冥濕天際。',108,'全唐诗/poet.song.61000.json','["登高望遠海，冥冥濕天際。", "百川趨東南，奔騰卷厚地。", "自從開闢來，溶渟不可計。", "浩浩無增虧，周流在一氣。", "怒風駕高浪，雪山寒贔屭。", "飛火掣電光，神怪時出戲。", "却疑蓬萊峰，只是鮫人髻。", "會當見清淺，乘月弄蘭枻。", "去問蟠桃花，結根幾千歲。"]'),
('3cc07f12-08a0-48c8-abe7-419cc5b64262','江行至黄牛廟山特奇秀晚檥舟廟下留詩於壁','李復','宋','宋诗','song-poetry','','[]','層峰浮雲空，亭亭出衆嶠。',132,'全唐诗/poet.song.61000.json','["層峰浮雲空，亭亭出衆嶠。", "芬敷如青蓮，飛光亂寒照。", "霜楓雜丹碧，瀑布垂窈窕。", "秀色紛異狀，爭奇動奔峭。", "欻失畏嶮心，頗愜賞幽好。", "舟行不暇徐，粗得領其要。", "隨風轉隈曲，晚泊黄牛廟。", "杖策登東岑，周睇萬山奧。", "臨岸理晚餉，問客賣早稻。", "明朝走夷陵，便入襄陽道。", "從此步平陸，歸程已可料。"]'),
('96d80837-49b5-4df3-91a8-93f7d463c6a7','峽山遇雨','李復','宋','宋诗','song-poetry','','[]','侵曉登楚山，山峻苦難陟。',216,'全唐诗/poet.song.61000.json','["侵曉登楚山，山峻苦難陟。", "半山忽陰晦，舉手不可識。", "躋攀穿雲過，赫然見日出。", "俯視雲氣中，洶湧浩無極。", "滉瀁雪海翻，兀硉寒冰立。", "蛟龍見或沒，鬐鬛火旆赤。", "風雷恣訇磕，萬車無轍迹。", "神君互麾訶，衆怪爭跳躑。", "變異從何來，萬態不可測。", "峰頂日晴明，下方驚雨急。", "倏爾寂無聲，昏翳豁開釋。", "返照光景新，巖岫翠欲滴。", "瀑泉縞带垂，稻塍清流溢。", "高路靜無泥，牽挽望前驛。", "世俗信耳目，天地度以臆。", "安知視聽外，奇駭可窮索。", "孰知滄溟寬，但見蹄涔窄。", "茲事非傳聞，吾行所自覿。"]'),
('709d8eeb-3a61-4d18-9f94-c7ec00fb7f95','西湖寺','李復','宋','宋诗','song-poetry','','["\u897f\u6e56"]','舊聞宣律師，戒行極精苦。',48,'全唐诗/poet.song.61000.json','["舊聞宣律師，戒行極精苦。", "眉毫出寶珠，錫杖解鬭虎。", "登壇三十年，布薩度緇侶。", "故物今餘何，石像暴風雨。"]'),
('356f7dfe-f9fc-4ca7-9387-eabf522951fc','周巨寺','李復','宋','宋诗','song-poetry','','[]','長楊夾通津，修竹带北岡。',192,'全唐诗/poet.song.61000.json','["長楊夾通津，修竹带北岡。", "尋行不知遠，時聞芝朮香。", "渡溪陟翠巘，松柏高蒼蒼。", "木杪見櫨簷，塔廟居上方。", "盤步曲折峻，入門庭宇荒。", "道人貌清羸，趺坐臨朝陽。", "手持天竺書，貝葉翻金光。", "爐殘柏子燒，龕續明燈長。", "見我默不語，舉杖鳴匡牀。", "以示清靜觀，妙出轉徙鄉。", "我從絕塞來，塵侵兩鬢霜。", "形骸久顛頓，思逐歸鳥藏。", "偶來叩禪扃，夐與人世忘。", "金篦刮病膜，清冰沃煩腸。", "鐵牛耕石田，海底種扶桑。", "超然越初地，青蓮泥中芳。"]'),
('37ed3bfb-e991-470f-87db-ae3fc3459535','陽華夫人祠','李復','宋','宋诗','song-poetry','','[]','陽華少夫人，飛香度青冥。',48,'全唐诗/poet.song.61000.json','["陽華少夫人，飛香度青冥。", "輕明弄餘妍，疏雲含曉星。", "粲然啟玉齒，流電交回熒。", "立久忽飄去，暮山風泠泠。"]'),
('7376affb-4a8e-4aea-915e-e606d13c348f','因何常德招遊西塔有詩遂和','李復','宋','宋诗','song-poetry','','[]','支提壓西城，境絕天香集。',120,'全唐诗/poet.song.61000.json','["支提壓西城，境絕天香集。", "招邀乘逸興，步駛追隨急。", "到門病眼明，曉逐秋雲入。", "浮屠喜躋攀，萬象在拱揖。", "古洞積陰靄，暗澹龕像濕。", "登茲翻百憂，履危非我習。", "南山西出秦，迤邐序等級。", "北渭東赴海，洶湧動都邑。", "林梢見新月，整歸尚依鬰。", "興來莫重辭，時節不可及。"]'),
('cf0ffc7d-b3a7-4cda-9c2b-823766bdd0f8','觀西華摧','李復','宋','宋诗','song-poetry','','[]','高山何時摧，谽谺作空谷。',180,'全唐诗/poet.song.61000.json','["高山何時摧，谽谺作空谷。", "擁土起重岡，斷石大如屋。", "洑泉盡涌發，散漫流新淥。", "南淵勢最廣，百畝亭澳曲。", "龍威儼睢盱，神靈不敢觸。", "茲舊多園囿，修篁带喬木。", "今忽掀阜亂，高下眩人目。", "惟羨勢雄尊，作鎮屹西服。", "嚴威物所仰，宜滋萬生福。", "胡不靜歸根，震蕩屢翻覆。", "天地域中大，奔馳猶未足。", "世事百年間，反衍如轉轂。", "開闢浩劫來，攬之不盈掬。", "紛紛祇如此，於予幸乞獨。", "歸來拂虛榻，孤坐但冥默。"]'),
('31d6ac58-2520-4dee-ba95-b241c7d17474','美原縣北軒','李復','宋','宋诗','song-poetry','','[]','淵明昔遯世，北窗朝脫巾。',120,'全唐诗/poet.song.61000.json','["淵明昔遯世，北窗朝脫巾。", "清風一披拂，自謂羲皇人。", "冥冥孤鴻姿，真與浮雲親。", "寂寞千載後，遐躅空遺塵。", "嗟予敢言勇，斗祿徒爲貧。", "形骸强包束，種種秋毛新。", "朅來渭水陰，訟簡民風淳。", "因喜縱懶僻，鑿牖開星辰。", "吏散鳥下階，清談可娛賓。", "歸去終亦賦，聊此蟠窮鱗。"]'),
('5a1a62b0-459f-41c4-87f7-50ded1922cf9','西崦人家','李復','宋','宋诗','song-poetry','','[]','處陰體生痾，居高地多風。',96,'全唐诗/poet.song.61000.json','["處陰體生痾，居高地多風。", "結廬西崦間，溫凊適炎冬。", "長楊带疏籬，綠畦分西東。", "門前澗水流，繫柳橫橋通。", "汲淺泉更甘，種沃年長豐。", "生理左右足，家有百歲翁。", "乃知淳朴全，能完造化功。", "何必濟淥河，晏寢玄華宮。"]'),
('3f4da5ce-ec32-48f5-87e4-a7f49aaef63a','晚出西郊','李復','宋','宋诗','song-poetry','','[]','晚日登西原，勁風飄我衣。',48,'全唐诗/poet.song.61000.json','["晚日登西原，勁風飄我衣。", "蕭蕭班馬鳴，野曠行人稀。", "撫轡無與語，目送新鴻飛。", "俗塵嘆久艱，故山多蕨薇。"]'),
('a328a138-4750-444c-9a12-4be245f1944b','同劉君俞城西寺避暑','李復','宋','宋诗','song-poetry','','[]','節欲春秋交，寒暑爭愈悍。',228,'全唐诗/poet.song.61000.json','["節欲春秋交，寒暑爭愈悍。", "故知陰陽氣，盛極暑方變。", "七月庚伏末，困弱但流汗。", "天地一大爐，造物虐相玩。", "早衰虛實反，舉動多顛眩。", "安得甘露漿，鑿頂沃清灌。", "招提古浮圖，巋壯壓西甸。", "烈風無時休，寂陰却炎暵。", "幾有籃輿興，客來發我願。", "共遊不暇徐，到寺日未旦。", "童兒青芒屩，潔洒花雨散。", "斌駮溪石枕，凝滑水紋簟。", "張置相對卧，境閑心不亂。", "有時聞妙香，忽來傳靜飯。", "飽起摩腹行，看盡長廊徧。", "却呼竹窗僧，汲泉具茗椀。", "道在語嘿間，淺深隨所見。", "同將煩惱蠲，盡洗清凉觀。", "茲游豈無益，欲繼慎莫緩。"]'),
('a5ddcbf0-d33a-42e2-811a-15eeb6e54214','陳元常醉眠菴','李復','宋','宋诗','song-poetry','','[]','淵明喜閒放，自號葛天民。',96,'全唐诗/poet.song.61000.json','["淵明喜閒放，自號葛天民。", "我眠君且去，人謂此語真。", "無機物莫猜，鷗鳥猶狎馴。", "欲眠何遣客，一念已生塵。", "豈如龐德公，相對忘主賓。", "陳生性嗜酒，大白舉浮身。", "衆中時酣卧，常貯滿腹春。", "澒洞更何物，知容幾輩人。"]'),
('1be57cb5-cf61-4df6-97c5-10ec782ce996','首夏端居','李復','宋','宋诗','song-poetry','','[]','美木交柔柯，薿薿衆葉光。',144,'全唐诗/poet.song.61000.json','["美木交柔柯，薿薿衆葉光。", "餘春歸未盡，葉間有遺芳。", "空庭午陰寂，黄鳥轉新吭。", "微風從何來，穆然和且凉。", "虛堂面清池，文簟舒藜床。", "憩偃神意適，形骸亦相忘。", "蕭然無雜塵，始覺日稍長。", "寒暑迭往返，物生安有常。", "百年只瞬息，忍使生理傷。", "起坐理素琴，曲罷取酒嘗。", "既飲復又酌，仰看閑雲翔。", "得爲太古民，優游見羲皇。"]'),
('57f83791-17e8-4c68-87df-945190f2a36e','居山','李復','宋','宋诗','song-poetry','','[]','居山不出山，日飯鮮鹽酪。',108,'全唐诗/poet.song.61000.json','["居山不出山，日飯鮮鹽酪。", "野菜芼山米，歡若屠門嚼。", "蒼蒼百歲翁，常如一日樂。", "人勸出山住，掉頭終弗諾。", "子孫入市門，賣薪食羹臛。", "歸來舉糜杯，持匕意自惡。", "市門負薪飧，滋味固甚薄。", "甘脆前方丈，入腹毒於藥。", "山翁意甚長，慎無厭澹泊。"]'),
('667e1a46-7f3e-4dae-8ef9-f8279e2b5bbf','次韵君俞三詩時在山下  其一','李復','宋','宋诗','song-poetry','','[]','西陵大火流，南融已頹征。',48,'全唐诗/poet.song.61000.json','["西陵大火流，南融已頹征。", "凉風拂庭樹，槭槭起秋聲。", "遥夜抱膝坐，耿耿河漢明。", "豈無尊中酒，非君誰與傾。"]'),
('36917cec-6796-4caf-a34a-88c7bb4385e6','次韵君俞三詩時在山下  其二','李復','宋','宋诗','song-poetry','','[]','流水會大壑，層岑出遥林。',48,'全唐诗/poet.song.61000.json','["流水會大壑，層岑出遥林。", "結茅窮窈窱，細路下嶔崟。", "風露浩滿野，默坐掩孤衾。", "孤衾無與寫，秋色日向深。"]'),
('93d06932-aa76-47ca-9cda-367872871745','次韵君俞三詩時在山下  其三','李復','宋','宋诗','song-poetry','','[]','朝採南山薇，暮採南山蕨。',48,'全唐诗/poet.song.61000.json','["朝採南山薇，暮採南山蕨。", "零霜百草腓，薇蕨行亦絕。", "清溪有白石，欲煮未可熱。", "故人在東山，幽桂安得結。"]'),
('a91fbc8b-d258-44a1-aba9-31101d431562','郊居五首  其一','李復','宋','宋诗','song-poetry','','[]','牛羊歸近籬，鳥雀喧前林。',48,'全唐诗/poet.song.61000.json','["牛羊歸近籬，鳥雀喧前林。", "天曠白露下，皓月吐東岑。", "呼兒掩柴門，孤燈茅屋深。", "欲寐問故裘，中夜霜氣侵。"]'),
('ca44bf93-0f13-4869-ae74-6f86b82d41f3','郊居五首  其二','李復','宋','宋诗','song-poetry','','[]','禾黍已登場，壠菽葉亦稀。',48,'全唐诗/poet.song.61000.json','["禾黍已登場，壠菽葉亦稀。", "天晴日氣煖，稚子負薪歸。", "婦姑具餉出，飯豆菜葉肥。", "白髮不自閑，但悵筋力微。"]'),
('d0fc1e0e-a5cc-4d2c-9041-7aaacefa0662','郊居五首  其三','李復','宋','宋诗','song-poetry','','[]','楸花不結實，花落綠蔕肥。',48,'全唐诗/poet.song.61000.json','["楸花不結實，花落綠蔕肥。", "彫零先衆木，葉落蔕亦稀。", "枝直鳥不巢，野藤相纏依。", "藤蔓日更長，楸覺生意微。"]'),
('44c5458e-bc8e-4996-805c-5bfa7af39251','郊居五首  其四','李復','宋','宋诗','song-poetry','','[]','歲回秋向閏，九日菊未華。',48,'全唐诗/poet.song.61000.json','["歲回秋向閏，九日菊未華。", "青青東籬下，强起折還家。", "豈無樽中酒，對之空嘆嗟。", "後日開已晚，棄置今如何。"]'),
('1fa46a3f-f135-41cf-a7e9-f00a7d081802','郊居五首  其五','李復','宋','宋诗','song-poetry','','[]','種稻滿南澤，露下稻已黄。',48,'全唐诗/poet.song.61000.json','["種稻滿南澤，露下稻已黄。", "雨足暗泉滿，秷穉各自長。", "侵曉負鐮去，日暮積我場。", "從今有晨炊，璨璨珠玉光。"]'),
('21eab4f1-66a3-4b0b-ad3c-6abb344bfc63','出門  其一','李復','宋','宋诗','song-poetry','','[]','出門復入門，所向常默默。',48,'全唐诗/poet.song.61000.json','["出門復入門，所向常默默。", "積陰久未開，凄風起空谷。", "孤鴻鎩翮悲，黄鵠飛亦獨。", "舊耕半荒蕪，自歎力不足。"]'),
('89e3306e-598c-4bf6-9bd5-483eb6374f23','出門  其二','李復','宋','宋诗','song-poetry','','[]','靜僻懶慢久，煩喧厭入耳。',48,'全唐诗/poet.song.61000.json','["靜僻懶慢久，煩喧厭入耳。", "過客吐新談，意况殊不美。", "火炎幾車薪，難救一盃水。", "但坐問鄰醅，餘事莫掛齒。"]'),
('45847f79-4710-4b05-ba0a-b7caa0edbced','出門  其三','李復','宋','宋诗','song-poetry','','[]','種禾滿東坡，薿薿尺許長。',48,'全唐诗/poet.song.61000.json','["種禾滿東坡，薿薿尺許長。", "初苦夏日暴，今爲秋雨傷。", "耘耔不能施，叢雜衆草荒。", "農夫荷鋤歸，無語空徊徨。"]'),
('ae02fb80-2030-4495-b962-ca4352ec1047','出門  其四','李復','宋','宋诗','song-poetry','','[]','夾徑梧十尋，隠映柴舍深。',48,'全唐诗/poet.song.61000.json','["夾徑梧十尋，隠映柴舍深。", "日期鳳鳥至，柯葉交繁陰。", "昏鴉接翅歸，不聞鳳鳥音。", "秋風黄葉落，感嘆傷我心。"]'),
('c5ed8ae1-a71a-46ad-9348-9a8b2c5b66d0','和石蒼舒喜雨','李復','宋','宋诗','song-poetry','','[]','元祐丁卯春，旱日透地赤。',120,'全唐诗/poet.song.61000.json','["元祐丁卯春，旱日透地赤。", "三農失歲事，嗷嗷嗟艱食。", "宸心動惻怛，祠禱馳星驛。", "張圖繪玄龜，探穴求蒼蜴。", "荒潭幾挈瓶，方壇徒舞覡。", "神龍忽應求，飛灑自前夕。", "蕩滌六合清，萬物湔蒸疫。", "陰陽有沴氣，備禦須多術。", "聖人不罪歲，能助天地力。", "風流仍叔詩，宣王中興日。"]'),
('f3cad11f-8d09-43e3-a5e7-3ef5621363dd','東齋獨坐','李復','宋','宋诗','song-poetry','','[]','飛雨日蕭蕭，秋風收晚暑。',48,'全唐诗/poet.song.61000.json','["飛雨日蕭蕭，秋風收晚暑。", "掩關兀然坐，默與玄相遇。", "坐久忽相忘，玄我無賓主。", "神遊出八紘，鴻蒙見氣母。"]'),
('d5b2983b-5bcd-435c-bcfc-793521da4e70','和人伏日','李復','宋','宋诗','song-poetry','','[]','太極剖元氣，五行均四時。',156,'全唐诗/poet.song.61000.json','["太極剖元氣，五行均四時。", "代謝密循環，母子相挈維。", "土散無定位，金德乘火馳。", "天刑發殺機，閉藏不敢施。", "胚胎勢力弱，熾赫畏炎離。", "聖人御陰陽，恐侵西極虧。", "遇庚防畏禍，用晦將待時。", "曠然達生理，燕息潛深思。", "馬遷紀秦事，德公初置祠。", "後世著令典，賜告休百司。", "曲學雖拘忌，消長自可推。", "歲星東方出，隠迹游天墀。", "詼諧動漢帝，割肉蒙酒卮。"]'),
('da81ae45-d55f-4c9e-931b-5a78627d5975','負暄','李復','宋','宋诗','song-poetry','','[]','朝坐前廡西，晚坐前廡東。',264,'全唐诗/poet.song.61000.json','["朝坐前廡西，晚坐前廡東。", "日當正午時，置榻兩楹中。", "予生本多羸，憂患百箭攻。", "三十已白髮，歲常苦嚴冬。", "凝陰晝墐戶，擁火裘蒙茸。", "寒氣深刺骨，有如嬰利鋒。", "晨曦忽入牖，心喜舊疹空。", "開門曝晴暖，暄酣春意融。", "溫溫百骸舒，漸發兩頰紅。", "乃知萬物生，陽德有全功。", "天輪浩無際，冥冥轉洪濛。", "盧敖遊八極，妄欲求初終。", "卒然至濛谷，見呵鳶肩翁。", "陽烏出扶桑，振轡馳六龍。", "轉盼億萬里，夸父走追蹤。", "遺策化鄧林，狂奔如捕風。", "我今觀天運，四序周無窮。", "東西逐日車，不出環堵宮。", "上古有至人，御風登璇穹。", "手挈日月行，返景回高舂。", "陰陽在掌握，默坐與天通。", "固知二子愚，可嘆如蠰蟲。"]'),
('c4f4abdc-f82a-46ab-8020-bd78c39e4455','冬日','李復','宋','宋诗','song-poetry','','[]','日出東南隅，轉側下西陸。',144,'全唐诗/poet.song.61000.json','["日出東南隅，轉側下西陸。", "不經中天行，但驚六龍速。", "愁寒餘月陰，雲重欲壓屋。", "霰雪飛不斷，凝冰介萬木。", "怒風中夜起，呼號鬼神哭。", "鼓蕩溟渤傾，勢欲翻坤軸。", "十日未肯回，凍埋蛟龍縮。", "城市百賈閉，衾裯換斗粟。", "蕭條觸事艱，更覺生意促。", "安得青帝回，愛景變鄒谷。", "氣溫筋骸舒，負暄一飯足。", "豈願北鄰富，甲第厭粱肉。"]'),
('d381518e-3c05-488c-a560-23735deb48c1','題朱老壁','李復','宋','宋诗','song-poetry','','[]','居無百畝田，廩有三年粟。',120,'全唐诗/poet.song.61000.json','["居無百畝田，廩有三年粟。", "舍北幾株桑，晚蠶食亦足。", "近水理蔬畦，面山結茅屋。", "夏風葦簟凉，冬烟土床燠。", "堂前蒲萄架，新實初垂綠。", "清浄語不煩，事任鞅掌僕。", "鄰里通有無，泉甘草無毒。", "誰知庚桑子，今此居南麓。", "予非市朝人，受性本幽獨。", "願就謀一廛，餘外百無欲。"]'),
('b8982769-9958-491d-864a-22a9480d829a','謁隠士段庭','李復','宋','宋诗','song-poetry','','[]','人生何多謀，常苦饑寒侵。',96,'全唐诗/poet.song.61000.json','["人生何多謀，常苦饑寒侵。", "裘完甑有炊，於世澹無心。", "築室清澗曲，窈窕幽徑深。", "閉門長松下，歲無車馬音。", "古書束高閣，兀然遺屨簪。", "悠悠不記年，日月徒光陰。", "兒童城市還，得酒或自斟。", "隠几望南山，閒雲起孤岑。"]'),
('b59aaf79-4779-4bd9-9b1f-188e17c2cfb4','秉文薦對報罷赴任有詩示予遂和','李復','宋','宋诗','song-poetry','','[]','廣文予所知，京國十年舊。',144,'全唐诗/poet.song.61000.json','["廣文予所知，京國十年舊。", "出背錦囊歸，人嘲飯山瘦。", "去歲近臣薦，三接期在晝。", "孤鴻鎩翮久，高舉或可就。", "慘淡辭都門，顛頓不可救。", "蕩蕩萬斛舟，失在一孔漏。", "相見嗟塌翼，誰與格困獸。", "危根逐輕流，蹇步難遠驟。", "予庭有疏松，風聲響泉溜。", "牆陰多雜花，晴日漸妍秀。", "都城帝子家，碧香寄新酎。", "期君一來過，獵獵直飛袖。"]'),
('0f0f2b2c-e7be-470c-85e5-a0c8de651c93','秋晚謁秉文有詩遂用其韵','李復','宋','宋诗','song-poetry','','[]','庭木葉蕭蕭，廣文官舍冷。',144,'全唐诗/poet.song.61000.json','["庭木葉蕭蕭，廣文官舍冷。", "閉門過客稀，讀書秋夜永。", "病起絮帽額，聞風挈裘領。", "一堂東西橫，乍若登虛艇。", "相對兩無言，孤燈弔形影。", "雲翼未鶱翥，光陰惜俄頃。", "雙璧君羨虞，三龍吾與邴。", "世異泣傷麟，意激軾怒黽。", "萬事非偶然，屈伸難可並。", "無逐頹波流，自覺囂塵靜。", "丹臺有珠宮，眺聽極疏迥。", "君能喜清游，登覽見殊景。"]'),
('9b413339-a61a-4096-a19d-f6aa5e15d7db','出承天院候客','李復','宋','宋诗','song-poetry','','[]','曉動人語喧，門開探騎發。',144,'全唐诗/poet.song.61000.json','["曉動人語喧，門開探騎發。", "冠蓋相後先，烟塵互明滅。", "出城寒寺靜，蒼松带餘雪。", "驅馬傍前廡，投鞭坐僧榻。", "畏風依蒲團，擁裘學趺結。", "曈矓曉日昇，逶迤旆成列。", "到官今年五，踽踽幾持謁。", "執板手有痕，脫冠頂無髮。", "將迎迹愈多，應接面常熱。", "野性素曠蕩，人事苦羈紲。", "久願整歸駕，渡汾尋舊轍。", "躬耕望雲岑，築室俯清潏。"]'),
('309e1113-c082-425d-a885-714def3e4e50','泛舟潏水君俞用韓泛南溪韵作詩三首遂和  其一','李復','宋','宋诗','song-poetry','','[]','出城泛南溪，朝暮可往返。',96,'全唐诗/poet.song.61000.json','["出城泛南溪，朝暮可往返。", "東西韋杜間，尺五天不遠。", "舟轉皇陂曲，岸带青龍坂。", "夷猶一篙足，不待雙絙挽。", "回臨市橋艤，走就僧居飯。", "面山高閣重，入門蒼松偃。", "黯黯雨意來，蒼蒼野色晚。", "更欲窮上方，理履慚尚蹇。"]'),
('43d513f0-dd86-401a-9d7f-c4b3164c9946','泛舟潏水君俞用韓泛南溪韵作詩三首遂和  其二','李復','宋','宋诗','song-poetry','','[]','溪水秋更清，天晴好行舟。',120,'全唐诗/poet.song.61000.json','["溪水秋更清，天晴好行舟。", "叩舷發吳歌，蕩漾無時休。", "朝戲朱坡下，暮宿青嶺頭。", "勝事或有得，隨意終日留。", "往年思此樂，屢嘆來無由。", "今我方求田，意欲營東疇。", "茲計儻能就，遂免卒歲憂。", "身隨鷗泛泛，心逐魚悠悠。", "南舍與北鄰，杖策步可投。", "更祈暘雨時，禾稌常有秋。"]'),
('733cd149-45dc-4044-bca4-4f5c1f4863e8','泛舟潏水君俞用韓泛南溪韵作詩三首遂和  其三','李復','宋','宋诗','song-poetry','','[]','山虧一簣功，泉廢九仞蹟。',96,'全唐诗/poet.song.61000.json','["山虧一簣功，泉廢九仞蹟。", "精神去不回，虛牝黄金擲。", "泝舟望南麓，近岸多巨石。", "溪流曲折多，波喧奔湍激。", "野竹擁雜樹，紛紛兩參列。", "古松氣不羣，蒼然數百尺。", "晚花發幽叢，浮雲動遥壁。", "優游可忘年，去此皆妄役。"]'),
('86c1c8f3-7331-4b75-b592-11f9aff9e74d','侯書記二子席上乞詩遂贈','李復','宋','宋诗','song-poetry','','[]','植蒿不爲棟，豢豚不成虎。',180,'全唐诗/poet.song.61000.json','["植蒿不爲棟，豢豚不成虎。", "本非英特姿，雖長何足數。", "男兒生墮地，便要立門戶。", "謝鳳炳有毛，羊豹兆於乳。", "探根咀其芽，已足知甘苦。", "吾黨有侯生，高門映東魯。", "翹然出二子，發祥自其祖。", "小兒肌骨明，珠光照合浦。", "大兒神宇深，崇鼎氣象古。", "學作四韵詩，已無近俗語。", "燃燈夜讀書，義頗識其觕。", "來客見盡傾，喜歎立如堵。", "積慶固有獲，力穡刈麰稌。", "人知須有成，青雲張步武。", "惜吾已老矣，異日衆必睹。"]'),
('0cd9f42f-a6cc-47ff-9218-5ea63a1fc99b','送章發運楶','李復','宋','宋诗','song-poetry','','[]','鄉農不寓兵，經費半非古。',288,'全唐诗/poet.song.61000.json','["鄉農不寓兵，經費半非古。", "天下雖無事，禁虣必備武。", "浚郊開王畿，屹然根本固。", "鈎陳擁帝居，百萬環貔虎。", "軍聲潮海驚，牙帳屯雲聚。", "臨難責死力，溫飽當有素。", "投身占尺籍，張口坐待哺。", "梁野川瀆交，掘泉不見土。", "種沙禾穟短，官租閣王府。", "國用取東南，舳艫引吳楚。", "浩浩九十州，連檣輸太庾。", "秋風滿汴渠，櫛比不可數。", "登陛獻歲額，供億足贏數。", "儲偫如丘山，司農視新腐。", "老幼無餒腹，誰復問暘雨。", "天子念大計，置官憂敗蠱。", "苟非簡帝衷，未肯輕付與。", "詔書忽西下，秦臺更使斧。", "精忠感帝聰，異寵褒聖語。", "實資經濟術，盡委浩劇務。", "狼荒極海壖，蜀江出荆渚。", "提封半禹跡，綜錯均周賦。", "際天聳風威，列城歸刺舉。", "西北敵騎飛，今猶急宸顧。"]'),
('6d87d167-b2c0-464f-a162-af78ba22e4ea','送呂思道','李復','宋','宋诗','song-poetry','','[]','東平貴公子，意氣區中窄。',120,'全唐诗/poet.song.61000.json','["東平貴公子，意氣區中窄。", "手撚金僕姑，青絲飛赭白。", "欲係單于頸，封侯取鼎食。", "四十心未展，垂翅渭川側。", "前日來坐上，天庭見黄色。", "今朝報恩書，戎幕進新職。", "崆峒古用武，高旌出鋒鏑。", "君當諧素期，洗劍秋泉碧。", "嗟予病摧頹，對別還悽惻。", "待君載旆歸，我作山中客。"]'),
('056c5f10-31fb-45a0-8123-dcfd778c8d66','送僧惠本','李復','宋','宋诗','song-poetry','','[]','山僧青芒屩，厭踏城中土。',48,'全唐诗/poet.song.61000.json','["山僧青芒屩，厭踏城中土。", "水風寒蕭蕭，片影過沙渡。", "晚雲迎歸錫，低飛暗石路。", "暮鐘落前峰，去衝後山雨。"]'),
('5e82d5f4-664d-41cb-b2ab-6f298ef43de3','送人之鄧城','李復','宋','宋诗','song-poetry','','[]','哀弄發危絃，苦調出促管。',48,'全唐诗/poet.song.61000.json','["哀弄發危絃，苦調出促管。", "傷別骨欲銷，坐失重纊暖。", "仙鵠顧徘徊，千里襄江潬。", "此去衮衮情，江水流不斷。"]'),
('cb6e6459-7c45-4d2e-9dca-5f08927bf4ba','送解敞','李復','宋','宋诗','song-poetry','','[]','昔惜結懽淺，今嗟傷別促。',48,'全唐诗/poet.song.61000.json','["昔惜結懽淺，今嗟傷別促。", "離懷動秋雲，清霜落羣木。", "窮山行路難，歲晚自驅轂。", "飛魂不可關，昨夜先到蜀。"]'),
('44fb0c66-4911-4c83-93a2-a41c993f0065','答劉君俞','李復','宋','宋诗','song-poetry','','[]','悠悠東武雲，來抱南山岑。',48,'全唐诗/poet.song.61000.json','["悠悠東武雲，來抱南山岑。", "南山有寒泉，雲影落泉心。", "泉古湛不流，雲靜閒不飛。", "相與待明月，千載發光輝。"]'),
('51c92376-0831-49d7-8409-af2f744e0f78','答嚴隠之','李復','宋','宋诗','song-poetry','','[]','美樹多來巢，确土無報耕。',144,'全唐诗/poet.song.61000.json','["美樹多來巢，确土無報耕。", "不問彼如何，但責己所營。", "聞昔荆有鴞，荆人惡其聲。", "自荆將遷吳，鳲鳩止其行。", "爾欲人不惡，無若革爾鳴。", "鳴聲尚猶爾，荆吳無異情。", "晉子父母邦，鄉閭皆弟兄。", "踽踽異嗜好，遽云居齊城。", "齊雖山川殊，是非如晉明。", "己私不自勝，齊人安肯平。", "子行求吾詩，吾詩豈妄成。", "贈子當發藥，期子沉疴輕。"]'),
('a673319b-7dec-499b-8943-f4ae1060102a','答屈爽','李復','宋','宋诗','song-poetry','','[]','至人喜曠達，所遇無形迹。',144,'全唐诗/poet.song.61000.json','["至人喜曠達，所遇無形迹。", "非樂重其放，中心本純一。", "東晉尚書令，簡文用王述。", "論事匪卓越，動意皆真率。", "以此能過人，謝安亦降挹。", "微物器褊淺，舉趣半出匿。", "靜坐本無事，城府强扃鐍。", "終日如寒蟲，啾啾復唧唧。", "計校不滿毫，血盡死猶泣。", "疾趨赴冥囂，但如水就濕。", "竟老何能爲，紛然衆惡集。", "古先有至言，小人長戚戚。"]'),
('d7102597-b98a-4c06-9261-706049f18a0c','答公孫及','李復','宋','宋诗','song-poetry','','[]','輾轉卧不周，遥夜何漫漫。',120,'全唐诗/poet.song.61000.json','["輾轉卧不周，遥夜何漫漫。", "娟娟竹間月，照我影零亂。", "繁蟲哀陰壁，輕風泛幃幔。", "節物自感人，寤言興永歎。", "頹坐易銷沉，去甚春冰泮。", "萬事隨俯仰，飄忽浮雲散。", "芳槿曜朱華，榮好常在旦。", "百年無期度，白日歲已晏。", "餘生能幾何，可進投憂患。", "駕矣追歡好，東方明星爛。"]'),
('a6084beb-97b6-4bd4-8d00-ad3c556c3dad','答吳與幾二首  其一','李復','宋','宋诗','song-poetry','','[]','人心如驚飈，飄忽無定時。',108,'全唐诗/poet.song.61000.json','["人心如驚飈，飄忽無定時。", "默與身爲讎，晝夜萬里馳。", "兀兀形未彫，茫茫神先疲。", "所喪甚丘山，所得微稗稊。", "日月不相饒，矧可自傷夷。", "志憯劇鏝鋤，欲問孰能知。", "種苗須善本，本善苗必滋。", "養生須養心，心怡氣不衰。", "學問自可求，予言豈汝欺。"]'),
('d3fc13f3-8a73-404a-9462-2e88b278ea63','答吳與幾二首  其二','李復','宋','宋诗','song-poetry','','[]','舊廬鄰通衢，先疇接近郊。',132,'全唐诗/poet.song.61000.json','["舊廬鄰通衢，先疇接近郊。", "居無風雨憂，歲免粒食勞。", "生理亦已愉，胸中胡鬰陶。", "楹桷思丹刻，久厭處衡茅。", "服味喜鮮甘，每羞視鋤薅。", "德業倦時修，憑虛事華豪。", "鄭真耕巖石，張蔚隠蓬蒿。", "內省重千鈞，外物輕一毛。", "當時笑寂寞，清節後世高。", "原思貧非病，賜也氣徒驕。", "爾視季子金，何如顔氏瓢。"]'),
('0bbe976c-4506-4528-b533-2856b46f8bd7','和蘇內翰趙伯堅大卿清池詩','李復','宋','宋诗','song-poetry','','[]','清池有華光，深夜闇不發。',48,'全唐诗/poet.song.61000.json','["清池有華光，深夜闇不發。", "繁星雖燦燦，含光待明月。", "熒熒孤螢飛，來助明月輝。", "明月出東屋，螢向故林歸。"]'),
('913d578c-441c-4bc3-8dd0-f50d8e6c2b0f','平陽民杜裕民因買薪得紫石於薪中石有黝理自然成觀音像相好端具觀察','李復','宋','宋诗','song-poetry','','[]','至心不可求，虛明曠無迹。',48,'全唐诗/poet.song.61000.json','["至心不可求，虛明曠無迹。", "應物乃現形，遺影留茲石。", "若以色見我，洋海塵三尺。", "諸像皆非相，於茲何所得。"]'),
('c32a7567-05d1-43e0-b1af-6cf1b9630693','十一月二十二日朝辭','李復','宋','宋诗','song-poetry','','[]','朝辭承明殿，暮下金馬門。',84,'全唐诗/poet.song.61000.json','["朝辭承明殿，暮下金馬門。", "伏讀明詔意，仰思聖主恩。", "蠢彼獯鬻氏，禮數乃弟昆。", "帝初爲息民，繒帛代更屯。", "嗣皇謹遵業，使傳交塞垣。", "下臣非知古，有舌詎得論。", "恭承丁寧命，敢不夙夜奔。"]'),
('30554b5d-f50b-41c4-a52e-0aed63d7f355','辛順忠唐得道之士真身今在河州寺','李復','宋','宋诗','song-poetry','','[]','少年遊嵩丘，登高吾獨見。',120,'全唐诗/poet.song.61000.json','["少年遊嵩丘，登高吾獨見。", "西游渡隴坂，脫屣古河縣。", "削髮俗網裂，絕味諸漏斷。", "卧脅三十年，凝塵滿羌簟。", "六月大地燋，爐中結冰霰。", "牛頭實栴檀，降出九重殿。", "正就寂滅時，泉竭悲禽散。", "直從開元初，到今色不變。", "破屋閉真相，野鼠嗅香篆。", "時有碧眼人，酌乳供新獻。"]'),
('cb5fc24c-d5c9-4755-94a1-b6498a6469ef','觀梅次豫章公飲潤甫家韵','李復','宋','宋诗','song-poetry','','[]','江梅犯晨霜，噴薄弄晴景。',60,'全唐诗/poet.song.61000.json','["江梅犯晨霜，噴薄弄晴景。", "坐遣塞葅胸，化作陂萬頃。", "論交貴皓首，枯澹味方永。", "戲探茱萸水，飽食雲門餠。", "日下烟渚寒，長歌敲柳癭。"]'),
('f61a6e84-c7b1-42fa-8486-5e03bcd9be53','後園雙松','李復','宋','宋诗','song-poetry','','[]','羣木喜春妍，彫落寒霜苦。',48,'全唐诗/poet.song.61000.json','["羣木喜春妍，彫落寒霜苦。", "昂藏兩大夫，森然鬚鬣古。", "堅姿不可回，正色少媚嫵。", "清風發好音，和氣琴中語。"]'),
('88b93b5d-88a1-40b8-b104-f26d48ccd888','庭下牡丹','李復','宋','宋诗','song-poetry','','[]','春晚午景遲，氣暄困妍姿。',48,'全唐诗/poet.song.61000.json','["春晚午景遲，氣暄困妍姿。", "乘酣意縱放，霞裾半紛披。", "晨起露風清，肅肅爭自持。", "相對默無語，含羞畏人知。"]'),
('58fb62ac-c4af-4c5f-a857-43f7e181db54','雨中觀池荷','李復','宋','宋诗','song-poetry','','[]','急雨過池荷，飛洒來縱橫。',48,'全唐诗/poet.song.61000.json','["急雨過池荷，飛洒來縱橫。", "光圓走青盤，的皪寒珠明。", "炫轉勢不定，積多忽自傾。", "浩然江湖思，蓬窗聽秋聲。"]'),
('58fabc4e-ce4c-4727-a6d7-dc147912d7a5','梧桐','李復','宋','宋诗','song-poetry','','[]','猗猗梧桐樹，前日繁花馥。',48,'全唐诗/poet.song.61000.json','["猗猗梧桐樹，前日繁花馥。", "西風不相饒，影疏不可暴。", "坐看一葉落，餘懷念羣木。", "漫有千歲憂，流光如急轂。"]'),
('a3877831-1e75-4f8b-8c0a-79fd3f694843','種罌粟','李復','宋','宋诗','song-poetry','','[]','前年陽亢驕，旱日赤如血。',215,'全唐诗/poet.song.61000.json','["前年陽亢驕，旱日赤如血。", "萬里隨羽書，揮鞭無留轍。", "炎毒乘我虛，兩歲苦病暍。", "遇夏火氣高，煩蒸不可活。", "飽聞食罌粟，能滌胃中熱。", "問鄰乞嘉種，欲往愧屑屑。", "適蒙故人惠，筠篋裹山葉。", "堂下開新畦，布藝自區別。", "經春甲未坼，邊冷傷晚雪。", "清和氣忽動，地面龜兆裂。", "含滋競出土，新綠如短髮。", "常慮蒿莠生，鋤不敢闕。", "時雨近霑足，乘凌爭秀發。", "開花如芙蕖，紅白兩妍潔。", "紛紛金蘂落，稍稍青蓮結。", "玉粒漸滿房，露下期採折。", "攻疾雖未知，適願已自悅。", "呼童問山鼎，芳乳將可設。"]'),
('a800e9c1-81d1-4bc3-9aa4-6ea3d0b0cd7f','梨','李復','宋','宋诗','song-poetry','','[]','柿垂黄尚微，棗熟赤可剝。',144,'全唐诗/poet.song.61000.json','["柿垂黄尚微，棗熟赤可剝。", "新梨接亦成，實大何磊落。", "纍纍如碧罌，器宇極恢廓。", "懸枝細恐折，植竹仰撐托。", "露下色漸變，逼霜味不酢。", "採摘置中筵，氣壓百果弱。", "憶昔壯少時，酒酣病痟作。", "取食不論數，甘寒勝發藥。", "今嗟老且病，滋味意彫索。", "對之未能忘，欲探引復却。", "晴簷午景暄，尚或思咀嚼。", "齒朽齧亦難，把玩時自噱。"]'),
('5519f30d-af5e-4b58-95b4-d0c1a684de21','慈恩寺枸杞','李復','宋','宋诗','song-poetry','','[]','枸杞始甚微，短枝如棘生。',96,'全唐诗/poet.song.61000.json','["枸杞始甚微，短枝如棘生。", "今茲七十年，巨幹何忻榮。", "偶以遺樵薪，遂有嘉樹名。", "雨露養秋實，錯落丹乳明。", "細蔓如牽牛，半枯猶絡縈。", "晚葉已老硬，不堪芼吾羹。", "根大多靈異，歲久精氣成。", "爲取入刀圭，頹顛掃霜莖。"]'),
('cb30ae1f-56fd-47d0-8ec4-1e30f5182ccf','薙草','李復','宋','宋诗','song-poetry','','[]','衆草費薙鋤，回首已荒翳。',48,'全唐诗/poet.song.61000.json','["衆草費薙鋤，回首已荒翳。", "隨處競茀冗，苟生無遠意。", "時亦吐柔蔓，牽引强附離。", "端居歎力寡，門庭媿蕪穢。"]'),
('21bbcec6-8077-4abc-875f-2b0616dd4a26','放魚','李復','宋','宋诗','song-poetry','','[]','有客持巨魚，造門前自陳。',204,'全唐诗/poet.song.61000.json','["有客持巨魚，造門前自陳。", "敢致子産饋，可待姜侯賓。", "野人不知薄，但媿心美芹。", "橫盤五尺餘，飛光生目輪。", "高鬣丹砂尾，長鬚黄金鱗。", "倔强忽起立，意氣如有神。", "口頰雖噞喁，哀訴何能伸。", "嗟哉自潛泳，胡遘網罟屯。", "使居江湖間，藏器養其身。", "得時感靈變，呼吸乘風雲。", "奮迅彌宇宙，洗滌萬物新。", "胡忍事一飯，遽使刀俎親。", "無罪就死地，惻然傷吾仁。", "解之謝來客，放爾歸通津。", "不期明珠報，相忘乃吾真。", "此去戒前禍，芳餌爲禍因。", "送爾吾自往，世有鄭校人。"]'),
('3de9db0e-23f1-48d2-9398-f7a7e73eca5f','種菜','李復','宋','宋诗','song-poetry','','[]','同牆茅屋東，有地十畝餘。',264,'全唐诗/poet.song.61000.json','["同牆茅屋東，有地十畝餘。", "蒿蓬雜毒草，壅闇惡木俱。", "歲久人跡絕，亂穴狐虺居。", "今晨杖藜出，顧步良躊躇。", "默嗟咫尺間，荒穢侵吾廬。", "散米飯羣僕，操具亟剪鋤。", "攘剔先叢棘，斬伐多高樗。", "乘濕束故急，積供爨我厨。", "耕土如蒸麵，治畦將種蔬。", "時雨近霑洽，膏脈涵如酥。", "問鄰地所宜，嘉種願乞諸。", "異有出戎夷，遠或傳蜀吳。", "根移甘或辛，色剖玄或朱。", "蕪菁飯之半，布藝廣數區。", "牙甲助芬味，瑣細不可無。", "霜降百物肅，禦冬必此須。", "居貧寡營辦，親賓間招呼。", "盤飧多造次，麤糲鮮毳腴。", "收藏資舉筯，率野真腐儒。", "澹薄味可久，萬錢非我圖。", "樊遲請學圃，予今老爲模。", "但媿公儀休，拔葵謝園夫。"]'),
('515e3c2d-b3cf-42b1-9091-180bc6b194fc','松明','李復','宋','宋诗','song-poetry','','[]','亢龍泄流津，津融身自化。',48,'全唐诗/poet.song.61000.json','["亢龍泄流津，津融身自化。", "蒼鱗困摧剝，古鬣漸彫謝。", "無地逃斧斤，豈願耀深夜。", "萬牛空回首，躊躇歎廣厦。"]'),
('e19120f1-e919-4ad1-ab86-45e3e11cf20f','晝坐東軒忽十三蝴蝶顔色鮮碧飛舞近人移時方去紀之以詩','李復','宋','宋诗','song-poetry','','[]','天上寶玉琴，星徽點瑟瑟。',120,'全唐诗/poet.song.61000.json','["天上寶玉琴，星徽點瑟瑟。", "仙人手摩拂，變化通靈術。", "忽隨琴聲起，委蛻如蟬質。", "飛翔下綠雲，風翅含寒碧。", "人間清晝長，遊覽喜自得。", "見我瓶中花，羣遊過簾額。", "高戲亂疏幌，低舞侵墮幘。", "却疑午夢酣，身是濠梁客。", "栩栩出虛庭，興闌有歸色。", "應聞調絃聲，驚去欻無迹。"]'),
('0167e730-0368-40f9-b6ab-1e494d19c41f','登蠶  其一','李復','宋','宋诗','song-poetry','','[]','林間葉半空，腹中絲欲生。',48,'全唐诗/poet.song.61000.json','["林間葉半空，腹中絲欲生。", "已老意更急，食如風雨聲。", "緯蕭外周防，條枝中交縈。", "鼠雀爾無來，共願十日晴。"]'),
('e0b897bb-47e5-4197-92af-d5065e35736e','登蠶  其二','李復','宋','宋诗','song-poetry','','[]','細細玄蟻浮，蠕蠕寸蠖伸。',48,'全唐诗/poet.song.61000.json','["細細玄蟻浮，蠕蠕寸蠖伸。", "抱葉食囁囁，負彩斑彬彬。", "假息方委蛻，吐棼非謀身。", "萬生爾甚微，趨死成其仁。"]'),
('88a7d9f2-fcbd-4961-8503-8ffef509a4e5','浴蠶','李復','宋','宋诗','song-poetry','','[]','柳暖柔可結，川晴流放光。',48,'全唐诗/poet.song.61000.json','["柳暖柔可結，川晴流放光。", "繫柳浴晴川，簇簇古渡傍。", "春陽涵餘潤，斕斑色青蒼。", "衣被天壤周，卵化初微芒。"]'),
('655902ef-7ced-4c44-89d1-9c463d90fb13','原蠶','李復','宋','宋诗','song-poetry','','[]','蠶馬巨細殊，異物同精氣。',48,'全唐诗/poet.song.61000.json','["蠶馬巨細殊，異物同精氣。", "物生不兩大，此衰彼所致。", "周人禮有禁，蠶爲馬之祟。", "織女天上明，多蠶今爲利。"]'),
('874a6e37-b0f0-42f3-a5f9-6b37e8cbaf71','咏蟬  其一','李復','宋','宋诗','song-poetry','','[]','委蛻疏竹根，舒翼高梧枝。',48,'全唐诗/poet.song.61000.json','["委蛻疏竹根，舒翼高梧枝。", "攀緣擇陰翳，意求物弗知。", "清曉喜零露，晴晝弄凉颸。", "長吟不能休，自喜方得時。"]'),
('c3d6031f-d25d-49b9-be61-c50082edff7d','咏蟬  其二','李復','宋','宋诗','song-poetry','','[]','轉丸能升高，藏丸必穴深。',48,'全唐诗/poet.song.61000.json','["轉丸能升高，藏丸必穴深。", "么形感氣變，默得幽憩心。", "遇冬潛厚地，應暑登高林。", "仙術爾何知，動靜役陽陰。"]'),
('cc3c5c68-4618-45c4-b1ff-b32c02f5a6f6','咏蟬  其三','李復','宋','宋诗','song-poetry','','[]','地僻小園靜，羣木陰交浮。',48,'全唐诗/poet.song.61000.json','["地僻小園靜，羣木陰交浮。", "蟬聲忽入耳，物意颯驚秋。", "嘒嘒促徂暑，西風動蕭颼。", "滿林青青葉，漸有搖落愁。"]'),
('52f6ba84-ca07-4bbd-a974-2f6d69bb8f4a','題載記','李復','宋','宋诗','song-poetry','','[]','河魚出龍門，雲雷走平地。',108,'全唐诗/poet.song.61000.json','["河魚出龍門，雲雷走平地。", "飛騰不上天，臨流夜生子。", "生子子有神，怒風翻海水。", "長爪探陽烏，中原苦腥氣。", "鉗奴不耕作，揚鞭斷其尾。", "黄犢養成斑，奔登鄴城址。", "豹來抱虎兒，新棘多鈎刺。", "洛陽金鳳凰，飛入漳河底。", "東南寒日短，滿地邊塵起。"]'),
('fb403e9b-4e1c-43b1-ae65-628273aab553','種松','李復','宋','宋诗','song-poetry','','[]','移松自南山，昔種十三株。',144,'全唐诗/poet.song.61000.json','["移松自南山，昔種十三株。", "連歲苦久旱，十一已彫枯。", "兩株偶得生，喻年未自如。", "近覺稍得地，翠柯漸扶疏。", "乘春抽芳心，歲長二尺餘。", "漸有干雲勢，軒昂出楸梧。", "對立聳奇姿，秀發動吾廬。", "紛紛視衆木，雀鷇望鳳雛。", "清風爲我來，飄爽洒我裾。", "足爲送老資，日待偃蓋舒。", "予今亦已老，顧步良躊躇。", "想當千載後，黛色凌天衢。"]'),
('09fccb43-b47d-478e-b11d-11f1992e4b48','秋夜曲','李復','宋','宋诗','song-poetry','','[]','玉刻麒麟煙縷直，生色屏風龜甲碧。',128,'全唐诗/poet.song.61000.json','["玉刻麒麟煙縷直，生色屏風龜甲碧。", "青娥無聲滿空白，兔影西流轉斜隙。", "仙人蓮花殷葉開，當心吐光照愁魄。", "縵纓短後易水客，氣動燕山驕子泣。", "挽下天河倚渴傾，崑崙流斷無五色。", "銅匣新開北斗高，電光驚飛走空壁。", "鯨魚鬭死海水紅，欃槍西出屯雲黑。", "酒酣揮舞七星寒，金精圯下留素策。"]'),
('c833c0a8-d2b0-4e4a-aece-530171452c64','出城','李復','宋','宋诗','song-poetry','','[]','今日何日我心傷，出門下馬走東岡。',200,'全唐诗/poet.song.61000.json','["今日何日我心傷，出門下馬走東岡。", "東岡路高人迹斷，獨立矯首望八荒。", "長空澹澹地莽莽，停雲黯淡山淒蒼。", "回薄浩劫何渺茫，冥默銷沉寂無光。", "矜雄挾詐爭强梁，百年在世如風狂。", "變化俯仰旋銷亡，一丘已有萬骨殭。", "舊骨未朽新骨藏，丘壠纍纍爭相望。", "萬事意欲一槩量，齎志憤死世更長。", "九月窮秋天欲霜，悲風烈烈吹我裳。", "哀鴻求羣鳴且翔，原野具腓草木黄。", "百川東馳但湯湯，安得曦車挂扶桑。", "高持北斗𣂏酒漿，美人對坐舉瑶觴，與我笑歌憂弭忘。"]'),
('4100441d-e844-4804-9133-bab74c1e2396','流泉引','李復','宋','宋诗','song-poetry','','[]','泉涓涓兮出重山，回抱山麓兮入於蒼淵。',196,'全唐诗/poet.song.61000.json','["泉涓涓兮出重山，回抱山麓兮入於蒼淵。", "流來孔多兮自溢于林間，出始一勺兮下合成川。", "塍有稻兮壠有黍，聚以時兮令以鼓。", "削高增卑兮釃渠絡縷，人不愛力兮揮鍤如雨。", "川流濬兮來無窮，泥五斗兮水一鍾。", "旱暵則引兮淫潦則通，自今以往兮樂我良農。", "禮有經兮歲有蜡，羊豕盈牢兮農舞於社。", "椒香桂綠兮雲車滿野，敬謝有功兮宜奠於泉下。", "吾之將歸兮星律回秋，告邦人兮導畎澮之常流。", "欲泉利之專兮先耘耨之不偷，無忘吾語兮若吾歲之來遊。"]'),
('4a3af370-8993-4a6b-b84e-899e3e75b9b3','惜花謠','李復','宋','宋诗','song-poetry','','[]','搖搖牆頭花，淺深爭灼灼。',104,'全唐诗/poet.song.61000.json','["搖搖牆頭花，淺深爭灼灼。", "容冶不自持，飄揚成輕薄。", "只知朝爲春風開，不知暮爲春風落。", "人心愛春見花喜，看花却嫌花結子。", "別愁常亂空中絮，年光付與東流水。", "今朝還是見花開，明日清陰滿綠苔。", "寂寞流鶑歸去後，忍看落日上高臺。"]'),
('e1509856-8fc1-4d5b-9ef1-bcea4651b120','別鶴曲','李復','宋','宋诗','song-poetry','','[]','碧海漫漫煙霧低，三山風驚別鶴飛。',112,'全唐诗/poet.song.61000.json','["碧海漫漫煙霧低，三山風驚別鶴飛。", "千年華表會能歸，不及雙烏乘夜棲。", "烏來相喜啞啞啼，寒月影移庭樹枝。", "枝上營巢庭下食，追隨應笑塵中客。", "人生聚散羨雙烏，烏若別離頭已白。", "光陰百歲共有幾，空有相思淚如水。", "因君試寫別鶴吟，拂絃欲動悲風起。"]'),
('33708014-5182-421b-b7e6-5ac283459850','湖水歎','李復','宋','宋诗','song-poetry','','["\u897f\u6e56"]','岷山中斷洮水來，分入西湖浸城址。',208,'全唐诗/poet.song.61000.json','["岷山中斷洮水來，分入西湖浸城址。", "一落城陰不復回，餘波日轉臯蘭尾。", "陰風凄冽寒氣早，愁霧慘澹邊思起。", "誰言秋水澹無情，默觀意亦有悲喜。", "天軒地闢滄溟開，百川東奔如激矢。", "龜龍受職日夜趨，萬折必東效臣子。", "發源本願盈科進，築防豈期因坎止。", "日升不及浴雲龍，泥潤空能養萑葦。", "停波寂寞雖無語，物情得失應如此。", "淮陰野外乞餘食，留侯圯下收墮履。", "當年或失龍準翁，冷落功名千古耻。", "我欲鳩工聚長鍤，齊平决堤如决紙。", "直看驚湍萬里潮，免嗟窮涸千山底。"]'),
('b858ddf3-fdd8-4d1a-bb43-1b77842dcb1d','夔州旱','李復','宋','宋诗','song-poetry','','[]','夔人耕山灰作土，散火滿山龜卜雨。',200,'全唐诗/poet.song.61000.json','["夔人耕山灰作土，散火滿山龜卜雨。", "春日不知秋有饑，下種計粒手中數。", "七月八月旱天紅，日脚散血龍似鼠。", "汙邪甌窶高下荒，草根木皮何甘苦。", "蠻商姦利乘人急，緣江轉米貿兒女，己身死重別離輕。", "歸州州南神有靈，歸人刲羊求山神。", "驅風灑潤應香火，飛點不到巫山村。", "巫山縣南也伐鼓，不告歸神告神女。", "江心黑氣卷江流，雷車載鬼雲中語。", "太守身作勸農官，子粒今朝多貸汝。", "春種須作三年計，上滿隆原下水滸。", "他時更勉後來人，老去子孫無莽鹵。"]'),
('a8045759-6d87-4a42-b658-334033633135','兵餽行','李復','宋','宋诗','song-poetry','','[]','調丁團甲差民兵，一路一十五萬人。',384,'全唐诗/poet.song.61000.json','["調丁團甲差民兵，一路一十五萬人。", "鳴金伐鼓別旗幟，持刀带甲如官軍。", "兒妻牽衣父抱哭，淚出流泉血滿身。", "前去不知路遠近，刻日要渡黄河津。", "人負六斗兼蓑笠，米供兩兵更自食。", "高卑日槩給二升，六斗纔可供十日。", "大軍夜泊須擇地，地非安行有程驛。", "更遠不過三十里，或有攻圍或鏖擊。", "十日未便行十程，所負一空無可索。", "丁夫南運軍北行，相去愈遠不接跡。", "敵聞兵侵退散隠，狡筭極深不可測。", "師老凍餓無鬭心，精銳方出來戰敵。", "古師遠行不裹糧，因糧於敵吾必得。", "不知何人畫此計，徒困生靈甚非策。", "但願身在得還家，死生向前須努力。", "征人白骨浸河水，水聲嗚咽傷人耳。", "來時一十五萬人，彫沒經時存者幾。", "運糧懼恐乏軍興，再符差點催餽軍。", "比戶追索丁口絕，縣官不敢言無人。", "盡將婦妻作男子，數少更及羸老身。", "尪殘病疾不堪役，室中長女將問親。", "暴吏入門便驅去，脫爾恐爲官怒嗔。", "紐麻纏腰袍印字，兩脛束布頭裹巾。", "冥冥東西不能辨，被驅不異犬豕羣。"]'),
('68c3e8fd-5126-4dcb-a487-e689264a9878','唐秘書省書目石刻','李復','宋','宋诗','song-poetry','','[]','蓬萊高閣凌浮雲，天上圖書奎壁明。',136,'全唐诗/poet.song.61000.json','["蓬萊高閣凌浮雲，天上圖書奎壁明。", "榮河溫洛龜龍呈，魯壁汲冢科斗行。", "森羅萬目分緯經，大官供烹集羣英。", "魯魚亥豕校讎精，垂籤甲乙刻堅珉。", "懷素無量元崇名，唐興百年人文成。", "大盜一炬甚秦坑，碑落人間如碎星，埋沒草莽荆棘平。", "刊刻欲傳千萬齡，毀滅今與糞壤并。", "牧童敲擊看火生，鏗然清圓猶磬聲。"]'),
('c775f86e-2ec4-4a79-99ad-818938f71452','玉泉寺','李復','宋','宋诗','song-poetry','','[]','道人東立海上山，錫飛西落大江北。',192,'全唐诗/poet.song.61000.json','["道人東立海上山，錫飛西落大江北。", "雙屨還乘海雲起，西過當陽駐山曲。", "倚巖引錫神泉湧，一道明虹出幽谷。", "兀然孤冥踞盤石，清夜鬼神禮白足。", "化城自化非人謀，七日煥然一何速。", "雄樓傑閣鬰相望，擁路十里長松綠。", "鳴鐘擊鼓四百年，法席巍巍傾楚蜀。", "堂上提印雲門孫，聞我足音下山麓。", "門銜大路久慣入，客館蕭蕭蔭寒竹。", "春茶自造始開嘗，色味甘新氣芬馥。", "更窮上方縱登覽，峰嶂四環森萬木。", "投老經過得少留，明發飛塵暗征轂。"]'),
('100bca90-0b8f-42e8-a86c-97b42fd09e03','過興德寺','李復','宋','宋诗','song-poetry','','[]','行雨忽過漸細微，冉冉傍馬殘雲飛。',160,'全唐诗/poet.song.61000.json','["行雨忽過漸細微，冉冉傍馬殘雲飛。", "亂溪爭流經屢渡，近水短畦菘葉肥。", "躋欹到寺石磴滑，紅葉擁門人迹稀。", "升堂坐定聞魚鼓，亦傳齋鉢慰我饑。", "久陰忽開日色薄，初見竹影搖窗扉。", "開山寶塔真相在，瞻拜入爐香霏霏。", "塔前蒼松盡手植，到今百尺森相圍。", "登覽未盡夜氣冷，拂榻置枕舒寢衣。", "明星耿耿東方白，僕夫結束馬已鞿。", "老僧送客有勤意，靜境幸到何遽歸。"]'),
('0cbfd81c-0384-4ab3-94cc-3bbfb680b2f3','下元日朝謁回與李秉文冒雪過承天寺因題二詩於僧壁  其一','李復','宋','宋诗','song-poetry','','[]','北風吹空天欲破，急雪如簁塞空墮。',64,'全唐诗/poet.song.61000.json','["北風吹空天欲破，急雪如簁塞空墮。", "焚香初自蘂宮歸，投鞭來就僧廬坐。", "乾坤一色飛鳥絕，市井無聲百賈餓。", "貧粟未給貧民啼，空屋漏穿不可過。"]'),
('44c79ca3-f72a-4409-89d0-5cc32ad8a0d7','下元日朝謁回與李秉文冒雪過承天寺因題二詩於僧壁  其二','李復','宋','宋诗','song-poetry','','[]','僧爐有令禁觸火，袖手指直凍欲墮。',64,'全唐诗/poet.song.61000.json','["僧爐有令禁觸火，袖手指直凍欲墮。", "缾暖微聞蚯蚓鳴，客寒對作橐駝坐。", "叩鐘擊魚呼衆起，持鉢分糜救晨餓。", "一參木佛古因緣，試舉丹霞有何過。"]'),
('2f187967-c8e2-435c-ad49-3242d6d751c2','督運宿明堂川','李復','宋','宋诗','song-poetry','','[]','督運晚宿明堂川，鑿冰飲馬沙岡窟。',64,'全唐诗/poet.song.61000.json','["督運晚宿明堂川，鑿冰飲馬沙岡窟。", "風沙正面立不得，驍騎輕兵忽馳突。", "密雪擁渡無定河，河带血流浸人骨。", "帳中令下星騎來，半夜促行更倉猝。"]'),
('e0c1db5e-7ac8-428a-85e0-fd029c7a20df','鯀廟','李復','宋','宋诗','song-poetry','','[]','治水弗績鯀當殛，逃入羽淵爲黄能。',160,'全唐诗/poet.song.61000.json','["治水弗績鯀當殛，逃入羽淵爲黄能。", "韓山東北有荒廟，豕象冕服吁怪哉。", "鄉社養牲禁畜豕，恐觸神怒風雷災。", "秦漢以來不讀禮，祝尸鼎俎如優俳。", "魂魄久與魑魅雜，野妖陰怪憑草萊。", "高山南北二千里，谽豁鑿斷龍門開。", "昆侖長河走出海，神禹功大不可偕。", "後王書稱嗣天子，永爲萬世嚴祠齋。", "爲崇王像備冠舄，寢廡敞侈完傾摧。", "明飭有司正祀典，春秋致祭吾自來。"]'),
('b2cdebba-2110-42ac-9220-edd097e67191','過高平縣','李復','宋','宋诗','song-poetry','','[]','蚩尤食昴乘鬼車，韓國爲窟秦爲蛇。',192,'全唐诗/poet.song.61000.json','["蚩尤食昴乘鬼車，韓國爲窟秦爲蛇。", "韓人畏蛇渡河走，殺氣吹斷邯山斜。", "秦鼓一擊趙括死，四十萬人坑黄沙。", "白日忽落天地黑，鴞銜碧火來人家。", "至今野土盡血色，古鏃漬血生銅花。", "髑髏銜恨骨不朽，千歲開口生齒牙。", "秦怒垂涎急饑腹，孱趙輕搏嬰其毒。", "折戟沉槍鐵半消，洗磨赤璺曾封肉。", "冤氣不絕起凄風，滿眼山川無草木。", "晝陰夜慘少行人，愁雨荒煙聞鬼哭。", "秦兵掃蕩六國塵，兵禍弗戢須焚身。", "博浪金椎擊不死，亡秦終是韓國人。"]'),
('985c69ed-c512-4f73-a211-dd362038b571','過澶州感事','李復','宋','宋诗','song-poetry','','[]','孫村黄河决北流，北使年年過澶州。',128,'全唐诗/poet.song.61000.json','["孫村黄河决北流，北使年年過澶州。", "澶州兩城戰格盡，七十餘年廢不修。", "昔歲契丹傾國起，欲投馬箠渡河水。", "烽火夜夜照前殿，殿前羣臣色如死。", "心憂社稷輸至忠，殿上只有寇相公。", "默使敵計墮吾計，獨屈黄屋親臨戎。", "敵驚潰奔虎北門，從此願講兄弟親。", "平時危冠盡肉食，一旦倉猝方見人。"]'),
('40b54a2f-41fc-4afc-99c9-b273f4b0f68b','和遊趙韓王園','李復','宋','宋诗','song-poetry','','[]','剝剝啄啄初叩扃，主人立門雙眼青。',192,'全唐诗/poet.song.61000.json','["剝剝啄啄初叩扃，主人立門雙眼青。", "籃輿遽下屏徒御，脫帽解带風泠泠。", "倦思經時一日縱，乍離涸轍遊滄溟。", "靚深曲折任吾向，度橋繞徑足不停。", "芍藥晚花猶泫露，櫻桃滿樹垂繁星。", "萬竹森嚴擁幢蓋，蒼松夭矯呼風霆。", "空嘆春時不得到，枯香落蒂今飄零。", "徙倚歷覽意稍滿，自具野飯追淥醽。", "却呼主人坐對酌，脯醢間錯魚蝦腥。", "共歎羈韁鮮休暇，一餉聊爾消沉冥。", "病餘量隘不禁醉，騎馬歸舍猶未醒。", "解衣拂榻欲假寐，傳呼有客來造庭。"]'),
('aa4d8069-9496-4d2d-86a5-b8529abaad6f','蒲城道中','李復','宋','宋诗','song-poetry','','[]','羣虎鎖頸鷄連羣，弓刀後先路暗塵。',64,'全唐诗/poet.song.61000.json','["羣虎鎖頸鷄連羣，弓刀後先路暗塵。", "劫錢殺人棄屍去，近山白晝無行人。", "格捕死鬭血狼藉，解衣黄金猶在身。", "傍云縱惡壞官法，自來赴愬官中嗔。"]'),
('2ccb15db-a7b4-4138-9148-1781062d3ec6','伊川道中','李復','宋','宋诗','song-poetry','','[]','溪流冰盡搖日光，夾岸弱柳千縷長。',64,'全唐诗/poet.song.61000.json','["溪流冰盡搖日光，夾岸弱柳千縷長。", "野鳥深藏但聞語，山花半開初有香。", "今朝伊川首西路，昔年潏水過南塘。", "安得春風生兩腋，從教吹到故山傍。"]'),
('f65a7510-7667-400b-8bb2-854de0a0d889','過平泉鋪','李復','宋','宋诗','song-poetry','','[]','去家十日九有雨，林間怒鳩猶逐婦。',64,'全唐诗/poet.song.61000.json','["去家十日九有雨，林間怒鳩猶逐婦。", "村店泥深晝閉門，繫馬臨河自炊黍。", "生桑煙重不供爨，麤糲如沙聊把筯。", "推盤急起却問程，黄昏更望山顛戍。"]'),
('762cccbc-72fb-4825-9bbd-976136e5d14b','下鐵礓嶺望秦川晚宿九谷','李復','宋','宋诗','song-poetry','','[]','六月登壠如登天，騰夷鐵礓須判年。',64,'全唐诗/poet.song.61000.json','["六月登壠如登天，騰夷鐵礓須判年。", "過險欲涉渭水渡，快眼喜見秦州川。", "溪塍青秧下白鷺，驛亭秀木含疏煙。", "投鞭清盥且展簟，明日去酌北流泉。"]'),
('90bfc373-1b18-40be-b99e-05aaf197b830','題步生所居','李復','宋','宋诗','song-poetry','','[]','君今移居澗水東，澗水暴漲侵近路。',192,'全唐诗/poet.song.61000.json','["君今移居澗水東，澗水暴漲侵近路。", "盡取澗石成垣牆，生鑿岸柳作橋柱。", "結茅構屋十數間，取次面勢分幾處。", "看山看水督耕耨，隨意自在不計步。", "到處或坐或偃息，盡有室廬庇風雨。", "土床竹簟雖草草，已足自適奉寒暑。", "窗下瓦榼漆生光，貰酒提携老無數。", "客來安更問誰何，漉魚拾蟹共烹煮。", "青黄錯雜出木盤，野蔌山蔬四時具。", "久厭輕動踏市塵，未嘗開口論世故。", "究竟得意此最多，向老尤要知其趣。", "一生遇事皆任真，仰首高風繼巢許。"]'),
('80abbad4-f4d2-47e1-b00d-b6d2aea564a1','和沈潛誠崔氏園九尾龜','李復','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','天生神物非偶然，此龜不知今幾年。',160,'全唐诗/poet.song.61000.json','["天生神物非偶然，此龜不知今幾年。", "世傳一尾直百歲，計應生在晉魏前。", "長江不掛豫且網，得來佳處遊林泉。", "穹然蒼甲大如屋，欲負三山翔羣仙。", "奇宮偶卦天地位，爻畫夐出大易先。", "惟昔寧王重爲寶，閟藏欲永萬世傳。", "今茲此寶世莫識，但愛金字毛綠鮮。", "仰視朝陽俯引氣，一閉千息常綿綿。", "默然無言觀物化，壽比彭籛猶更賢。", "陰陽靈變固莫測，時或輕舉來巢蓮。"]'),
('ff6f551a-77b7-4744-8c72-eae337a49eac','督糧宿鹽州東','李復','宋','宋诗','song-poetry','','[]','怒風吹雪急鞭馬，匪兕匪虎率曠野。',64,'全唐诗/poet.song.61000.json','["怒風吹雪急鞭馬，匪兕匪虎率曠野。", "護糧將軍夜不來，敦然獨宿在車下。", "夏人驕狃敢予侮，王師問罪在一舉。", "半歲力盡竟無功，哀哀生人命如土。"]'),
('5780b5e9-2730-49e6-8aaf-2b62177d37be','西洨晚歸','李復','宋','宋诗','song-poetry','','[]','今日雨晴雲出溪，疏林荒僻色愀悽。',128,'全唐诗/poet.song.61000.json','["今日雨晴雲出溪，疏林荒僻色愀悽。", "杖藜出步洨水曲，白沙細草浄無泥。", "漁人截流張巨網，擊水驚魚魚更迷。", "兒童喜見魚網重，得魚貫柳畢提携。", "林竹翛翛久不到，夏笋迸籬生不齊。", "或蓑或笠荷尺箠，牛羊羣過喬木西。", "野曠衣潤露已下，回尋歸徑登故畦。", "吾茅遥見隠暝靄，到門鄰舍雞亦棲。"]'),
('5af6c31a-bb0a-4baa-af3a-b1c55ed1ab14','村步','李復','宋','宋诗','song-poetry','','[]','東阡南陌常經過，臘破已覺春氣和。',64,'全唐诗/poet.song.61000.json','["東阡南陌常經過，臘破已覺春氣和。", "出門仰視天宇靜，暄暖自聞人語多。", "青青短麥徧原隰，耿耿殘雪明陵阿。", "身閒心適欲追酒，惜無佳客來當歌。"]'),
('45a5fa67-c0cc-4996-9249-c8ccef1550a6','和李夷行遊西溪醉歸','李復','宋','宋诗','song-poetry','','[]','輕輿共登大堤路，左手持螯不問數。',64,'全唐诗/poet.song.61000.json','["輕輿共登大堤路，左手持螯不問數。", "風回驚怨落紅飛，把酒臨溪倚花樹。", "杯中神物換凡骨，直欲呼雲上天去。", "茂陵劉郎老更癡，夜守銅盤飲寒露。"]'),
('7434adf0-7e54-47c5-9b84-f7ff88abe42f','雪中觀梅花','李復','宋','宋诗','song-poetry','','[]','破萼江梅爭初吐，漢宮妙香聞百步。',112,'全唐诗/poet.song.61000.json','["破萼江梅爭初吐，漢宮妙香聞百步。", "耐寒蛺蝶何自來，繞花翩翩那忍去。", "幽芳不載蔚宗譜，絕俗韵高吾最許。", "直疑滕王百幅圖，淡墨濡毫添老樹。", "冷蘂疏枝整復斜，倚杖時時暗香度。", "惜無璧月懸中天，令渠交光映當戶。", "莫作桓伊一笛風，要看冰姿嬌挾曙。"]'),
('c5643a4a-cdb8-422c-ade5-dd67d2980c8f','種桃','李復','宋','宋诗','song-poetry','','[]','西郊移桃園散植，東風一吹高數尺。',112,'全唐诗/poet.song.61000.json','["西郊移桃園散植，東風一吹高數尺。", "開花滿樹亂蔫綿，結實壓枝雜紅碧。", "初年採摘不知幾，三年花稀實少得。", "陰蟲食根膠自流，今歲春餘愁寂歷。", "須知花多必易朽，人間顔色安能久。", "寒松森嚴少媚嫵，回視衆木爾何有。", "不作羣花十日紅，欲獻主人千歲壽。"]'),
('c5b6ef28-4135-43ed-93df-b26576543157','李花','李復','宋','宋诗','song-poetry','','[]','桃花爭紅色空深，李花淺白開自好。',64,'全唐诗/poet.song.61000.json','["桃花爭紅色空深，李花淺白開自好。", "前日含青意澀縮，今晨碎玉亂高杪。", "暖風借助開更多，餘陰鬰芘花還少。", "天晴不愁不爛漫，後花開時先已老。"]'),
('a80209a2-fb27-49e9-8267-56fa270b0e11','牧童曲','李復','宋','宋诗','song-poetry','','[]','牧童喜晴卧溪曲，羣牛互鬭殘我竹。',64,'全唐诗/poet.song.61000.json','["牧童喜晴卧溪曲，羣牛互鬭殘我竹。", "驚起旁行不肯來，聞呼却走如生鹿。", "園夫奮詈辱其翁，老翁操箠自驅逐。", "牛奔衝狂亂壞籬，補籬更剪溪邊木。"]'),
('10572ee4-40ce-4e58-8a4d-6c79d77a178f','書飲客言','李復','宋','宋诗','song-poetry','','[]','御史在前執法後，先生飲酒不濡口。',236,'全唐诗/poet.song.61000.json','["御史在前執法後，先生飲酒不濡口。", "脫巾露頂兩脚赤，先生飲酒不論石。", "試問先生飲何如，舉手指腹此誰測。", "東家閉門强偪仄，刻骨膠筋束形跡。", "一生寂寞養聲光，誰肯回頭顧枯魄。", "南鄰矜誇尚馳騖，平明跨馬朝天去。", "車從導騎如雲屯，謗辱丘山盈後路。", "賜銅鑄錢終餓死，深居巷內還逢虎。", "高天蒼蒼地茫茫，與君舉首望八荒。", "人生優游本無事，自置冰炭毒肺腸。", "鵬飛鷃躍何高卑，菌短椿壽何彭殤。", "百年倏忽不再得，爭奪紛紛世界仄。", "渾沌不鑿人不死，但知飲酒志願畢。", "東方明星高，西山江水流。", "明星却回江不斷，與君常醉消白頭。"]'),
('8007d83b-4607-4c6e-9eb3-41f04649654f','溫泉行','李復','宋','宋诗','song-poetry','','[]','驪山鴻濛凝白煙，山根陰火煮玉泉。',160,'全唐诗/poet.song.61000.json','["驪山鴻濛凝白煙，山根陰火煮玉泉。", "陰靈炎炎燃礜石，石焰不滅何千年。", "珠閣縹緲飛鳳來，素衣仙人坐高臺。", "臺前香引流水出，白玉蓮花九葉開。", "泓渟分去浮輕碧，中有純陽無限力。", "四時獨不放春歸，散向人間消百疾。", "瓊樹他年日月新，霓裳舞動蜀山塵。", "寒雲怨鎖遺宮冷，林葉巖花秋復春。", "靈泉有靈天降福，山神嚴呵不可觸。", "祖龍心穢慢神天，毛髮流腥身被毒。"]'),
('0bf2e385-1ac4-4fca-9561-f0f245251bde','孤鶩','李復','宋','宋诗','song-poetry','','[]','孤鶩何時失舊羣，空郊迥立如長人。',160,'全唐诗/poet.song.61000.json','["孤鶩何時失舊羣，空郊迥立如長人。", "疾風拂地忽驚顧，欲起不起低昂頻。", "遼東八月霜氣早，萬里旅飛來南賓。", "雲間翩翩羽相接，沙上雝雝情更親。", "空江誤駭虛絃響，飄亂哀驚爭愛身。", "倉皇離散意奔翥，形迹漂零心苦辛。", "拳曲悲鳴求遺穗，稻粱收盡原野貧。", "暮天蕭條侶影過，側頭仰望空傷神。", "想能高鶱投別伴，思故未忍重求新。", "會向北歸却相見，當看刷翮向前春。"]'),
('22801de6-79a5-4381-8ef2-c0407142d66f','襄州大悲像','李復','宋','宋诗','song-poetry','','[]','寶伽如來出海山，隠身自畫如來像。',144,'全唐诗/poet.song.61000.json','["寶伽如來出海山，隠身自畫如來像。", "三日開門孤鶴飛，滿壁晬容現殊相。", "一首千臂眼在手，一一手執各異狀。", "日月山嶽星宿明，鐘鼓磬鐸琴筑響。", "矛戟戈劍利兵鋒，缾鉢螺巾寶錫杖。", "左右上下滿大千，應機妙用不可量。", "金光宛轉徧沙界，億萬人天盡回向。", "昔聞如來發洪誓，慧目無邊破諸妄。", "我今祝願果初心，銷滅含生多劫障。"]'),
('bc203826-1b3e-4d9a-b9ea-6de12720047d','論交','李復','宋','宋诗','song-poetry','','[]','市井苟喜毫釐親，節義動以肝膽許。',64,'全唐诗/poet.song.61000.json','["市井苟喜毫釐親，節義動以肝膽許。", "餘耳兆亂在交初，管鮑論財偶多與。", "情僞安能盡一言，是非必欲期千古。", "尼父已遠不得復，夢寐恍惚與神遇。"]'),
('88c2a23f-36ea-4af4-a4ce-e57cd850629b','元日','李復','宋','宋诗','song-poetry','','[]','元日擁戶如盤蝸，門前轣轆多行車。',64,'全唐诗/poet.song.61000.json','["元日擁戶如盤蝸，門前轣轆多行車。", "擁門喧呼客投刺，驚風舞雪翻飛沙。", "幽室置火引就坐，持杯暖腹客氣華。", "三杯油然衆客去，庭樹瑟縮蹲山鴉。"]'),
('d9a0d923-9ee2-4a1f-aaa0-11b163ccd3e6','上巳成季召會于西溪會上賦詩須多韵仍用故事或舊詩十事已上未終席而成違者浮以三大白罰者四人予與成季免焉','李復','宋','宋诗','song-poetry','','[]','華林園中千金堤，銅龍吐水天泉池。',288,'全唐诗/poet.song.61000.json','["華林園中千金堤，銅龍吐水天泉池。", "八公山下劉安臺，城郭周圍雜花開。", "流金寶劍爲秦出，綵鷁羽觴浮洛來。", "著處祓除務是日，西關千人萬人出。", "脩脩美竹带林高，激湍遠照崇山碧。", "主人濟南舊詞伯，芸閣鉛丹事書冊。", "載酒展席俯長流，一飯未嘗留俗客。", "拂地低回舞袖翻，簫管哀吟動魂魄。", "天晴初暖雲自嬌，風柔徐動花無力。", "氣酣傾倒不自惜，屢顧空尊有愁色。", "豈學飛蚊一餉樂，論文清心聽鳴鏑。", "詩壇誓衆軍令嚴，立表下漏不容刻。", "神意慘淡諠謔寂，疊簡搖毫辭舉白。", "欲徵故事入新語，摯虞追歎慚束皙。", "山陰衣冠交履舄，千載風流傳不息。", "繭紙墨妙龍鳳飛，遠近家雞皆斂翼。", "明年此會恐難得，俯仰之間已陳迹。", "來者興歎感斯文，後之視今今視昔。"]'),
('8ece3758-4601-46ea-89d7-c75cce925276','夏旱','李復','宋','宋诗','song-poetry','','[]','浮雲蔽空旱日熾，日酷燒雲雲散裂。',64,'全唐诗/poet.song.61000.json','["浮雲蔽空旱日熾，日酷燒雲雲散裂。", "雲怒漏穿未肯去，日光迸射千道血。", "蔽天頑狠鬭不歇，天工默默無與决。", "乘時爭勝更苦熱，魚龍戢戢愁海竭。"]'),
('169533a6-cc96-4b1c-a1b7-3eaaa4f3ea1c','七夕和韵','李復','宋','宋诗','song-poetry','','[]','東方牽牛西織女，飲犢弄機隔河渚。',304,'全唐诗/poet.song.61000.json','["東方牽牛西織女，飲犢弄機隔河渚。", "西風忽起怨夜長，相望盈盈不得語。", "走投上帝貸金錢，五雲飛來結香軿。", "曳裾拂露天榆冷，照影回身桂葉偏。", "銀潢七月秋浪高，黄昏欲渡未成橋。", "却向人間借烏鵲，銜石欲半河已落。", "碧霧爲帳霞爲裳，絳節欲盡兩旂張。", "燦然一星中耀芒，前瞻漢曲喜色長。", "飈輪儼雅靈龍翔，相迎交贈雙明璫。", "臨席舉袖開雕扇，故人有似新相見。", "共持深願祝天工，海底烏沉參不轉。", "世間共傳牛女喜，綺樓百尺排空起。", "垂綏插竹動雲陰，玉豆珠盤羅飺餌。", "壺開綠酒浄於空，秋滿虛庭氣如水。", "兒童不眠看星會，白光奕奕搖飛旆。", "整衣低首祝深心，未祝焚香先再拜。", "曈矓曉動斗車移，小雨班班怨別離。", "天上還應分鳳軫，人間又喜見蛛絲。", "空堂野老頭如雪，不解祈巧但祈拙。"]'),
('1e298b55-bf19-4cca-a861-1716df1d5c23','重陽日獨居洨水君俞出遊杜曲惠詩酬以來韵','李復','宋','宋诗','song-poetry','','[]','衆人有錢競沽酒，嗟我獨醒坐搔首。',64,'全唐诗/poet.song.61000.json','["衆人有錢競沽酒，嗟我獨醒坐搔首。", "荒徑蓬蒿深映門，茅舍三間傍疏柳。", "南山奔騰呼欲來，雲散山容一笑開。", "何似齊山江上客，菊花須插滿頭回。"]'),
('e0e72a38-280b-4d4d-ac28-387d184f77bb','和李教授攄遊溪阻風','李復','宋','宋诗','song-poetry','','[]','去年春盡送春歸，溪邊曾與春風期。',288,'全唐诗/poet.song.61000.json','["去年春盡送春歸，溪邊曾與春風期。", "共期今歲春風到，却話去年相別時。", "二月天回斗杓轉，沙際春風猶未知。", "咄咄向空但書怪，常有孤愁來兩眉。", "南巷佳人佩蘭客，去年把葉同題詩。", "能傳芳信慰枯槁，問我溪邊來何遲。", "明發招邀出城去，欲傍垂楊舉酒巵。", "盲飈東來忽作惡，掀簸地軸搖天維。", "坐客隔手不相見，縮頸盡如藏殻龜。", "昏沙欲定日更黑，浩浩崩奔陰雲垂。", "蒼茫催人雨勢急，促轡競路爭先馳。", "歸途邂逅過蕭寺，投鞭思弈雲房棋。", "道人呼童拂廣榻，笑我塵土兩目眵。", "漫展紋楸第袖手，瞑依團蒲神意疲。", "朝來共尋一餉樂，齟齬似爲神物欺。", "况乎人生百年間，世事萬里多嶮巇。", "紛紛智巧日夜鬭，一身浪苦寧非癡。", "試向道人問實相，指我自求無言師。"]'),
('6c10e06b-bc79-4f8d-bc85-6f47f2e9113a','和朱公掞禱雨五龍廟','李復','宋','宋诗','song-poetry','','[]','太師占歲驗律管，氣來姑洗聲猶短。',320,'全唐诗/poet.song.61000.json','["太師占歲驗律管，氣來姑洗聲猶短。", "野人告病三月餘，公堂嚴齋五日滿。", "相招禱雨陟南山，出城鞭馬追飛繖。", "林鳩怒鳴競逐婦，穴蟻移居自銜卵。", "迎路商羊舞若飛，隨車少女風不斷。", "陰昇陽交兆已見，神意感通知憫旱。", "焚香瀝酒灑枯地，草根清流忽盈碗。", "茲事舊傳或未信，誠禱靈答知非誕。", "祠亭豐碑高突兀，歲紀神䴥魏所纂。", "道武開國始南征，矯首據鞍思勝筭。", "雲間仰見黑龍來，翔戲下山五爲伴。", "考卜推爲受命符，將拜帝休先沐澣。", "前瞻雷電塞空山，築宮岧嶢敢辭懶。", "鬼神填委煥丹青，草木森嚴無冗散。", "登山層級繞巖巒，趣門一徑極平坦。", "簫鼓于今幾百年，暘雨無愆雩禜罕。", "今朝霢霂千里蘇，太守憂民罄誠款。", "四郊宿麥遠青青，土膏脈潤天已暖。", "明朝牲幣躬脩報，豈憚陟降步巘窾。", "魯無禾麥書春秋，須知民事不可緩。"]'),
('b875ae4c-14c8-4919-bad8-c2035c0e5d89','依韵酬朱公掞給事','李復','宋','宋诗','song-poetry','','[]','滄溟酌蠡天窺管，龜兆何長筮何短。',320,'全唐诗/poet.song.61000.json','["滄溟酌蠡天窺管，龜兆何長筮何短。", "什百倍蓰情不齊，斛龠釜鍾難槩滿。", "東西地缺如斷玦，西北天傾猶倚繖。", "山䍽何由蔚豹班，荆雞豈解伏鵠卵。", "雖許駑駘可累馳，所貴鏌鋣能立斷。", "東陵瓜地久已荒，南山豆苗歲常旱。", "日隨羣影塵滿衣，愧竊太倉米盈碗。", "默嗟世事意難期，却怪古書語多誕。", "往來迅景急川流，悵惘無聞歸鬼纂。", "今年短髮颯驚秋，餘日駸駸豈容筭。", "逸驥空勤足未舒，寒燈靜弔影爲伴。", "數朝忽喜挹高風，煩心執熱逢清澣。", "仰觀眉睫意可見，巳許交臂心無嬾。", "飄零鎩翮感鸞悲，繩墨呈材媿樗散。", "須思汲古得修綆，却步歸愚識夷坦。", "惟君早歲嘆淹回，白雪調高和宜罕。", "諫垣密疏藁常焚，瑣闥舊風筆不款。", "雲間遽與鴛鷺分，邑里新歌襦袴暖。", "與我晤語若合契，鋤去陵谷無隙窾。", "因君相見慰蹉跎，再激平生嗟已緩。"]'),
('08eecaf6-cff7-41f0-89af-f6c7ea17054f','酬邢先生疊前韵','李復','宋','宋诗','song-poetry','','[]','道人海南游五管，野服褷褵鶴羽短。',320,'全唐诗/poet.song.61000.json','["道人海南游五管，野服褷褵鶴羽短。", "飛符分藥濟炎州，陰功早約三千滿。", "細葺柔蔓作重茵，密綴圓荷爲翠繖。", "丹回七返已成珠，寶養三田如抱卵。", "一身天畔若雲浮，萬事世間皆刃斷。", "行山書篆虎逃穴，臨水呼風龍救旱。", "弄琴得趣或忘絃，遇酒無辭任傾碗。", "試持舊說叩真詮，深笑浮言多詭誕。", "須知至道甚無煩，豈若俗書務集纂。", "向走天下四十年，利口妄談何可筭。", "引枝逐葉盡無根，神與形離不相伴。", "超然自得方自知，天下一新如澡澣。", "生平聞風已默契，今者相從敢縱懶。", "事來酬酢外須應，心不將迎意自散。", "喜予雙眼爛熒熒，知予靈臺常坦坦。", "寶身好事求雖多，誠言出口識還罕。", "赤水遺珠若爲求，五雲瑶闕何時款。", "凌空未便御風行，跨馬先覺雙鐙暖。", "輪扁運斤棄繩墨，庖丁解牛遊綮窾。", "太清吾祖遺真風，欲逐青牛媿駑緩。"]'),
('3e53b1c6-cf71-46ef-9546-218a412da2fb','按視沙苑','李復','宋','宋诗','song-poetry','','[]','南瀕清渭北洛水，寒沙東西橫百里。',192,'全唐诗/poet.song.61000.json','["南瀕清渭北洛水，寒沙東西橫百里。", "中條太華塞秦關，衆川無歸皆潴此。", "地維忽斷兩山高，帝罰罔功五丁死。", "波飛浪激走東溟，積雪回汀擁都鄙。", "坡陀起伏接城門，薦草甘泉國馬屯。", "雲昏霧暗天駟下，星宮夜失房宿尊。", "驊騮騏驥種各有，一一六印官字存。", "開元籍馬七十萬，監苑舊政宜討論。", "過都歷塊汗流血，朝刷幽并暮楚越。", "天邊不從鑾輅行，歲久空老狐狟窟。", "去年駒生風雨腥，戴角肉鬣自有鱗。", "廄人見怪棄於野，騰入渭水方知神。"]'),
('93b278bf-e9bb-4182-986d-bddb50c05899','與任鯤同按沙苑','李復','宋','宋诗','song-poetry','','[]','寒空暗澹風滿衣，縈回林薄相追隨。',64,'全唐诗/poet.song.61000.json','["寒空暗澹風滿衣，縈回林薄相追隨。", "野花班班隠亂草，暮葉翩翩辭高枝。", "渭水無烟但聞哭，延州築城猶出師。", "四顧乾坤莽回互，濺濺洛水東南馳。"]'),
('44611bed-e677-4150-9e80-a1247a66372b','送人赴雅州任','李復','宋','宋诗','song-poetry','','[]','去年送君走邊州，今年送君入蜀道。',192,'全唐诗/poet.song.61000.json','["去年送君走邊州，今年送君入蜀道。", "上官南北不自知，風卷孤雲離海嶠。", "場屋爭飛二十年，垂翼空歸嘆潦倒。", "綠衣晚出外家來，一命初忻慰枯槁。", "憶昨當途數論薦，謂君逸足須騰趠。", "故爲羈縶尚淹蟠，區區課額量登耗。", "辭尊有義不辭卑，屈身斗祿貧親老。", "蒙峰正在岷山西，新月殘時行始到。", "連江地暖春無雪，天際春來氣常早。", "君今此去春已盡，江山綠滿花枝少。", "人生離別難爲情，莫戀異鄉風景好。", "杜鵑忽傍耳邊啼，回首秦川淚斑草。"]'),
('eb536a0a-f4de-453e-a86e-a4f2604a97ca','晉州會上送衛伯紹休官南歸','李復','宋','宋诗','song-poetry','','[]','叔寶風流喜高簡，非意相干以理遣。',320,'全唐诗/poet.song.61000.json','["叔寶風流喜高簡，非意相干以理遣。", "勝日一言能造微，衆許沖情去人遠。", "斑斑氣韵見諸孫，秋水神清驚俗眼。", "追風逸驥自龍來，照夜靈珠須海産。", "結髮讀書棄人事，南上衡廬宿雲巘。", "窮源欲探崑崙深，導河猶恨積石淺。", "十年業白出石壁，錯落青錢宜萬選。", "長衢驤首向雲嘶，千里霜蹄思一展。", "辛勤久未脫羈銜，蹀足蟻封嗟踠踠。", "去冬懷綬到并州，投鞭三月春風滿。", "溪邊行聽踏踏歌，草露忽驚人世短。", "地下枯骨不沽名，便棄華簪獨恨晚。", "尋山高頂白綸巾，寄食但乞青精飯。", "醮壇龍虎夜星寒，海嶠雲霞春洞暖。", "憶昔相逢洛水橋，偶來促坐襄陵宴。", "半生契闊一日逢，互嘆參差不相見。", "新鬢早驚蒲柳衰，舊事重論風雨散。", "我今漸歎暮駸駸，長卿多病嵇康懶。", "肯强塵沙立暝途，逆流理檝厭牽挽。", "待君植杖武夷山，南去尋君任雙趼。"]'),
('de2cb65b-3ad5-49f5-b771-18d7f681854d','趙㠓惠二詩酬以來韵','李復','宋','宋诗','song-poetry','','[]','廣漢諸孫用心苦，亹亹妍譚殊可數。',96,'全唐诗/poet.song.61000.json','["廣漢諸孫用心苦，亹亹妍譚殊可數。", "江南春意滿芳洲，長襲幽香佩蘭杜。", "世緣嚼蠟久無情，喜聞叔起有新聲。", "著書半百懸罄久，躡屩一日雙璧明。", "顧予畫脂已心朽，看君著鞭方力生。", "他時負雲縱六翮，上摶扶搖遊太清。"]'),
('13e1eaad-b55f-4fe7-81aa-486b78b98095','戲酬楊次公','李復','宋','宋诗','song-poetry','','[]','法雲說法元非法，六月洪爐舞飛雪。',224,'全唐诗/poet.song.61000.json','["法雲說法元非法，六月洪爐舞飛雪。", "寶香一瓣下天來，須彌座上金光發。", "三界風雨動雷音，八部人天歸象設。", "昔年關西舊夫子，今日淮南大檀越。", "揚眉師利傾千偈，隠几維摩無一說。", "試開門戶立家風，頓超初地無生滅。", "百川萬折必朝宗，東南到海無分別。", "紫陌紅塵拂面來，鐵壁不容通水泄。", "衆形畢現明鏡靜，浮雲飛蓋秋空澈。", "眼見億萬歸彈指，境落毫釐差永劫。", "野犴不是師子兒，磨了觜頭三尺鐵。", "全湖巨浸一浮漚，結果開花今幾葉。", "昔人卷簾仰天笑，得道固應由慧業。", "一言可盡千語迷，不如靜看水中月。"]'),
('200d458f-aa08-4390-9011-cd7e067a839a','答郎渙','李復','宋','宋诗','song-poetry','','[]','蕭生陸沉自信篤，白首抱關羞碌碌。',64,'全唐诗/poet.song.61000.json','["蕭生陸沉自信篤，白首抱關羞碌碌。", "爾期速售恥干時，行爲徒涉慚濡足。", "鴻飛冥冥凌高秋，南來亦有稻粱謀。", "無言盡戀江湖樂，未肯相隨腐鼠求。"]'),
('4afef08a-c1b4-4851-b8df-51cfef3f99c7','依韵戲答胡沙汲','李復','宋','宋诗','song-poetry','','[]','去年聞君到漳浦，庭樹鵲鳴簾燕舞。',96,'全唐诗/poet.song.61000.json','["去年聞君到漳浦，庭樹鵲鳴簾燕舞。", "今年聞君入戰場，眉間黄氣如蒸霧。", "風霜往回太行道，空解寄聲託飛鳥。", "南城百里不著鞭，輕逐歸雲高縹緲。", "知君苦吟尚如舊，他日相逢更驚瘦。", "明年射策對明光，曾聽人歌扊扅否。"]'),
('2cdb9c9f-8237-4102-a2c3-374824d59363','依韵答胡直孺','李復','宋','宋诗','song-poetry','','[]','東蒙野老工何拙，刻楮三年不成葉。',160,'全唐诗/poet.song.61000.json','["東蒙野老工何拙，刻楮三年不成葉。", "迂途獨往自名愚，舉足常嫌投險捷。", "忽然開口向時人，機士笑驚多脫頰。", "半生長餓首慵回，厭見糟醨能腐脅。", "惟與孤雲靜往還，胎仙戲舞琴三疊。", "江南墨客貌雖癯，戰勝當前輕勇俠。", "潤身不貯世間珍，別有驪珠光滿篋。", "北游一見潜魄動，雙目爛爛巖光曄。", "新詩幾幅起秋風，使我靜觀但嚅囁。", "相逢便欲苦死留，恐跨飛鯨動歸鬣。"]'),
('aeecd37e-662d-4f2d-a1bd-71e663e5c87b','答李師載','李復','宋','宋诗','song-poetry','','[]','早歲賢關初闖首，五色長虹出君手。',320,'全唐诗/poet.song.61000.json','["早歲賢關初闖首，五色長虹出君手。", "孤坐傲兀若老羆，滿場輸伏甘居後。", "巨榜清曉揭宮牆，名姓喧傳天下口。", "天子未見已先知，雲路風生看馳驟。", "一官纔得墜驚波，顛頓衝風嗟莫救。", "冥冥陰禍鬼發機，羅網恢恢疏不漏。", "幽囚束縛落空山，蟬腹龜腸餓荒藪。", "黄雛乳鷇飛刺天，病翼傷垂自看醜。", "男兒性命絕可憐，萬事填臆難出口。", "天高地遠無消息，日月回環歲閏九。", "情之所鍾正在我，幾度寄音藏客袖。", "辟書抆拭召從軍，寒出綈袍憐范叟。", "孤童匹馬渡盟津，白髮青衫亦何有。", "相逢握手話契闊，懷昔感今嗟嘆久。", "巨幹堅姿老不衰，霜雪蒼松性依舊。", "騏驥不合駕鼓車，鏌鋣鬰鬰猶衝斗。", "惟君與我同襟期，爲君掃榻開東牖。", "相對惆悵懷抱惡，聊且撥置共尊酒。", "天地氤氳何事無，白雲須臾變蒼狗。", "冥心委順觀我生，任有垂楊生左肘。"]'),
('dd9445e7-4f70-4cc9-a2ff-7ad133d47560','依來韵答謝教授敞還鄙藁語','李復','宋','宋诗','song-poetry','','[]','老便收氣自暖腹，厭見先漿動人目。',96,'全唐诗/poet.song.61000.json','["老便收氣自暖腹，厭見先漿動人目。", "乘間縈思似秋蟲，終日牽絲不成幅。", "廣文嗜好背時利，妙律開雲發孤竹。", "已驚垂蚓得鯨歸，更愧並貂持狗續。", "可嗟按劍夜投珠，何異剖巖朝泣玉。", "昨宵月暗風淒淒，燈陰神物來聽讀。"]'),
('7c3d9e53-e924-42b7-82df-83eb10f7b32d','調李教授','李復','宋','宋诗','song-poetry','','[]','君不見屈平放逐南辭楚，顦顇行吟羣江浦。',358,'全唐诗/poet.song.61000.json','["君不見屈平放逐南辭楚，顦顇行吟羣江浦。", "一聞鼓枻笑獨醒，搔首低回愧漁父。", "又不見淵明彭澤投簪纓，退隠衡門依五柳。", "凝塵滿匣不鳴絃，頭上接䍦親漉酒。", "爾後寥寥幾百年，醉鄉途路隔雲烟。", "空看青鑑悲毛髮，不向芳尊問聖賢。", "天邊酒星歎寂寞，太白相逢發嘲謔。", "悲風苦霧動星愁，欲惱寒蟾對杯酌。", "舞袖低回雙鶂退，曾憶婆娑拂仙桂。", "雲間月下兩茫然，牢落江山無勝氣。", "星星今古夢中身，巧力爭求身後名。", "衛鶴莫矜軒冕貴，魯鶋曾見鼓鐘驚。", "園林昨夜春風滿，待得花開春已半。", "流鶑才怨曉紅飛，布穀已催秋種晚。", "藻間養子碧魚肥，石上拳牙紫蕨齊。", "柳下驚逢金騕褭，花深聞唱白銅鞮。", "須知向眼光陰好，忍困饑腸守枯槁。", "明年雖見舊花開，却恐花枝笑人老。", "終南紫翠倚天高，渭水東流入海潮。", "水去不回山不改，茫茫曾歷幾昏朝。", "君看曠達是劉伶，寵辱冥心過一生。", "枕麴潄醪方自得，任從耳畔發雷霆。"]'),
('d34add76-d873-4b85-8523-c576659d4cab','戲謝漕食豆粥','李復','宋','宋诗','song-poetry','','[]','石泉清甘出山麓，瓦釜貯泉烹豆粥。',294,'全唐诗/poet.song.61000.json','["石泉清甘出山麓，瓦釜貯泉烹豆粥。", "太行苦霧朝塞門，相與持杯煖寒腹。", "集仙學士著繡衣，瑞節前驅光照玉。", "入境風生三十州，高廩臨邊溢紅粟。", "公臺深靜兵衛嚴，部吏趨承冠履肅。", "剪毛胡羊小耳肥，列甕釀香浮螘綠。", "盡嫌豪侈徹豐俎，坐刻黳煤溫凍足。", "擁爐招客學僧禪，爭聽敲魚醒睡目。", "太師論詩歌蟋蟀，千載遺音流晉曲。", "何曾方丈裂餠多，武子琉璃蒸乳熟。", "只知齒頰快芳羶，豈料年齡愁嗜欲。", "但能舉鉢厭饑腸，便覺古風親土俗。", "君不見錦帳匝地石季倫，又不見冰澌渡河劉文叔。", "竈間燎濕困滹沱，席上爭先出金谷。", "豈惟暫飽濟艱難，猶貴速成勝珠玉。", "昔人不願五侯鯖，今我何知九鼎肉。", "杜陵春晚把鋤歸，常喜朝盤堆苜蓿。", "莫嗟粗糲百年飧，且免禍盈鬼瞰屋。"]'),
('bc642ce5-7dc7-4664-8376-24c101aba1b5','題謝子高易義','李復','宋','宋诗','song-poetry','','[]','東風吹園未曾出，隠几潜心讀大易。',64,'全唐诗/poet.song.61000.json','["東風吹園未曾出，隠几潜心讀大易。", "低頭不知客入門，但見開編時點筆。", "天開地闢日月明，四時變化萬物成。", "伏羲畫卦混沌死，紛紛智巧彫元精。"]'),
('159afee4-9c90-44ff-85aa-4557f5974000','梁山','李復','宋','宋诗','song-poetry','','[]','梁山蒼蒼寒日低，武皇昔年留羽旂。',64,'全唐诗/poet.song.61000.json','["梁山蒼蒼寒日低，武皇昔年留羽旂。", "層宮突兀天上出，舉手欲引仙人衣。", "仙人不來怨空老，索莫時從東海歸。", "銅盤千里渡漳水，茂陵草荒秋螢飛。"]'),
('c816cd60-0c46-47ea-a9d7-9a401b80b064','野蠶','李復','宋','宋诗','song-poetry','','[]','野蠶緣桑自成繭，羣兒採繭殘桑枝。',64,'全唐诗/poet.song.61000.json','["野蠶緣桑自成繭，羣兒採繭殘桑枝。", "明年家蠶黑蟻出，田中桑死蠶忍饑。", "野繭更採不滿筥，家蟻歲生無盡時。", "翁乎驅兒無殘桑，葉長蠶成長有絲。"]'),
('1c34681a-d32a-4dd8-9e03-e5ac12ca3ab4','酬愍長老退院作','李復','宋','宋诗','song-poetry','','[]','掣電機鋒不容擬，已逐驚飈落千里。',64,'全唐诗/poet.song.61000.json','["掣電機鋒不容擬，已逐驚飈落千里。", "人生萬事孰爲大，世上百年能有幾。", "餘蔬殘肉豈能飽，包束乾坤歸一指。", "今朝齋鉢掛空牆，山前山後松風起。"]'),
('2b1b260c-b1a6-488d-9b98-e640044f11f8','山寺禪者','李復','宋','宋诗','song-poetry','','[]','敗屋數間叢萬笴，虎豹到庭門下鏁。',64,'全唐诗/poet.song.61000.json','["敗屋數間叢萬笴，虎豹到庭門下鏁。", "自種石田一飯足，與語略能言璨可。", "天昏霏霏小雪墮，拾薪吹爐勸親火。", "葉藏巨栗大如拳，撥灰炮栗來饋我。"]'),
('705a430f-c6a7-4afa-939a-50ade6ed7d41','過萬泉縣','李復','宋','宋诗','song-poetry','','[]','邑屋連山麓，蕭條去路斜。',48,'全唐诗/poet.song.61000.json','["邑屋連山麓，蕭條去路斜。", "鹵田無美井，旱港足飛沙。", "逃室多欹棟，殘林有斷槎。", "荒墟人不見，牆角自開花。"]'),
('a759453f-dd33-4868-a062-660ee98e8d25','自壽安之長水','李復','宋','宋诗','song-poetry','','[]','夜宿錦屏下，曉行伊水長。',48,'全唐诗/poet.song.61000.json','["夜宿錦屏下，曉行伊水長。", "露寒荷葉紫，秋晚稻花香。", "女几仙風斷，連昌輦路荒。", "二年渾作客，山驛過重陽。"]'),
('e27aaf6f-6c62-463c-a3b2-6a96331700cc','白沙驛','李復','宋','宋诗','song-poetry','','[]','轉側下層巔，江流出斷壖。',48,'全唐诗/poet.song.61000.json','["轉側下層巔，江流出斷壖。", "寒雲生古戍，野店引山泉。", "雨暗疏茅濕，堂危倒石懸。", "去程無限險，心落渭城邊。"]'),
('fa6d3bdf-2001-4036-bf03-099950cc547e','再過方山驛','李復','宋','宋诗','song-poetry','','[]','春過方山驛，依然柳色新。',48,'全唐诗/poet.song.61000.json','["春過方山驛，依然柳色新。", "昔遊嘗弭節，舊記已埋塵。", "往歲讎書客，新恩守土臣。", "南來心不競，時羨北歸人。"]'),
('cc3ea27f-08a8-40bf-a116-93deaaacaf46','自吳嶽歸','李復','宋','宋诗','song-poetry','','[]','鳴鳳岡邊路，秋風動夕嵐。',48,'全唐诗/poet.song.61000.json','["鳴鳳岡邊路，秋風動夕嵐。", "閒雲依絕壁，獨鳥下空潭。", "疇昔經行慣，重來委曲諳。", "試尋遺墨在，投策訪僧龕。"]'),
('911404b7-6631-43c1-9140-f8ec7d9b0f63','聖容寺','李復','宋','宋诗','song-poetry','','[]','應感雖無地，棲真自有緣。',48,'全唐诗/poet.song.61000.json','["應感雖無地，棲真自有緣。", "寶坊開泗水，香露散秦川。", "草亂遺庵廢，珠明舊相圓。", "豐碑傳異事，細字刻誠懸。"]'),
('9ead33ff-9bd6-41c9-9fd0-ed44370fff34','遊寶雨寺','李復','宋','宋诗','song-poetry','','[]','信步出江𦪽，庭松立兩龍。',48,'全唐诗/poet.song.61000.json','["信步出江𦪽，庭松立兩龍。", "晨僧自汲水，高閣忽鳴鐘。", "浄飯多山蜜，新羹供野葑。", "傳聞初祖錫，猶掛最西峰。"]'),
('55c1bac9-a329-4557-8fde-e6c5fc37af1e','重遊寶雨寺','李復','宋','宋诗','song-poetry','','[]','題墨暗頹垣，崢嶸歲序遷。',48,'全唐诗/poet.song.61000.json','["題墨暗頹垣，崢嶸歲序遷。", "舊僧霜髮滿，老柏瘦根穿。", "客少庭多草，村饑供乏錢。", "重來猶晚暑，清盥挹寒泉。"]'),
('2aa03b6a-056d-4ea1-9b66-798a9c4b1617','興慈寺觀君俞舊題','李復','宋','宋诗','song-poetry','','[]','松院前年到，同君共五人。',48,'全唐诗/poet.song.61000.json','["松院前年到，同君共五人。", "今來觀舊蹟，君已是前身。", "遽掩千秋夜，空傷兩歲春。", "向風無可語，淚灑壁間塵。"]'),
('89d51b0b-18d4-4503-bba3-da696268508c','峽州渡江入寺  其一','李復','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','雪暗離秦地，春歸入楚邦。',48,'全唐诗/poet.song.61000.json','["雪暗離秦地，春歸入楚邦。", "平生憐匹馬，將老渡長江。", "解纜辭亭樹，中流見寺窗。", "舟人喜風色，略得寸心降。"]'),
('c597aeff-42c3-47f0-9c3f-99153f3a987c','峽州渡江入寺  其二','李復','宋','宋诗','song-poetry','','[]','江上招提古，蕭疏對郡城。',48,'全唐诗/poet.song.61000.json','["江上招提古，蕭疏對郡城。", "延賓竹榻靜，過雨石堂清。", "齋接荆州供，題多蜀士名。", "老僧飛錫倦，歸坐聽江聲。"]'),
('28031dd5-b926-4933-be08-f52e442fadcc','興德寺逢張居士','李復','宋','宋诗','song-poetry','','[]','掃葉開新徑，携缾汲曉泉。',48,'全唐诗/poet.song.61000.json','["掃葉開新徑，携缾汲曉泉。", "偶逢巖下客，來問室中禪。", "鳥去空還寂，薪窮火自傳。", "四方行已徧，歸老舊林邊。"]'),
('57669cb1-86e5-4e75-b788-78d845409c4b','登青龍寺','李復','宋','宋诗','song-poetry','','[]','疏爽巖邊寺，秋登更晚晴。',48,'全唐诗/poet.song.61000.json','["疏爽巖邊寺，秋登更晚晴。", "連岡橫野斷，遠水隔林明。", "廢井餘荒甃，殘碑有舊名。", "幾經兵火劫，禾黍徧新耕。"]'),
('8d55b228-b61b-4c57-ba9d-5d9de859442f','遊觀音院','李復','宋','宋诗','song-poetry','','[]','秋林晴簇簇，野竹靜娟娟。',48,'全唐诗/poet.song.61000.json','["秋林晴簇簇，野竹靜娟娟。", "臺殿橫高絕，山河滿大千。", "莫論金屑貴，且契布毛緣。", "試問庭前柏，干戈動幾年。"]'),
('640fe4ce-3fbc-4868-95d2-0807e052ea1b','慜禪師','李復','宋','宋诗','song-poetry','','[]','湘南衡岳水，分得一支來。',48,'全唐诗/poet.song.61000.json','["湘南衡岳水，分得一支來。", "宴坐秋峰靜，澄心夜月開。", "清風生虎錫，驚電護龍杯。", "昨夜飛香動，山神禮寶臺。"]'),
('18d5ea42-ce4e-48a1-9ec3-09361da887d8','新羅寺唐有新羅僧咒草愈疾卵塔今在閒來因題','李復','宋','宋诗','song-poetry','','[]','斷石傳遺事，唐年刻永徽。',48,'全唐诗/poet.song.61000.json','["斷石傳遺事，唐年刻永徽。", "庭荒靈草盡，塔壞禮僧稀。", "古殿含凉氣，空堂照夕暉。", "獨來人不問，行聽暮鐘歸。"]'),
('dd73f367-a4d3-4500-9af9-e3067fb0faa8','甘羅廟','李復','宋','宋诗','song-poetry','','[]','縱橫爭擅勢，之子獨尊秦。',48,'全唐诗/poet.song.61000.json','["縱橫爭擅勢，之子獨尊秦。", "弱齒能專國，奇謀不借人。", "拳峰凌九仞，勺粒動千鈞。", "過客瞻遺構，臨溪野草春。"]'),
('e2fd0bc1-1d17-4fd3-af42-4ec055293291','九日過介之推廟','李復','宋','宋诗','song-poetry','','[]','荒祠久零落，秋日故山阿。',48,'全唐诗/poet.song.61000.json','["荒祠久零落，秋日故山阿。", "椒菊持新奠，龍蛇憶舊歌。", "論功嗟晉粟，流怨動汾波。", "千歲遺靈在，鄉民禁火多。"]'),
('a1e68dae-0a4e-4d25-a7b6-3b3c652facd7','清明日北園亭作','李復','宋','宋诗','song-poetry','','[]','錦亂筠遺籜，青浮水結衣。',48,'全唐诗/poet.song.61000.json','["錦亂筠遺籜，青浮水結衣。", "乳鳩呼却逐，鬭雀墮還飛。", "客過殘樽在，年侵冷食稀。", "去年今日意，渡峽雨霏霏。"]'),
('67e502ec-1c1d-43e2-b31a-015c84e4680b','春日北園早起','李復','宋','宋诗','song-poetry','','[]','雨斷雲猶在，風回氣已明。',48,'全唐诗/poet.song.61000.json','["雨斷雲猶在，風回氣已明。", "林花含宿潤，露沼散餘清。", "喜靜心常澹，居閒意寡營。", "流光隨轉盼，所向達吾生。"]'),
('cd0ff60e-14b4-43cb-a939-13f0a6b6703e','秋晚北園','李復','宋','宋诗','song-poetry','','[]','野興乘俄頃，扶行錦竹長。',48,'全唐诗/poet.song.61000.json','["野興乘俄頃，扶行錦竹長。", "碎蔬殘宿圃，亂葉散寒塘。", "地僻柴門靜，人稀草逕荒。", "曉霜今幾見，猶有菊花黄。"]'),
('60214af2-11b1-4bf4-a793-ef8ce4ff0df1','晨起東軒','李復','宋','宋诗','song-poetry','','[]','影暗纔分竹，煙低正滿簷。',48,'全唐诗/poet.song.61000.json','["影暗纔分竹，煙低正滿簷。", "雨斜侵藥裹，風過亂書籤。", "篆滅香猶在，塵昏硯未添。", "靜中時有興，著論不爲潛。"]'),
('f2927534-5877-4c65-8fbf-d38097d0fd46','曉至西郊','李復','宋','宋诗','song-poetry','','[]','墟落隋城外，西郊路可尋。',48,'全唐诗/poet.song.61000.json','["墟落隋城外，西郊路可尋。", "带霜殘黍短，過雨舊溪深。", "近港來迎犬，荒籬散宿禽。", "鄰翁邀具餉，煙火動疏林。"]'),
('e7d5bce3-66d5-4adb-b149-398a2bd99f69','江晦叔邀遊吳氏園爲約月餘始能一往吳生某求留題遂書石上','李復','宋','宋诗','song-poetry','','[]','竹屋橫虛舫，松屏展翠帆。',48,'全唐诗/poet.song.61000.json','["竹屋橫虛舫，松屏展翠帆。", "柳條晴後弱，花態曉來嚴。", "樂意難逢暇，清游久嘆淹。", "主人求客語，乘醉寫雲巖。"]'),
('40b6a48d-baae-450c-828d-2d29d81b560f','出村','李復','宋','宋诗','song-poetry','','[]','風露已淒淒，郊原百草腓。',48,'全唐诗/poet.song.61000.json','["風露已淒淒，郊原百草腓。", "負樵山木下，轉粟戍人歸。", "野曠羊牛遠，場荒鳥雀稀。", "南山經月雨，猶有亂雲飛。"]'),
('597883a8-a824-4290-bb51-46485ca5ad4b','西溪酬孫倚李珪二同年依韵','李復','宋','宋诗','song-poetry','','[]','水部張員外，中書白舍人。',48,'全唐诗/poet.song.61000.json','["水部張員外，中書白舍人。", "曾聞三絕句，同賞曲江春。", "且逐追隨舊，休悲老大身。", "花今千樹發，有底不來因。"]'),
('1aeef80a-d7bd-4638-8f5d-7eced3c6b350','病起','李復','宋','宋诗','song-poetry','','[]','病起秋將晚，高林葉半黄。',48,'全唐诗/poet.song.61000.json','["病起秋將晚，高林葉半黄。", "梳驚殘髮少，瘦覺舊衣長。", "尚怯扶藜杖，猶勤檢藥囊。", "喜拋烏帽去，曝背卧朝陽。"]'),
('d7f48f00-7df3-408a-bc8b-7603e6235b10','雲巖','李復','宋','宋诗','song-poetry','','[]','徑轉隨高下，欹危亂石中。',48,'全唐诗/poet.song.61000.json','["徑轉隨高下，欹危亂石中。", "寒巖朝起霧，空谷夜生風。", "疏竹連殘屋，驚麏逐斷蓬。", "求棲問茅舍，非淺愛田翁。"]'),
('8dc15e23-bada-48ec-9769-b314c5bd92b9','夜意','李復','宋','宋诗','song-poetry','','[]','山霧連城白，虛庭待月生。',48,'全唐诗/poet.song.61000.json','["山霧連城白，虛庭待月生。", "雨餘秋葉潤，露重葛衣輕。", "陰壁鳴蟲澀，風枝宿鳥驚。", "淹留禾黍興，悵望故園情。"]'),
('c0e61de0-85ca-4418-9650-6c7f86bee95d','和楚倅懷歸','李復','宋','宋诗','song-poetry','','[]','雨斷他鄉夢，風沉故國音。',48,'全唐诗/poet.song.61000.json','["雨斷他鄉夢，風沉故國音。", "山城黄葉落，蘭畹白雲深。", "寄食衣裘敝，憑鞍歲月侵。", "流塵昏斗劍，萬里愧初心。"]'),
('fdbdc81d-54ab-4a03-a1df-99ffc03e32f2','留客','李復','宋','宋诗','song-poetry','','[]','秋堂留曉客，密雨擁柴門。',48,'全唐诗/poet.song.61000.json','["秋堂留曉客，密雨擁柴門。", "石鼎燃松葉，山樽捧竹根。", "買魚催網急，嘗栗破皺繁。", "村黑歸泥滑，移床醉夜軒。"]'),
('6b9bc7f9-ab42-48e4-937a-455369151673','送客至黎城','李復','宋','宋诗','song-poetry','','[]','二年三送客，空復往來情。',48,'全唐诗/poet.song.61000.json','["二年三送客，空復往來情。", "野色浩無主，秋風暮獨行。", "山連長狄國，水過鄴王城。", "試問式微詠，猶歌怨衛聲。"]'),
('0e5acb3e-8aa9-4c3f-ab60-66fd2a713cd8','答徐耘朝散','李復','宋','宋诗','song-poetry','','[]','昔年汾水上，曾遇海南翁。',48,'全唐诗/poet.song.61000.json','["昔年汾水上，曾遇海南翁。", "欲問三山路，先知一溉功。", "萬紛銷寂默，一氣抱沖融。", "更約丹砂訣，他時訪葛洪。"]'),
('7ea501fb-0482-41f0-b524-ba9f4753f032','催發諸邑民兵至朝邑縣官未至遂宿其驛','李復','宋','宋诗','song-poetry','','[]','羸馬趨程晚，衝風雪滿衣。',48,'全唐诗/poet.song.61000.json','["羸馬趨程晚，衝風雪滿衣。", "城荒更鼓暗，市冷吏民稀。", "烏壘兵初起，河橋客未歸。", "北行殊未已，捧檄寸心違。"]'),
('b43e3153-a324-475f-a095-fdef5c4f7e15','月','李復','宋','宋诗','song-poetry','','[]','玉露漳川月，相看幾上弦。',48,'全唐诗/poet.song.61000.json','["玉露漳川月，相看幾上弦。", "氣橫秋浦白，輪带女城偏。", "半魄蟾猶隠，分枝桂未圓。", "雲衢誰可到，柅轍駐流年。"]'),
('589ec10e-a3e1-4867-be7d-f28075886030','竹','李復','宋','宋诗','song-poetry','','[]','園竹三年種，今春綠始稠。',48,'全唐诗/poet.song.61000.json','["園竹三年種，今春綠始稠。", "未知能却暑，但愛不悲秋。", "影補頹垣缺，枝多暮翼留。", "近因開小徑，時有客相投。"]'),
('21d473cb-18a3-4285-8a14-a291c57fe396','蝦蟆碚水','李復','宋','宋诗','song-poetry','','[]','泉出蝦蟆碚，名高陸羽經。',48,'全唐诗/poet.song.61000.json','["泉出蝦蟆碚，名高陸羽經。", "細分寒乳白，散落曉巖青。", "歸客停松檝，臨江貯蘚缾。", "神仙雲母液，烹飲養頹齡。"]'),
('0633a0fc-5e4f-4a8d-bf19-a172375ed688','江公著舉棋無偶忽敗于予有詩戲用其韵','李復','宋','宋诗','song-poetry','','[]','忘暑憐楸局，含風愛竹窗。',48,'全唐诗/poet.song.61000.json','["忘暑憐楸局，含風愛竹窗。", "料兵聞舊怯，築壘納新降。", "舟渡焚秦水，兵分泣楚江。", "君知猿臂將，國譽世無雙。"]'),
('7a06558d-6792-48e2-8a5b-cee6e5837e8c','觀山郊閱武  其一','李復','宋','宋诗','song-poetry','','[]','疊錦聯貂帽，飛光散羽旗。',48,'全唐诗/poet.song.61000.json','["疊錦聯貂帽，飛光散羽旗。", "虎文雙箙重，金粟小鞦垂。", "望鶻翻雲沒，呼鷹駐馬遲。", "更聞傳令去，先促羽林兒。"]'),
('5ed10d89-9662-4816-bf26-3d83cec1e964','觀山郊閱武  其二','李復','宋','宋诗','song-poetry','','[]','榆落山連壘，川平水带城。',48,'全唐诗/poet.song.61000.json','["榆落山連壘，川平水带城。", "張兵圖野曠，吹角怨秋清。", "移帳高雲動，開鐔碧海驚。", "歸風回勝氣，西北埽欃槍。"]'),
('be83e23c-f1dc-424c-9eef-d6af025f70a6','晚客狎至應接不一或有疑者作此詩示謝敞教授','李復','宋','宋诗','song-poetry','','[]','岸幘扶藜杖，移床傍晚林。',48,'全唐诗/poet.song.61000.json','["岸幘扶藜杖，移床傍晚林。", "形骸猶是累，語默更何心。", "望外浮雲薄，凉生古汲深。", "自憐多懶僻，塵色悶孤琴。"]'),
('d59da380-2e41-4d51-a713-cadb73673641','答分守魏大夫','李復','宋','宋诗','song-poetry','','[]','坐憶金臺別，于今十四年。',48,'全唐诗/poet.song.61000.json','["坐憶金臺別，于今十四年。", "新恩乘五馬，北首渡三川。", "縣急均鹺戶，邊停助餉錢。", "晉民衣食薄，移柱聽調絃。"]'),
('8e8e6004-4adc-4641-bbae-92d835ce227b','舟行出峽先寄峽州太守榮子邕同年','李復','宋','宋诗','song-poetry','','[]','幾日方離峽，舟浮任所之。',48,'全唐诗/poet.song.61000.json','["幾日方離峽，舟浮任所之。", "江開平岸闊，天遠去雲遲。", "心折襟分後，身存痛定時。", "晚亭登至喜，歸信半年期。"]'),
('f2babbd2-1537-4d4e-9083-055111d82b75','依韵酬趙令之','李復','宋','宋诗','song-poetry','','[]','相逢三十載，少恥事驍雄。',48,'全唐诗/poet.song.61000.json','["相逢三十載，少恥事驍雄。", "封植思嘉樹，交遊嘆谷風。", "雲山輪迹少，葵藿歲時充。", "冉冉秋還暮，霜寒泣候蟲。"]'),
('3220e8c2-cd24-40c2-92b0-05c9081a48bf','呂子固置會有詩張芸叟邀予席上依韵和','李復','宋','宋诗','song-poetry','','[]','故國歸來晚，相逢共老年。',48,'全唐诗/poet.song.61000.json','["故國歸來晚，相逢共老年。", "聊從浮白飲，莫擬畔牢篇。", "花近紅侵坐，槐新綠媚天。", "還丹消息斷，無惜放杯傳。"]'),
('0bd3f4bb-ff13-4859-a1f0-546c84b2edc8','還王天倪詩卷','李復','宋','宋诗','song-poetry','','[]','素尚躋遐曠，平生厭淺浮。',48,'全唐诗/poet.song.61000.json','["素尚躋遐曠，平生厭淺浮。", "錦囊刀尺古，江渚蕙荃幽。", "翹首孤雲遠，疏林暮葉秋。", "十年人不問，寂默老荒丘。"]'),
('7e9d3aa5-db19-4a4f-96cb-8202a65ea975','酬喬世材推官','李復','宋','宋诗','song-poetry','','[]','地僻人來少，公庭吏散時。',48,'全唐诗/poet.song.61000.json','["地僻人來少，公庭吏散時。", "亂蟬號晚日，凉葉下高枝。", "仰羨知歸鳥，先書寄遠詩。", "只應今夜月，偏解照相思。"]'),
('444a9336-3369-4c3c-ace2-e6e72992feec','答推官李珪','李復','宋','宋诗','song-poetry','','[]','吾族柯條茂，人稱孝子賢。',48,'全唐诗/poet.song.61000.json','["吾族柯條茂，人稱孝子賢。", "新游思我共，舊學欲誰傳。", "每愛鸞鴻志，徒嗟犬馬年。", "青雲如得路，驤首看揚鞭。"]'),
('fd00aca8-b942-4367-9a21-e433dd57905f','和張裁推官遊湖','李復','宋','宋诗','song-poetry','','[]','閒弄香蘭楫，斜開紫綺襟。',48,'全唐诗/poet.song.61000.json','["閒弄香蘭楫，斜開紫綺襟。", "回風收雨脚，靜月到湖心。", "高柳留疏翠，前山動夕陰。", "興來行處愜，樂罷感還深。"]'),
('68489478-1c18-48d8-b67d-b8b7e1503e78','寄延帥趙龍圖卨','李復','宋','宋诗','song-poetry','','[]','瘴嶺有毒霧，鳴沙無美田。',48,'全唐诗/poet.song.61000.json','["瘴嶺有毒霧，鳴沙無美田。", "乾坤滋孕毓，山海限腥羶。", "干舞旄星落，弓櫜譯舌傳。", "但能思上策，何必勒燕然。"]'),
('abd61bae-261a-4905-9ef9-d5e5c4d4094f','戲答山人趙穎憶山居','李復','宋','宋诗','song-poetry','','[]','綠髮年來改，相看憶去頻。',48,'全唐诗/poet.song.61000.json','["綠髮年來改，相看憶去頻。", "青山不厭客，黄屨自迷塵。", "耳冷泉聲淡，松殘藥竈貧。", "白雲他日見，應問世間春。"]'),
('1ba62813-e043-4feb-b41f-6dba08400418','新蟬','李復','宋','宋诗','song-poetry','','[]','病耳不堪聽，仍愁露下時。',48,'全唐诗/poet.song.61000.json','["病耳不堪聽，仍愁露下時。", "纔能升木杪，便解入雲吹。", "漫有真仙契，猶多風樹悲。", "美陰如可託，後患亦須知。"]'),
('0224852b-7821-4448-a7f8-2f2bb955bb4d','太學試駕幸後苑觀穀','李復','宋','宋诗','song-poetry','','[]','禁籞開清曉，宸心喜豫遊。',72,'全唐诗/poet.song.61000.json','["禁籞開清曉，宸心喜豫遊。", "鳴鸞迎霽日，嘉穀茂高秋。", "秀穎晴光爛，雕輿睿鑒留。", "晨光照金粟，喜色動珠旒。", "綠野勤農力，青編藹帝猷。", "周人豳頌在，王業起耕疇。"]'),
('df5764dd-63da-4e10-a3d6-644a9597fbe1','依韵酬沈仍長官惠葡萄','李復','宋','宋诗','song-poetry','','[]','異果乘秋熟，分來道路長。',168,'全唐诗/poet.song.61000.json','["異果乘秋熟，分來道路長。", "緘封湘篋重，題詠剡藤光。", "氣蓄西河潤，山圍大谷凉。", "龍鬚初引水，馬乳晚經霜。", "衣薄輕鉛粉，包圓小紫囊。", "膏腴凝紺液，甘酢溢雲漿。", "蔗浥含餘潤，醅浮带舊香。", "藥經難彷彿，畫筆漫形相。", "涇洛宜秦土，汾嵐利晉鄉。", "鱗差分萬葉，珠實綴千房。", "楚瑞慚萍實，江奴笑橘黄。", "破酲生靜爽，滌熱慰新嘗。", "契闊初心在，提携遠意將。", "茂陵遺客老，痟病證仙方。"]'),
('398faf26-1308-4797-b2fb-a6fc374aff99','垂拱殿賜對蒙恩入省','李復','宋','宋诗','song-poetry','','[]','黼座親瞻咫尺威，恭承天語慰衰遲。',64,'全唐诗/poet.song.61000.json','["黼座親瞻咫尺威，恭承天語慰衰遲。", "錦書殿陛初傳賜，白髮郎潜且漫爲。", "九日重分番直夜，六參便赴早朝時。", "自知麋鹿難馴習，深媿鵷鸞接羽儀。"]'),
('77daacac-d687-4b9f-912f-8583446ee736','雪中早朝','李復','宋','宋诗','song-poetry','','[]','正衙冠劍拱星齊，清曉天花舞御墀。',64,'全唐诗/poet.song.61000.json','["正衙冠劍拱星齊，清曉天花舞御墀。", "玉殿影深分扇早，金爐煙濕散香遲。", "雲低含潤侵珠絡，風亂飛花拂羽旗。", "班退便疑凡骨變，自驚身得到瑶池。"]'),
('d322692c-3a7e-43ac-ad41-c48e9bfc3745','會聖宮朝謁','李復','宋','宋诗','song-poetry','','[]','七葉丹成不可攀，蘂珠宮殿翠微間。',64,'全唐诗/poet.song.61000.json','["七葉丹成不可攀，蘂珠宮殿翠微間。", "千年空怨龍髯斷，億世曾聞寶筴還。", "宮女祠歸朝路靜，嶽神綦退曉風閒。", "五雲高宴蟠桃罷，鶴馭時應會此山。"]'),
('7c918ebe-0e96-4ec3-8b52-f31c4953ca2a','省中寓直次劉巨濟職方韵兼示祠部張臺卿','李復','宋','宋诗','song-poetry','','[]','鋃鐺司鑰禁門重，寓直高秋此夜同。',64,'全唐诗/poet.song.61000.json','["鋃鐺司鑰禁門重，寓直高秋此夜同。", "樓外歸雲迎霽月，宮中傳漏带疏風。", "衰迂豈合參新論，俊少何堪接野翁。", "華省分曹占列宿，經時飽食愧無功。"]'),
('fa201b50-87a7-41f5-bda5-ba09b8dc0f1c','再任提點雲臺觀','李復','宋','宋诗','song-poetry','','[]','天光垂碧抱瓊臺，蘂殿珠宮對嶽開。',64,'全唐诗/poet.song.61000.json','["天光垂碧抱瓊臺，蘂殿珠宮對嶽開。", "峽口巴猿初別去，海東遼鶴又飛來。", "三生難轉靈源靜，六歲空驚迅景催。", "欲挹蓮花峰頂水，普將甘冽浄浮埃。"]'),
('a31524ac-5924-49c4-b09f-8512a810dfdf','守鄭易陳方及境改信都過大名書呈呂太尉','李復','宋','宋诗','song-poetry','','[]','淮陽閉閤欲偷閒，新捧除書墨未乾。',64,'全唐诗/poet.song.61000.json','["淮陽閉閤欲偷閒，新捧除書墨未乾。", "五日御風方假翼，兩河試郡別移官。", "生緣有定隨流易，世事無端用力難。", "今日得陪門下客，一枝容息便心安。"]'),
('87249439-06f8-4adf-be9e-adaf60444bf1','京西初歸作','李復','宋','宋诗','song-poetry','','[]','少年輕喜欲憑虛，誤落塵中二紀餘。',64,'全唐诗/poet.song.61000.json','["少年輕喜欲憑虛，誤落塵中二紀餘。", "生事蕭條寒葉散，故人寥落曉星疏。", "殘骸已脫風波晚，清枕方回醉夢初。", "却覓漁蓑尋舊釣，一溪煙雨伴春鋤。"]'),
('aff1946f-5eb7-4ab5-8132-79308deeb6de','乞罷未報承延晉秦慶皆惠書','李復','宋','宋诗','song-poetry','','[]','東西南北閱光陰，邊意蕭條老境侵。',64,'全唐诗/poet.song.61000.json','["東西南北閱光陰，邊意蕭條老境侵。", "四府飛書慚過譽，數疇廢壤媿初心。", "傾懷敢望時情合，論事須思後計深。", "髀肉久消筋力倦，但能操筆謝知音。"]'),
('71cdce3d-5788-4d7a-9f84-58d2c4d8fe3d','九月十三日夜偶書','李復','宋','宋诗','song-poetry','','[]','林葉紛紛已半凋，陰雲不放眼周遭。',64,'全唐诗/poet.song.61000.json','["林葉紛紛已半凋，陰雲不放眼周遭。", "稍知風逐青娥動，更覺天騰北海高。", "萬里無心思假翼，百年多事喜持螯。", "山前沙井通幽圃，待得春深弄桔槹。"]'),
('86b91b65-3123-4e14-9419-8cf5dec7c15b','熙州再乞罷','李復','宋','宋诗','song-poetry','','[]','末途潦倒媿知音，幕府重來歲月侵。',64,'全唐诗/poet.song.61000.json','["末途潦倒媿知音，幕府重來歲月侵。", "狂見請纓憎往策，禮容著帽感虛襟。", "白頭久厭戎衣窄，黧面空嗟寒色深。", "東望故山今有約，清秋應得訪雲林。"]'),
('d03e46b1-bdde-4294-bf19-36bef5a9325d','乙卯七月十六日忽報罷任','李復','宋','宋诗','song-poetry','','[]','掩關忽報被刑書，自笑無堪涉世疏。',64,'全唐诗/poet.song.61000.json','["掩關忽報被刑書，自笑無堪涉世疏。", "白晝曾聞驚市虎，殘灰今見禍池魚。", "莫嗟靜影逢沙矢，猶恐餘猜及鼠蔬。", "逆境自觀還自喜，片心無礙一舟虛。"]'),
('71e0112e-35bb-43ac-9fb2-b06043122517','上延帥沈內翰  其一','李復','宋','宋诗','song-poetry','','[]','昔年圖史守巖幽，每仰高文動斗牛。',64,'全唐诗/poet.song.61000.json','["昔年圖史守巖幽，每仰高文動斗牛。", "千里來登徐孺榻，一時如上李膺舟。", "激昂囊穎思先出，慰藉泥塗欲晚收。", "曾笑王筠無事業，但題草木作風流。"]'),
('e1bba013-0d6e-41c0-8d39-322b251356d0','上延帥沈內翰  其二','李復','宋','宋诗','song-poetry','','[]','榮路回翔簡帝衷，坐煩談笑靜西戎。',64,'全唐诗/poet.song.61000.json','["榮路回翔簡帝衷，坐煩談笑靜西戎。", "金鑾學士承新詔，烏壘將軍有古風。", "關塞星烽葱嶺遠，塵沙毳幕賀蘭空。", "平時未便知頗牧，今日親逢出禁中。"]'),
('8bcb8244-57b8-4952-b362-445c180afa10','答夔州舊僚被召見寄','李復','宋','宋诗','song-poetry','','[]','聖恩優厚得西還，又向雲臺作地仙。',64,'全唐诗/poet.song.61000.json','["聖恩優厚得西還，又向雲臺作地仙。", "顧我全生如苦李，喜君頻酌似甘泉。", "一篙已占南溪水，二頃初無負郭田。", "他日題詩如欲寄，爲尋茅屋白雲邊。"]'),
('37a4e43e-f64a-437d-9fd5-8c3750e23190','搗藥岩世傳昔人煉丹得道今隠於此山下土中時得丹粒服之愈疾','李復','宋','宋诗','song-poetry','','[]','超世猶存救世心，深山相遇不知名。',64,'全唐诗/poet.song.61000.json','["超世猶存救世心，深山相遇不知名。", "巖前時得丹砂粒，雲裏嘗聞玉杵聲。", "汩汩流光愁易促，冥冥濁劫苦難清。", "如何爲我開靈鼎，徧使蒼生病骨輕。"]'),
('da0f4074-2496-41e0-b3d1-1384ca96627d','登北原望京城有作','李復','宋','宋诗','song-poetry','','[]','五季兵銷帝業新，霏煙雙闕照夷門。',64,'全唐诗/poet.song.61000.json','["五季兵銷帝業新，霏煙雙闕照夷門。", "地盤王氣千齡會，勢據中天萬國尊。", "劍佩輝光新日月，風雷鼓舞變寒溫。", "開先神發隨人意，轤軸於今轉海垠。"]'),
('0b90b767-b6f7-46a8-b713-1d4b69f5ccdb','登美原縣樓','李復','宋','宋诗','song-poetry','','[]','三月春光入眼稀，試尋高處看芳菲。',64,'全唐诗/poet.song.61000.json','["三月春光入眼稀，試尋高處看芳菲。", "影行平野孤雲過，點破青山白鳥飛。", "秦甸氣回驚綠滿，渭川勢穩競東歸。", "憑虛便欲乘凌去，清吹飄飄已拂衣。"]'),
('3d6060f2-ccfc-41ca-8245-0d13cf5a6e44','登夔州城樓','李復','宋','宋诗','song-poetry','','[]','夔州城高樓崔嵬，浮空繞檻雲徘徊。',64,'全唐诗/poet.song.61000.json','["夔州城高樓崔嵬，浮空繞檻雲徘徊。", "百川東會大江出，羣山中斷三峽開。", "關塞最與荆楚近，舟帆遠自吳越來。", "雄心乘險爭割據，功業俯仰歸塵埃。"]'),
('c3bb417d-c402-4a83-99ef-7e300ca60503','夔州制勝樓','李復','宋','宋诗','song-poetry','','[]','野蜑荒獠南北羣，西接庸蜀東荆門。',64,'全唐诗/poet.song.61000.json','["野蜑荒獠南北羣，西接庸蜀東荆門。", "高城獨控江山險，勝算爭先日月昏。", "散火燒畬連近岸，歸雲带雨過孤村。", "二儀開闢雖重阻，須引流波及後昆。"]'),
('c0146cd1-8de7-41d5-9491-f2b5444a9946','自京之楚州','李復','宋','宋诗','song-poetry','','[]','隋柳橋邊一問津，便將行止付舟人。',64,'全唐诗/poet.song.61000.json','["隋柳橋邊一問津，便將行止付舟人。", "土風入眼鄉閭異，客路關心童僕親。", "淮水煙開漁市曉，龜山雲動佛香春。", "共傳米價年來賤，取次東遊不畏貧。"]'),
('aec60a9c-f7ae-44c3-bbb1-43a6b0007d3a','過黄牛峽','李復','宋','宋诗','song-poetry','','[]','轉首黄牛百里西，便風不斷滿歸旗。',64,'全唐诗/poet.song.61000.json','["轉首黄牛百里西，便風不斷滿歸旗。", "青山隨客豈辭遠，白浪催船常恐遲。", "多米漸聞荆渚近，故宮欲問楚人知。", "今朝共話平安喜，更得長魚伴晚炊。"]'),
('f9aec4fd-1925-4bee-bbc6-1a84953322cc','大江','李復','宋','宋诗','song-poetry','','[]','西南水會大江出，萬里奔激瞿塘開。',64,'全唐诗/poet.song.61000.json','["西南水會大江出，萬里奔激瞿塘開。", "神宮龍府雲霧暗，渦轉峽盤天地回。", "岷山發源四瀆長，廬峰白浪九道來。", "刳舟濟涉萬世頼，積金覆舟吁可哀。"]'),
('462c2fe9-0eb6-40f5-9707-bd568ed997fc','荆門軍蒙泉','李復','宋','宋诗','song-poetry','','[]','遠山分脈發巖陬，六月虛堂客意秋。',64,'全唐诗/poet.song.61000.json','["遠山分脈發巖陬，六月虛堂客意秋。", "無限寒雲噴不去，有多鳴玉碎無休。", "清涵錦石斑斑麗，秀吐金蓮熠熠幽。", "美潤散分周下澤，餘波還入楚江流。"]'),
('3dd0629b-c599-4b5a-9027-a2dfe41af3a0','過葉縣','李復','宋','宋诗','song-poetry','','[]','南對黄山百里峰，雙溪夾路碧溶溶。',64,'全唐诗/poet.song.61000.json','["南對黄山百里峰，雙溪夾路碧溶溶。", "難追舊事飛仙舄，但有餘風喜畫龍。", "柳際秋晴分䆉稏，亭陰晚色見芙蓉。", "襄城已遠方城近，圖誌分疆入楚封。"]'),
('51ebaca5-34ce-4eaa-9861-afba2d8fb3e8','移官慶陽過定平縣','李復','宋','宋诗','song-poetry','','[]','春郊二月浴蠶時，傍岸溪流可染衣。',64,'全唐诗/poet.song.61000.json','["春郊二月浴蠶時，傍岸溪流可染衣。", "谷轉城深驚柳暗，地寒春早見花稀。", "三年厭應西烽急，千里重隨北鳥飛。", "若問前籌慚潦倒，欲辭虎帳訪漁磯。"]'),
('f68b4fe0-7538-429a-940a-1a8f8717bbb6','過天門關','李復','宋','宋诗','song-poetry','','[]','龍鍾雙袖馬駸駸，來往榆關日向深。',64,'全唐诗/poet.song.61000.json','["龍鍾雙袖馬駸駸，來往榆關日向深。", "多病出門愁遠道，早寒平野苦層陰。", "泉流危棧新冰滑，風入長林暮葉吟。", "觸目凄然何所補，高枝巢穩感歸禽。"]'),
('c0d5f055-0eae-455a-b797-305679776e69','峽山阻風','李復','宋','宋诗','song-poetry','','[]','黄牛白馬渡驚灘，兩目盲飈更險艱。',64,'全唐诗/poet.song.61000.json','["黄牛白馬渡驚灘，兩目盲飈更險艱。", "天地容身惟一榻，江湖駭浪動千山。", "豪商競利能爭捷，陰鬼多私故作慳。", "歎息鄰家田舍穩，柴門深掩日高閒。"]'),
('d86498df-9336-4def-b54e-29a696a2b0ef','定昆池','李復','宋','宋诗','song-poetry','','[]','風煙當日競豪華，故里猶傳貴主家。',64,'全唐诗/poet.song.61000.json','["風煙當日競豪華，故里猶傳貴主家。", "何處可尋樓下水，平南不見面前花。", "陰機鬼伏天沉海，危禍波翻骨委沙。", "遊客乘秋興永嘆，高林不覺見棲鴉。"]'),
('38addbcb-af54-4bb2-9665-501248a7bfb9','分按洛西諸邑登山出永寧西望晚宿韶山寺','李復','宋','宋诗','song-poetry','','[]','雙旌明滅轉委蛇，行徧秋山意若何。',64,'全唐诗/poet.song.61000.json','["雙旌明滅轉委蛇，行徧秋山意若何。", "暗谷路窮平野闊，回巒石斷亂泉多。", "崤陵東盡開周邑，熊耳中分放洛河。", "欲舉因緣尋隻履，夜深隨雨到巖阿。"]'),
('229ce848-e419-4254-8566-136347d98075','胡義修推官再招彥桓與予同遊龍泉寺','李復','宋','宋诗','song-poetry','','[]','江曲花開惱醉翁，經旬出飲獨床空。',64,'全唐诗/poet.song.61000.json','["江曲花開惱醉翁，經旬出飲獨床空。", "芳羹間筯溪毛碧，異果堆盤海藥紅。", "盡晚莫辭千日酒，餘春已怨幾番風。", "主人清韵家聲在，伯始源流到眼中。"]'),
('32c46061-2b8e-4836-aafc-2b2bc5677f6b','彥桓奉檄將行同飯素於龍泉寺','李復','宋','宋诗','song-poetry','','[]','西江吸水試龐翁，再訪祇園問色空。',64,'全唐诗/poet.song.61000.json','["西江吸水試龐翁，再訪祇園問色空。", "古殿香寒消宿篆，晴林葉暗退殘紅。", "衰年再乞千家飯，逸馭初乘五日風。", "曉去清明邊檄急，前旌高下亂山中。"]'),
('b4b26c46-dd1e-4803-9ded-58cccd574e43','過香積寺','李復','宋','宋诗','song-poetry','','[]','迂轍來尋昔歲題，恍然前世意猶迷。',64,'全唐诗/poet.song.61000.json','["迂轍來尋昔歲題，恍然前世意猶迷。", "荒庭老樹半空腹，壞塔野禽爭暮棲。", "晚學盡驚新使節，殘僧時認舊沙彌。", "松房自出成何事，二十餘年東復西。"]'),
('e1e883df-e0c0-40f9-8133-c49e19b7cd66','遊山寺','李復','宋','宋诗','song-poetry','','[]','山後山前紺宇開，閒携藜杖結青鞋。',64,'全唐诗/poet.song.61000.json','["山後山前紺宇開，閒携藜杖結青鞋。", "霜欺泉澀羣流淺，風勁林彫萬壑哀。", "到處每逢清衆出，有時偶伴野人來。", "裴公看盡因緣在，百塔龕前首重回。"]'),
('96cd119c-94d7-499a-9a46-8f57bb018f5e','寒泉亭','李復','宋','宋诗','song-poetry','','[]','孤亭結架開巖扃，山深氣偏冬常侵。',64,'全唐诗/poet.song.61000.json','["孤亭結架開巖扃，山深氣偏冬常侵。", "驚浪一溪噴飛雪，陰簷五月垂堅冰。", "長風不斷響空峽，崩石欲落纏巨藤。", "三伏火雲愁病暍，投鞭知有幾人登。"]'),
('ff3e51a2-14e3-4ac0-af82-760c6bf13bad','題大圓庵  其一','李復','宋','宋诗','song-poetry','','[]','星郎步履在清禪，雅結新庵賦大圓。',64,'全唐诗/poet.song.61000.json','["星郎步履在清禪，雅結新庵賦大圓。", "譬喻河沙終未盡，含弘法界外無邊。", "渾成獨轉離諸相，不立中間絕兩偏。", "聞說毗耶在方丈，衆人欲問却茫然。"]'),
('2bff6ddf-eb1e-401a-999e-ecc3f502b112','題大圓庵  其二','李復','宋','宋诗','song-poetry','','[]','焚香置榻拂氍毹，困倚蒲團坐結趺。',64,'全唐诗/poet.song.61000.json','["焚香置榻拂氍毹，困倚蒲團坐結趺。", "丈室曾瞻一居士，臺山豈有兩文殊。", "信心自得超三界，明眼何嘗滯四隅。", "伯雪相逢能目擊，電機已笑涉泥塗。"]'),
('41524923-8464-4617-8313-1cb4f11dc2e2','題武侯廟  其一','李復','宋','宋诗','song-poetry','','[]','梁甫高吟一幅巾，聯翩衆盜肯同羣。',64,'全唐诗/poet.song.61000.json','["梁甫高吟一幅巾，聯翩衆盜肯同羣。", "久蟠丘壑雖龍卧，默計江山已鼎分。", "庸蜀欲開來日月，隆中先見會風雲。", "雜耕初動明星落，千古英雄泣渭濱。"]'),
('a500ce04-6a85-4187-a532-8860a693938c','題武侯廟  其二','李復','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','天厭炎靈暗不開，欲吹餘燼發寒灰。',64,'全唐诗/poet.song.61000.json','["天厭炎靈暗不開，欲吹餘燼發寒灰。", "强因徐庶南陽起，能枉周瑜赤壁來。", "常見英風吹草木，尚存精魄動雲雷。", "西南遺愛無時歇，不逐長江去不回。"]'),
('02bcb8b5-f5e8-4b0a-a744-b53d64808788','女几山女仙廟','李復','宋','宋诗','song-poetry','','[]','絳節高翔不可攀，尚留遺几在空山。',64,'全唐诗/poet.song.61000.json','["絳節高翔不可攀，尚留遺几在空山。", "月明曾有芳簫過，松老時看舊鶴還。", "巖下春歸花寂寂，壁間雲暗蘚斑斑。", "開元已遠霓裳絕，野草青青輦路閒。"]'),
('9a4a3e93-0e5a-4775-92d2-fe61005ff377','和林次中秘閣題五龍廟','李復','宋','宋诗','song-poetry','','[]','頭角蟠潛歲月沉，腥風不散古祠深。',64,'全唐诗/poet.song.61000.json','["頭角蟠潛歲月沉，腥風不散古祠深。", "曾聞驚電開巖壁，常見屯雲宿殿陰。", "蒼蜴吐冰藏暗穴，彩虹收雨出長林。", "荒碑磨滅無遺事，猶冠龜跗壓翠岑。"]'),
('4286975d-7a55-46b9-a633-60a469c03e8d','屈原廟','李復','宋','宋诗','song-poetry','','[]','古廟荒山暗水雲，歲時歌舞感鄉民。',64,'全唐诗/poet.song.61000.json','["古廟荒山暗水雲，歲時歌舞感鄉民。", "幾傷讒口方離國，欲悟君心豈愛身。", "慘慘飛魂號帝闕，冥冥齎志託江神。", "千年自有遺文在，光焰長如日月新。"]'),
('3e629ac5-ec2f-4e1b-8349-06f5112e9747','題解梁驛舍','李復','宋','宋诗','song-poetry','','[]','三年去國苦飄零，滿面風沙漫度春。',64,'全唐诗/poet.song.61000.json','["三年去國苦飄零，滿面風沙漫度春。", "白日驅車無住客，青山當路亦爲塵。", "東經鹵澤初迎雪，西出蒲關欲問津。", "何日投鞭尋舊隠，雲間深訪牧牛人。"]'),
('c8b76f2f-32e5-4708-aaa6-592fd9467387','過沔池驛','李復','宋','宋诗','song-poetry','','[]','崤陵臯墓幾摧輪，秋暮重過白髮新。',64,'全唐诗/poet.song.61000.json','["崤陵臯墓幾摧輪，秋暮重過白髮新。", "小雨廉纖能滑徑，亂山迴互欲迷人。", "客心苦厭孤程晚，驛舍頻來舊吏親。", "明日問途知更遠，又須呼僕待初晨。"]'),
('e7975c35-7313-4c5d-b04d-a372bc80415e','過襄陽','李復','宋','宋诗','song-poetry','','[]','表裏山川舊楚畿，築關乘險事皆非。',64,'全唐诗/poet.song.61000.json','["表裏山川舊楚畿，築關乘險事皆非。", "槎頭魚盡無新語，峴首人亡失隠扉。", "雲外煮茶僧室靜，江邊酤酒客帆歸。", "我來駐節無言久，爲愛春流可染衣。"]'),
('76f1780d-4402-47fe-bb64-e7b2c27311fb','初至鄭州','李復','宋','宋诗','song-poetry','','[]','二年青海困征鞍，歸望天威咫尺間。',64,'全唐诗/poet.song.61000.json','["二年青海困征鞍，歸望天威咫尺間。", "雨露忽頒西輔印，鴛鸞阻綴紫宸班。", "往來擾擾無虛日，應接紛紛祗强顔。", "吏責無窮人事拙，夢魂時到舊家山。"]'),
('948a9c02-4f91-4d77-8ce5-4d95fe80ad4d','過臨晉縣適調發','李復','宋','宋诗','song-poetry','','[]','半夜驚呼府有符，河堧荒邑應軍須。',64,'全唐诗/poet.song.61000.json','["半夜驚呼府有符，河堧荒邑應軍須。", "冰生垂血辭鄉淚，風漲飛塵出塞車。", "千里饋糧人未返，百丁團甲戶無餘。", "天邊旁午流星使，更見河橋急羽書。"]'),
('5d1083e4-9df6-4d06-8602-ef543d35321d','韓退之舊業','李復','宋','宋诗','song-poetry','','[]','城南舊業訪韓符，門掩荒榛老木疏。',64,'全唐诗/poet.song.61000.json','["城南舊業訪韓符，門掩荒榛老木疏。", "陰洞尚寒難駐客，短茅初葺未成居。", "崩崖亂竹從欹倒，糝逕飛花不掃除。", "舊集遠年今散逸，蒼碑但刻馬鳴書。"]'),
('ff57acdd-779b-4bfd-b2a9-7462d53a8486','八月十六日後池上','李復','宋','宋诗','song-poetry','','[]','竹戶深扃滿逕苔，芙蓉落盡曉池開。',64,'全唐诗/poet.song.61000.json','["竹戶深扃滿逕苔，芙蓉落盡曉池開。", "數番雨勢隨風去，一片秋光入座來。", "已老林蟬餘韵斷，將歸簷燕强飛回。", "沙鷗時下知人意，近岸相親眼不猜。"]'),
('cb2ad416-8965-41dd-844e-c6848ac1bd2b','种說山居  其一','李復','宋','宋诗','song-poetry','','[]','隠君奕葉爲清門，誅茅卜築歲已深。',64,'全唐诗/poet.song.61000.json','["隠君奕葉爲清門，誅茅卜築歲已深。", "池影青蒼山墮地，松枝夭矯龍出林。", "六月取冰自鑿谷，百壺進酒不論金。", "阮生熟醉無臧否，今愛遺風杜曲陰。"]'),
('cf6d9665-c977-427d-9f16-55db34705a9d','种說山居  其二','李復','宋','宋诗','song-poetry','','[]','客來稚子出應門，潔灑虛庭屢汲深。',64,'全唐诗/poet.song.61000.json','["客來稚子出應門，潔灑虛庭屢汲深。", "西澤千塍連別岸，南山一带是家林。", "泉清野果浮蒼玉，燈散靈峰見紫金。", "晚日已收凉氣動，客歸相送步松陰。"]'),
('0faca6dc-64da-462e-9c69-976cd13f4f00','抱甕軒','李復','宋','宋诗','song-poetry','','[]','擾擾誰知巧喪生，惟君智巧不關心。',64,'全唐诗/poet.song.61000.json','["擾擾誰知巧喪生，惟君智巧不關心。", "爲能懸解如莊叟，會識真風在漢陰。", "閒笑重輕爭俯仰，靜忘身世任浮沉。", "堪嗟混沌亡來久，今獨憐君踵息深。"]'),
('58c5f2c4-0977-444e-b614-bf2536a74332','郊居','李復','宋','宋诗','song-poetry','','[]','閒原渺渺散疏襟，風舞淵潛自樂生。',64,'全唐诗/poet.song.61000.json','["閒原渺渺散疏襟，風舞淵潛自樂生。", "春到雲山惟杖履，日長天地獨柴荆。", "百年雖健猶親藥，一飯無多嬾問耕。", "常羨子喬仙馭遠，笑悲滄海世人情。"]'),
('744efa09-e3d2-41a3-8e5c-23d7cb112b30','三月二十八日園中作','李復','宋','宋诗','song-poetry','','[]','决决清溪漱遶堂，興來隨意轉藜床。',64,'全唐诗/poet.song.61000.json','["决决清溪漱遶堂，興來隨意轉藜床。", "畏人野鳥疑花動，收蜜山蜂誤酒香。", "杏子带鬚紅半抱，藥苗退甲綠新長。", "風光須是閒時見，身世今欣已兩忘。"]'),
('93a292bf-9c5c-4538-94fc-91003febc141','和夏日園中即事','李復','宋','宋诗','song-poetry','','[]','雨過深園暑氣清，拂雲松竹映重閽。',64,'全唐诗/poet.song.61000.json','["雨過深園暑氣清，拂雲松竹映重閽。", "預期節物移承露，自驗方書採合昏。", "片影有緣聊暫寄，寸心無事得閒論。", "風光未信隨流轉，猶見飛花落酒尊。"]'),
('c23367e0-1b4d-4102-be96-0bdcd697dc9f','園中獨坐','李復','宋','宋诗','song-poetry','','[]','高樹風輕葉影齊，新荷破卷綠猶低。',64,'全唐诗/poet.song.61000.json','["高樹風輕葉影齊，新荷破卷綠猶低。", "日長松下少人到，坐久竹間聞鳥啼。", "萬里驚波逢寶筏，百年病膜快金篦。", "雖知赤水遺珠在，問路襄城舉世迷。"]'),
('fa82a733-056a-4550-97fb-53a64e39f240','李氏園','李復','宋','宋诗','song-poetry','','[]','城近斜臨南郭路，地寬分得奉誠園。',64,'全唐诗/poet.song.61000.json','["城近斜臨南郭路，地寬分得奉誠園。", "垂竿引水穿回徑，種竹成陰補壞垣。", "曉露不收荷已敗，新霜將落柿初繁。", "天晴野曠秋風厲，借榻虛堂負午暄。"]'),
('2ab081df-5d80-4e55-998c-e353a7f88c28','過李氏園','李復','宋','宋诗','song-poetry','','[]','伊川北首始知春，問路停驂僕候門。',64,'全唐诗/poet.song.61000.json','["伊川北首始知春，問路停驂僕候門。", "垂柳萬顰梅一笑，蒼松四出石雙蹲。", "高人舊隠家風遠，祥兆開先國邑尊。", "昔歲往來曾駐蹕，從臣遺刻在雲根。"]'),
('05b15abc-5003-4de5-ab5a-043ba9a188f6','陸渾王秀才園','李復','宋','宋诗','song-poetry','','[]','兩歲伊川擁傳行，往來屢喜訪雲扃。',64,'全唐诗/poet.song.61000.json','["兩歲伊川擁傳行，往來屢喜訪雲扃。", "四時溪水喧巖石，六月山陰滿戶庭。", "每到似開雙眼翳，久居應滌百骸醒。", "露香浮座供賓餉，凉葉生風野草青。"]'),
('2c0a21fe-e818-4f43-9cf3-07596a9ed4c9','和題屈氏園','李復','宋','宋诗','song-poetry','','[]','密樹煙深綠映門，入門清絕隔囂塵。',64,'全唐诗/poet.song.61000.json','["密樹煙深綠映門，入門清絕隔囂塵。", "須知澤畔行吟客，便是林間散髮人。", "山色滿樓何處盡，花香過酒逐番新。", "東風時引閒雲到，留作輕陰欲駐春。"]'),
('04eeeaf1-0ea6-4033-ba49-51948f330b9a','杜城陳文惠公園','李復','宋','宋诗','song-poetry','','[]','杜曲西遊訪物華，門前潏水淥涵沙。',64,'全唐诗/poet.song.61000.json','["杜曲西遊訪物華，門前潏水淥涵沙。", "南城天近無雙譽，北斗魁前第一家。", "當日不知龍卧久，今朝空羨桂交花。", "高文遺墨皆漫滅，林下祠堂春日斜。"]'),
('b7f9fbf3-3f43-4738-bd87-45bdc47d53e7','和范君武出郊','李復','宋','宋诗','song-poetry','','[]','九月天高客喜晴，籃輿因興度溪行。',64,'全唐诗/poet.song.61000.json','["九月天高客喜晴，籃輿因興度溪行。", "身逢樂歲留漳浦，心逐秋風入渭京。", "日暖登場多稼熟，桑陰具餉野盤盈。", "豐年社後多餘酒，處處神林簫鼓聲。"]'),
('44894904-35ea-44ee-843e-ccc59f2ff037','和人遊千金公主園池','李復','宋','宋诗','song-poetry','','[]','溪流古堞带林高，林下行通小水橋。',64,'全唐诗/poet.song.61000.json','["溪流古堞带林高，林下行通小水橋。", "但有春風催載酒，更無仙鳳伴吹簫。", "花間鳥散驚藜杖，沼際波回轉桂舠。", "塵迹尋餘思一弔，楚魂飛盡不能招。"]'),
('1c85655c-dd48-40a3-b1a1-62b674b9abb3','後園小池  其一','李復','宋','宋诗','song-poetry','','[]','鑿地開方斷石根，潤通草樹亦欣欣。',64,'全唐诗/poet.song.61000.json','["鑿地開方斷石根，潤通草樹亦欣欣。", "築基偏傍孤亭闊，引水初從曲徑分。", "風約落花回近岸，露垂欹竹滴圓紋。", "春晴山鳥常來浴，淺處喧喧故作羣。"]'),
('be56662d-2a92-468b-8e58-d590589dadea','後園小池  其二','李復','宋','宋诗','song-poetry','','[]','城陬荒僻自開鋤，野性難忘水竹居。',64,'全唐诗/poet.song.61000.json','["城陬荒僻自開鋤，野性難忘水竹居。", "岸側星機搘錦石，波心仙仗立紅蕖。", "閒中有客唯來鶴，靜去無竿不釣魚。", "八卦神靈今可問，玄夫時出御輜車。"]'),
('09bd9936-5dd5-4666-b71b-8d9a37b723e6','和韓丞相玉汝登見山閣','李復','宋','宋诗','song-poetry','','[]','丹青岌嶪冠鼇丘，地闢天開洗百憂。',64,'全唐诗/poet.song.61000.json','["丹青岌嶪冠鼇丘，地闢天開洗百憂。", "萬竅倚空號一噫，八川盤野會千流。", "浮雲晚日悲餘翠，廢苑荒陵怨暮秋。", "自昔登臨思善賦，高吟豈向世間求。"]'),
('5a7efb21-03f4-456d-82d1-f96a2c301851','遊柏谷寺寄范君武','李復','宋','宋诗','song-poetry','','[]','絕塞初歸喜澣休，東城送客偶成遊。',64,'全唐诗/poet.song.61000.json','["絕塞初歸喜澣休，東城送客偶成遊。", "山前欲訪青蘭若，林下初聞黄鷅鶹。", "雙屨高窮溪水出，一身輕共野雲浮。", "寄聲德操還能否，炊黍吾過爲少留。"]'),
('c0f24788-9ac3-4b6d-94c9-4f256fc9d765','賦杜子美劉夢得遺事','李復','宋','宋诗','song-poetry','','[]','壁間石刻圖經在，瀼外祠堂繪像真。',64,'全唐诗/poet.song.61000.json','["壁間石刻圖經在，瀼外祠堂繪像真。", "秋去書懷傳北客，歸時遺曲祠蠻神。", "十年口語投荒謫，千里兵戈下峽身。", "嗟我南來心跡似，臨風把酒寄情親。"]'),
('e05b962b-e5c4-42a9-95dc-5d5e25c1c58c','王穀節推畫草蟲花竹求詩','李復','宋','宋诗','song-poetry','','[]','細羽爭飛翠蔓長，窗間留影點綃光。',64,'全唐诗/poet.song.61000.json','["細羽爭飛翠蔓長，窗間留影點綃光。", "寧知臂朽專蜩翼，但見心精妙楮芒。", "詩學蟲魚增舊譜，藥圖草木驗仙方。", "請君放筆開高臆，縱意雲龍五色章。"]'),
('1982369c-c57d-49c2-9bc7-c03c4fae2e51','王氏園置燭觀梅','李復','宋','宋诗','song-poetry','','[]','堂前梅樹花初徧，露坐看花對夕風。',64,'全唐诗/poet.song.61000.json','["堂前梅樹花初徧，露坐看花對夕風。", "苦恨夜收春色去，故移燈入素光中。", "亂爭短髮愁邊白，清映衰顔酒後紅。", "醉眼却來尋不見，只疑林月碎玲瓏。"]'),
('dc9900d8-6d72-49f3-aa95-b4f67196c2ac','依韵和秦倅陳無逸觀梅','李復','宋','宋诗','song-poetry','','[]','渭水冰消意始回，肌膚玉雪本仙材。',64,'全唐诗/poet.song.61000.json','["渭水冰消意始回，肌膚玉雪本仙材。", "江南氣暖常先見，隴坻山寒不易開。", "二月莫傷春色晚，一枝豈待嶺邊來。", "風光切莫輕流轉，未放悲雲畫角哀。"]'),
('9ce41b35-1b5c-4093-aa23-eacc779ab0aa','觀梅','李復','宋','宋诗','song-poetry','','[]','轥藉霜威欲斷肌，傲霜挺挺發南枝。',64,'全唐诗/poet.song.61000.json','["轥藉霜威欲斷肌，傲霜挺挺發南枝。", "微風披拂香來去，皎月勾添光陸離。", "已入鸞臺弄粧手，猶存谷口出塵姿。", "苦無疏影橫斜句，深愧林逋處士詩。"]'),
('c4abd0b2-990c-443c-badd-75c9af84116b','陳再有詩誚梅開晚戲酬','李復','宋','宋诗','song-poetry','','[]','漠漠飛香散不收，無言對客似含羞。',64,'全唐诗/poet.song.61000.json','["漠漠飛香散不收，無言對客似含羞。", "雖非雪裏孤根暖，却免黄時細雨愁。", "爭意競先多淺俗，高情持重自風流。", "一株又見垂垂發，肯學江邊取次休。"]'),
('4ec352b5-1b6e-4f2b-a716-d7a5df995916','和林次中五鬣松','李復','宋','宋诗','song-poetry','','[]','僊人五色鼎中丹，丹養松根葉不添。',64,'全唐诗/poet.song.61000.json','["僊人五色鼎中丹，丹養松根葉不添。", "雲散細風梳碧縷，龍離遠嶠奮蒼髯。", "雨衣鐵澀封霜甲，露點珠明滴翠纖。", "採釀春醪能愈疾，欲求方法檢書籤。"]'),
('953b032e-2e92-4e0b-8a2e-eec2507d1488','詠槐  其一','李復','宋','宋诗','song-poetry','','[]','當年夾路綠參差，曾擁金輿拂羽旗。',64,'全唐诗/poet.song.61000.json','["當年夾路綠參差，曾擁金輿拂羽旗。", "得地偶逃斤斧幸，聞風非與雪霜期。", "猶殘臘火燔空腹，時有驚雷起蠹枝。", "想見妖靈占上象，龜山獵罷舊都移。"]'),
('e68bf310-fd06-4597-8d6f-6db8a0a6c632','詠槐  其二','李復','宋','宋诗','song-poetry','','[]','古槐疏慘倚頹牆，病葉先秋已半黄。',64,'全唐诗/poet.song.61000.json','["古槐疏慘倚頹牆，病葉先秋已半黄。", "封植不知何歲月，彫零今困幾風霜。", "老根傍出人供爨，蠹腹多穿馬繫韁。", "嘆惜他年承愛賞，清陰曾借暑天凉。"]'),
('9e45898a-0940-47ee-a05c-68154c819810','和進櫻桃上宣諭近臣洛中今年進櫻桃甚大當日分賜','李復','宋','宋诗','song-poetry','','[]','四月櫻桃始爛紅，拜章馳驛歲常同。',64,'全唐诗/poet.song.61000.json','["四月櫻桃始爛紅，拜章馳驛歲常同。", "留都舊事修邦貢，薦廟清朝廣孝風。", "翠籠摘從西後苑，彩奩進入大明宮。", "近臣曾見天顔喜，清曉分頒到省中。"]'),
('3c16b79a-bd81-4a64-abf9-324c0ae80004','和人汰竹','李復','宋','宋诗','song-poetry','','[]','與世論交獨厭數，此君多冗豈無煩。',64,'全唐诗/poet.song.61000.json','["與世論交獨厭數，此君多冗豈無煩。", "欲期虛靜延清影，莫懶芟除去惡根。", "漸見遠山開晻靄，更無繁鳥亂黄昏。", "直須放手留閒地，別待春雷見子孫。"]'),
('c0d151d7-dccd-465a-a7a6-05b8476fe8d0','和人筍詩','李復','宋','宋诗','song-poetry','','[]','葛陂龍去已千年，每見遺孫出是間。',64,'全唐诗/poet.song.61000.json','["葛陂龍去已千年，每見遺孫出是間。", "未遇嚴霜懷節久，因生平地立身難。", "長崖氣潤雲藏角，暗谷叢深霧養斑。", "春晚向空重籜盡，却驚高意不能攀。"]'),
('f3b0944d-81c8-4ea3-8584-262b8bbe9838','和周湜雪  其一','李復','宋','宋诗','song-poetry','','[]','雲表爭飛鏤玉花，衝烟照水弄光華。',64,'全唐诗/poet.song.61000.json','["雲表爭飛鏤玉花，衝烟照水弄光華。", "徧粧庭樹能多巧，亂入風簾不奈斜。", "漠漠楊花迷客徑，紛紛蝴蝶滿人家。", "寒簷向晚凝清滴，乳洞春硝長馬牙。"]'),
('56262624-9197-4d6f-b14c-fb3c6c7b0b47','和周湜雪  其二','李復','宋','宋诗','song-poetry','','[]','六合天人競散花，坐驚門地亦清華。',64,'全唐诗/poet.song.61000.json','["六合天人競散花，坐驚門地亦清華。", "川原霽後龍鱗出，島嶼平時鳥篆斜。", "秀發園林春萬里，寒生樓觀月千家。", "待看陽律還暄早，破潤乘凌見翠牙。"]'),
('32b21a40-c50f-4c17-9a8d-700a3d773dc5','和周湜雪  其三','李復','宋','宋诗','song-poetry','','[]','暮飈作氣動長林，渴意經時恨未深。',64,'全唐诗/poet.song.61000.json','["暮飈作氣動長林，渴意經時恨未深。", "亂學飛花穿竹戶，散搖清影落池心。", "生憎拂面輕難改，更覺衝風薄未任。", "狡兔但從開幾穴，韓盧會逐曉蹤尋。"]'),
('28687c45-a043-48e8-b3f7-033add8208df','和周湜雪  其四','李復','宋','宋诗','song-poetry','','[]','毰毸亂舞出烟林，落久臨階試淺深。',64,'全唐诗/poet.song.61000.json','["毰毸亂舞出烟林，落久臨階試淺深。", "平盡高低寬眼界，放開虛白見天心。", "狂傾月窟愁將竭，厚壓坤輿恐未任。", "潤澤功成本無迹，便回春意欲同尋。"]'),
('d8004552-8317-41e2-80f9-9e4f122ea788','和朱給事上元早雪','李復','宋','宋诗','song-poetry','','[]','玉花清曉作餘寒，雲暗重城晻靄間。',64,'全唐诗/poet.song.61000.json','["玉花清曉作餘寒，雲暗重城晻靄間。", "初逐細風飛寂寂，旋隨小雨潤斑斑。", "萬家燈火方行樂，九陌輪蹄肯放閒。", "向晚霽開斜照在，門前柳色未藏山。"]'),
('ee3d5eb6-e69b-4fc5-a531-c79818f4c7ae','和孫俁朝奉立春','李復','宋','宋诗','song-poetry','','[]','閏餘隨臘報迎春，便覺勾芒令有神。',64,'全唐诗/poet.song.61000.json','["閏餘隨臘報迎春，便覺勾芒令有神。", "流轉光陰頻著物，崢嶸歲序苦驚人。", "花裝寶蠟餘枝弱，菜點彫盤小綠勻。", "從此試聽枝上鳥，漸傳芳信語言新。"]'),
('090a1e84-c047-41d9-aafc-59899f81153f','梁元彬招池上府會辭之以詩','李復','宋','宋诗','song-poetry','','[]','東郊日日喚春催，得意晴天浩蕩來。',64,'全唐诗/poet.song.61000.json','["東郊日日喚春催，得意晴天浩蕩來。", "病客强因寒食起，新花不爲老人開。", "塵埃邊叟拋書卧，鼓吹山翁倒載回。", "欲問湖光幾時浄，試容扶杖獨徘徊。"]'),
('bbb1bd4a-bd9f-4929-b722-918146cbe8bb','和郭戶部中秋月','李復','宋','宋诗','song-poetry','','[]','重雲宿靄風收盡，千丈銀毫吐海涯。',64,'全唐诗/poet.song.61000.json','["重雲宿靄風收盡，千丈銀毫吐海涯。", "露氣洗開青玉闕，龍宮浮出白蓮華。", "寒驚棲鵲翻庭樹，陰引靈珠耀浦沙。", "我是襆巾修月手，玉皇應許上仙槎。"]'),
('7d9d0489-3929-4748-b8e3-d84552aef580','潞守歐陽叔弼召登鼎軒暑飲','李復','宋','宋诗','song-poetry','','[]','崇軒寫物體模分，爽拔風携顥氣升。',64,'全唐诗/poet.song.61000.json','["崇軒寫物體模分，爽拔風携顥氣升。", "王粲消憂思眺聽，本初持飲滌煩蒸。", "金烏不轉銅壺箭，碧碗時分玉井冰。", "每見喜公如玉雪，更因執熱服吾膺。"]'),
('9ef5d7bf-4ece-4e83-8628-6aab5d9b74e9','再和叔弼暑飲','李復','宋','宋诗','song-poetry','','[]','古製雖存事一新，奇峰時作火雲升。',64,'全唐诗/poet.song.61000.json','["古製雖存事一新，奇峰時作火雲升。", "憑風高棟能虛爽，欲雨炎天故鬰蒸。", "適意浮沉多野果，熱中咀嚼喜清冰。", "別裁僞體親風雅，若比陰鏗豈敢膺。"]'),
('eb2a2cb8-0f0c-4468-950c-97e9ad7da32d','答晦叔求飲','李復','宋','宋诗','song-poetry','','[]','墨客高吟動碧雲，蕢桴輕笑鼓雷閽。',64,'全唐诗/poet.song.61000.json','["墨客高吟動碧雲，蕢桴輕笑鼓雷閽。", "千尋自分遺樗散，百和何堪借棗昏。", "按劍夜光驚暗擲，揮絃流水喜新論。", "久聞逸興須酣發，願看長虹出淥尊。"]'),
('17b0c662-3202-4863-b658-641383ab8988','和江晦叔喜雨','李復','宋','宋诗','song-poetry','','[]','千里人懷閔旱心，輕將歲事叩天閽。',64,'全唐诗/poet.song.61000.json','["千里人懷閔旱心，輕將歲事叩天閽。", "驟傾江海繁聲合，盡滌山川沴氣昏。", "官責時豐聊共喜，歸休興動欲誰論。", "更思田父相邀樂，步屧春風倒社尊。"]'),
('9b6e1e00-47d9-4db0-a8fc-4e7acbbf1461','和朱公掞給事喜雨','李復','宋','宋诗','song-poetry','','[]','喜雨高吟夜不眠，飄飄秀句選青錢。',64,'全唐诗/poet.song.61000.json','["喜雨高吟夜不眠，飄飄秀句選青錢。", "已推覆斗占穰歲，誰事操豚祝下田。", "滿澤新秧初放溜，連雲高樹欲生煙。", "未知美價堪多少，洗盡人間苦暍天。"]'),
('86276c17-4bcc-4908-b5ce-b7b2644c00b7','中秋客至不赴郡會次范君武韵','李復','宋','宋诗','song-poetry','','[]','經歲相期盡賞心，虛堂有客阻趨塵。',64,'全唐诗/poet.song.61000.json','["經歲相期盡賞心，虛堂有客阻趨塵。", "登樓君似庾老子，挾策我爲臧丈人。", "清據胡床興不淺，來尋奇字夜相親。", "莫言糟粕無佳味，未許桓公媿斲輪。"]'),
('374cc20c-8722-407a-8ef4-398a2de4ea06','和李獻甫守歲','李復','宋','宋诗','song-poetry','','[]','枯蝦乾栗排野盤，擁爐酌酒兒女筵。',64,'全唐诗/poet.song.61000.json','["枯蝦乾栗排野盤，擁爐酌酒兒女筵。", "却愁詰朝祗明日，便數今宵爲去年。", "瞻星惟恐斗柄落，續膏更願燈花燃。", "小癡老怯坐自笑，無補漫廢通夕眠。"]'),
('f8ac111f-705a-4590-889f-b38975805c61','次韵鮮于之武遊南谷','李復','宋','宋诗','song-poetry','','[]','山光娛客古城東，雲散春陰望處空。',64,'全唐诗/poet.song.61000.json','["山光娛客古城東，雲散春陰望處空。", "畏影戲魚依藻綠，避人飛鳥動巖紅。", "林間野坐分溪石，岸曲晴行喜水風。", "舊事共高文字飲，新遊盡寄語言中。"]'),
('64031976-1752-434b-9dfa-ff3a64d9d4f0','芸叟召杜城晚飲遂宿於東軒欲同遊五臺寺有詩因和其韵','李復','宋','宋诗','song-poetry','','[]','第五橋東潏水濱，山紅漫漫綠紛紛。',64,'全唐诗/poet.song.61000.json','["第五橋東潏水濱，山紅漫漫綠紛紛。", "溪邊童子風雩舞，林外先生植杖耘。", "高論但談雙樹法，勝遊將步五峰雲。", "東軒夜久清無寐，山雨初從葉上聞。"]'),
('25c7e7e4-c5d2-40d3-bafd-fedbd026209c','次馬承議韵','李復','宋','宋诗','song-poetry','','[]','浮雲飄忽竟多姿，蒼狗須臾化白衣。',64,'全唐诗/poet.song.61000.json','["浮雲飄忽竟多姿，蒼狗須臾化白衣。", "對客莫思捫蝨語，乘風且共跨鯨歸。", "巖巖清壁三千仞，鬰鬰寒松四十圍。", "君看時光易流轉，新霜高葉又朝稀。"]'),
('304c3ace-fb94-46ba-9f88-249c6c363973','依韵答俞承議','李復','宋','宋诗','song-poetry','','[]','南北相望已十年，白頭相見喜留連。',64,'全唐诗/poet.song.61000.json','["南北相望已十年，白頭相見喜留連。", "風埃異國君多感，朱墨勞心我自憐。", "事可寸心能有幾，生無百歲漫憂千。", "一聞新賦思歸去，韋杜溪邊訪舊田。"]'),
('4ca1da58-e6b0-41a3-95d5-9be67c14b81a','次韵李忱承議所惠詩','李復','宋','宋诗','song-poetry','','[]','人生飄蕩若浮雲，邂逅乘風忽聚羣。',64,'全唐诗/poet.song.61000.json','["人生飄蕩若浮雲，邂逅乘風忽聚羣。", "嗟我淹留今倦宦，喜君傾倒細論文。", "揚舲覺海宗提印，授鉞詩壇勇冠軍。", "荒學漫勞無所得，鼻端聊假一揮斤。"]'),
('b5a2590b-6be2-4fad-a872-e1a23c24d64f','和胡漕鬭茶分藥','李復','宋','宋诗','song-poetry','','[]','萬里飛香入晉山，高真秘籙露談端。',64,'全唐诗/poet.song.61000.json','["萬里飛香入晉山，高真秘籙露談端。", "春雷發地巖驚綠，夜鶴飛壇鼎轉丹。", "仙桂清風生兩腋，玉壺五色抱神丸。", "虛談論罷無塵事，林外娟娟月半殘。"]'),
('0da2fc79-587d-4f95-9799-8726781aa317','和成季','李復','宋','宋诗','song-poetry','','[]','芸閣磨鉛勘舊經，昔聞同舍此同升。',64,'全唐诗/poet.song.61000.json','["芸閣磨鉛勘舊經，昔聞同舍此同升。", "九楹置榻從頹偃，百尺浮空遠濕蒸。", "玉鱠堆盤魚勝雪，綠荷傾飲酒凝冰。", "家風牢落承推奬，深愧龍門昔有膺。"]'),
('c2b9effb-1aa2-47c4-8fea-e42664e75732','依韵和南子强','李復','宋','宋诗','song-poetry','','[]','雲路天門白日開，豈無松桂出蒿萊。',64,'全唐诗/poet.song.61000.json','["雲路天門白日開，豈無松桂出蒿萊。", "於斯未信誠可矣，如或知爾何以哉。", "鏗然舍瑟有異撰，豈必讀書無取裁。", "業廣惟勤今汝畫，覆簣不止須崔嵬。"]'),
('b0f2cbc7-5d2d-434f-b732-c9b2b0bb41c2','和劉丈招與康集同遊韋杜','李復','宋','宋诗','song-poetry','','[]','潏水橋邊縱客車，去天尺五訪尋初。',64,'全唐诗/poet.song.61000.json','["潏水橋邊縱客車，去天尺五訪尋初。", "按圖韋杜風烟在，遺址隋唐錦繡餘。", "雨後晚花寒寂歷，霜前老樹半彫疏。", "松間有酒來招我，遠約相依造隠廬。"]'),
('23ce0ae0-36d7-40a7-96e0-1a1e74040b9c','和尹宗閔書記四月二日候客溪上潞守李獻甫具飯有詩','李復','宋','宋诗','song-poetry','','[]','溪園經歲不曾開，逸興何妨候客回。',64,'全唐诗/poet.song.61000.json','["溪園經歲不曾開，逸興何妨候客回。", "春色堂堂辭我去，暑風咄咄逼人來。", "追凉故繞池邊樹，分坐時侵石上苔。", "皂蓋歸城魚鳥樂，更延虛靜獨徘徊。"]'),
('4042a548-b7b0-4797-8393-b0231adbe8ac','酬汾守鄭大夫','李復','宋','宋诗','song-poetry','','[]','鄭公賦政鬢如絲，符竹新分晉水湄。',64,'全唐诗/poet.song.61000.json','["鄭公賦政鬢如絲，符竹新分晉水湄。", "招客遠郊常置驛，論文古訓舊箋詩。", "漢庭行曳尚書履，涇谷曾刊隠士碑。", "今日湖亭共遊汎，追懷子美昔同時。"]'),
('e20f5a0c-d2e5-455f-be97-9c62e34e9498','暑中即事','李復','宋','宋诗','song-poetry','','[]','掛壁清羸金粟像，映窗性相凈名經。',64,'全唐诗/poet.song.61000.json','["掛壁清羸金粟像，映窗性相凈名經。", "門前野水流繞舍，雨後綠槐陰滿庭。", "凉簟醒心須稍健，好風吹鬢欲重青。", "此間真境誰宜到，更有珍茶一種靈。"]'),
('0bb564ce-ab8b-459c-8efe-0c4579796c4d','靜坐','李復','宋','宋诗','song-poetry','','[]','一室蕭然不受塵，簾垂疏竹映深門。',64,'全唐诗/poet.song.61000.json','["一室蕭然不受塵，簾垂疏竹映深門。", "擁衾調氣煩呼吸，據案翻書費討論。", "南郭子綦初喪我，毗耶摩詰已忘言。", "盡傳息慮何須息，竅鑿無傷混沌存。"]'),
('a6bd0f3e-549f-49c8-8b3e-ff0a5fee76fa','和劉君俞遊華嚴寺謁文禪師  其一','李復','宋','宋诗','song-poetry','','[]','華嚴法界出諸天，帝網重重絕世緣。',64,'全唐诗/poet.song.61000.json','["華嚴法界出諸天，帝網重重絕世緣。", "昔有高僧開寶剎，今留飛閣聳瓊田。", "身遊色相無窮境，心悟虛空不住禪。", "碧眼胡人香一炷，分來今欲對師燃。"]'),
('7498a698-b0dc-496f-a393-53fa666e6089','和劉君俞遊華嚴寺謁文禪師  其二','李復','宋','宋诗','song-poetry','','[]','靈山勝致古今同，下種開花一線通。',64,'全唐诗/poet.song.61000.json','["靈山勝致古今同，下種開花一線通。", "峴首道安酬鑿齒，江西馬祖對龐翁。", "圓珠迥耀千淵黑，滴乳微傾六斛空。", "我有宿緣香火念，閒來相與論幡風。"]'),
('260aa0f1-f13b-41a7-bf87-a8d981cc364c','暑退病起沐罷倦卧得芸叟詩招爲草堂紫閣之遊酬以來韵','李復','宋','宋诗','song-poetry','','[]','八月秋高肺病蘇，深居吾亦愛吾廬。',64,'全唐诗/poet.song.61000.json','["八月秋高肺病蘇，深居吾亦愛吾廬。", "晚風剡剡初衣裌，白髮蕭蕭不滿梳。", "困著藜床眠北牖，遠飛蝶夢訪清都。", "覺來聞有雲山興，親寫新詩欲起予。"]'),
('388460e0-cdec-4970-85c2-16afa6ddb764','酬晉倅徐發承議','李復','宋','宋诗','song-poetry','','[]','默默窮年逐衆行，杯坳浮芥竟何成。',64,'全唐诗/poet.song.61000.json','["默默窮年逐衆行，杯坳浮芥竟何成。", "交遊似夢逢還去，世事如塵掃更生。", "未訪故溪舟一葉，空嗟短髮雪千莖。", "病衰易感傷搖落，一夜西風枕上驚。"]'),
('4cf1abc4-97d3-4462-9a12-570ce480efe6','天輔歸休再用前韵并其弟恪子勉所和詩見寄再酬之','李復','宋','宋诗','song-poetry','','[]','西北秋風動碧雲，經年忽忽慘離羣。',64,'全唐诗/poet.song.61000.json','["西北秋風動碧雲，經年忽忽慘離羣。", "去辭北闕投新綬，歸老東山綴舊文。", "詩遇惠連須長價，書從阿買可張軍。", "平生勝理思懸解，糟粕徒觀愧運斤。"]'),
('23ccb2d4-85ed-4863-aa9e-d9061f9165c9','同君俞自牛頭寺至興教院又會文師','李復','宋','宋诗','song-poetry','','[]','杜曲樊川舊化城，東西相峙兩牛鳴。',64,'全唐诗/poet.song.61000.json','["杜曲樊川舊化城，東西相峙兩牛鳴。", "巖前寶塔藏遺燼，殿裏長燈續舊明。", "萬法分流皆有相，一心息妄自無生。", "叢林是處經行徧，會向東山記姓名。"]'),
('75ca6c19-cdcc-4868-8754-60682fd3455d','贈楷長老','李復','宋','宋诗','song-poetry','','[]','靈源獨耀脫根塵，豈論空身與色身。',64,'全唐诗/poet.song.61000.json','["靈源獨耀脫根塵，豈論空身與色身。", "若論有無寧見法，須知開悟不因人。", "病瘖得味難形語，走餓還家忽忘貧。", "薪火相交多少險，煩師與衆指迷津。"]'),
('02ada52a-df6a-4327-847a-550d7538c47d','天竺僧金總持','李復','宋','宋诗','song-poetry','','[]','金輪風火轉無涯，震旦觀光渡海沙。',64,'全唐诗/poet.song.61000.json','["金輪風火轉無涯，震旦觀光渡海沙。", "八萬言詮歸貝葉，三千世界聚蓮花。", "有緣禽鳥來波第，隨喜天人盡木叉。", "今古少林風月在，閉門常御白牛車。"]'),
('350ff880-e38c-47b6-b004-fb73e6db3e39','蔡元度話其子能言前世事江晦叔有詩次韵  其一','李復','宋','宋诗','song-poetry','','[]','應感隨緣各有因，一源真寂自無塵。',64,'全唐诗/poet.song.61000.json','["應感隨緣各有因，一源真寂自無塵。", "須知此物非他物，能悟前身是後身。", "叔子探環喬木在，房公發石舊書新。", "區中誰是王文度，證印曾逢竺上人。"]'),
('b05c3491-9b3a-4541-98ec-5342c750c934','蔡元度話其子能言前世事江晦叔有詩次韵  其二','李復','宋','宋诗','song-poetry','','[]','往來積習幾生身，石上精魂世共聞。',64,'全唐诗/poet.song.61000.json','["往來積習幾生身，石上精魂世共聞。", "北澗水通南澗水，南山雲繞北山雲。", "光含衆色珠常靜，影入千溪月不分。", "試向道人談實相，神奇腐臭但紛紛。"]'),
('995ebc75-afaf-43d2-930a-c04cf141c3fa','次韵錢穆父內翰題劉掾詩集','李復','宋','宋诗','song-poetry','','[]','朱絃曾聞三歎曲，青松自長千歲枝。',64,'全唐诗/poet.song.61000.json','["朱絃曾聞三歎曲，青松自長千歲枝。", "意來是有我輩語，佳處只應能者知。", "舊心洗盡萬斛水，新愁誰爭半額眉。", "清興飄飄仙奕奕，欲遊天外戲雲螭。"]'),
('9f0f8078-db9a-46f8-8f40-27cc5207132c','依韵酬張公燮','李復','宋','宋诗','song-poetry','','[]','城下清溪照病容，溪邊開席豆籩豐。',64,'全唐诗/poet.song.61000.json','["城下清溪照病容，溪邊開席豆籩豐。", "故應舉酒殷勤處，欲慰疏花索莫中。", "短髮蕭蕭羞帽側，强顔咄咄學書空。", "青山行卜他年樂，深結茅廬訪德公。"]'),
('beec4971-802e-44b0-99d4-71c8feacbdf2','次韵李信叔','李復','宋','宋诗','song-poetry','','[]','不見吟翁近十年，驛亭相遇兩欣然。',64,'全唐诗/poet.song.61000.json','["不見吟翁近十年，驛亭相遇兩欣然。", "旋臨野岸烹河鯉，賸向鄰家送酒錢。", "對雨張燈留夜榻，傍籬繫柳泊歸船。", "此生自斷君休問，早晚須芸杜曲田。"]'),
('5048da1d-a027-464a-9418-194b6424aa28','和徐發承議懷歸','李復','宋','宋诗','song-poetry','','[]','駸駸長路倦羸驂，搔首飛塵苦戰酣。',64,'全唐诗/poet.song.61000.json','["駸駸長路倦羸驂，搔首飛塵苦戰酣。", "猿過故山驚曉帳，苔生舊釣暗秋潭。", "土風膏潤田耕熟，物意清幽井汲甘。", "一別幾年勞客夢，會携藜杖破晴嵐。"]'),
('6ecfeb8d-e94a-459d-9704-fcd6d814b902','和胡吏部醇夫','李復','宋','宋诗','song-poetry','','[]','妙語飄飄慰旅窮，自憐饑味得甘豐。',64,'全唐诗/poet.song.61000.json','["妙語飄飄慰旅窮，自憐饑味得甘豐。", "朱絃恨廢高山久，明月驚投按劍中。", "垂翅爲逢勍敵勇，傾囊但媿鄙夫空。", "相從知便忘形跡，一鶚先曾玷至公。"]'),
('8f8b6d7f-2b47-4705-a825-5fe4ed15bc20','依韵酬蔡陽叔赴永倅留別','李復','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','朱紱翩翩別乘行，候人楚語喜秋晴。',64,'全唐诗/poet.song.61000.json','["朱紱翩翩別乘行，候人楚語喜秋晴。", "君山木落洞庭闊，帝子魂歸湘水清。", "曾嘆選官稱一字，舊聞世譽重三明。", "餟醨若訪垂綸客，葦岸夷猶鼓枻聲。"]'),
('1b4cb009-ee08-4a8e-b2cd-3b08478d7985','次韵呂元鈞給事嘉川驛來詩','李復','宋','宋诗','song-poetry','','[]','相逢莫厭重留連，邂逅浮雲只偶然。',64,'全唐诗/poet.song.61000.json','["相逢莫厭重留連，邂逅浮雲只偶然。", "前日一樽窮樂事，今朝千里感流年。", "塵侵遺跡留漳水，風入高吟動蜀鞭。", "錦鯉往來出江浦，應傳秀句滿嘉川。"]'),
('ce1d861f-6fc9-4835-a909-bf25b76f317a','送客至西湖','李復','宋','宋诗','song-poetry','','["\u897f\u6e56"]','湖亭獨往客初歸，春去春來盡不知。',64,'全唐诗/poet.song.61000.json','["湖亭獨往客初歸，春去春來盡不知。", "新竹出梢纔放籜，斷蒲經雨別生枝。", "山寒藏雪生雲濕，風送飛鷗過水遲。", "却笑偷閒得忙事，自尋鄰叟問鈎絲。"]'),
('caffe99e-69cd-47c5-b24c-cdc9cf7d0c18','吳安老罷制舉赴安吉任','李復','宋','宋诗','song-poetry','','[]','南北飛鴻迹影孤，青衫相見十年餘。',64,'全唐诗/poet.song.61000.json','["南北飛鴻迹影孤，青衫相見十年餘。", "中銓簡士歸繩墨，小邑沉才謹簿書。", "游刃屠龍傳世學，飛章薦鶚待公車。", "太平藻繪須文彩，今日何人誦子虛。"]'),
('0c6daa3a-4c39-4a45-895d-a22cd0fb7e3f','送衛奕之西河任','李復','宋','宋诗','song-poetry','','[]','藹藹長空春已歸，東風猶在綠楊枝。',64,'全唐诗/poet.song.61000.json','["藹藹長空春已歸，東風猶在綠楊枝。", "故人錯莫送行處，流水蒼茫無住時。", "汾上先生能理曲，河濱退老喜論詩。", "聞君此去追高躅，應忘青衫簿領卑。"]'),
('b495742f-556b-4054-ab7f-19985b0c8296','送孫甥','李復','宋','宋诗','song-poetry','','[]','瘦馬駸駸渡洛行，東風莫著褐衣輕。',64,'全唐诗/poet.song.61000.json','["瘦馬駸駸渡洛行，東風莫著褐衣輕。", "爲嫌愁夢能催老，故懶題封去問程。", "千仞會游懸水急，五漿須信客心驚。", "明朝我向壺關路，待約歸纓共濯清。"]'),
('e1e03cce-9c5e-46fa-8104-f61559d62529','送張景純','李復','宋','宋诗','song-poetry','','[]','我居杜陵君淮東，平生南北馬牛風。',64,'全唐诗/poet.song.61000.json','["我居杜陵君淮東，平生南北馬牛風。", "雲山一日邂逅見，草木千里臭味同。", "今朝歸心逐社燕，他日付書隨春鴻。", "不堪立馬向日暮，索莫酒散秋堂空。"]'),
('523ae7d9-daea-4953-8ff8-0d03d8112de2','送趙侗承議致仕歸','李復','宋','宋诗','song-poetry','','[]','聊爲五斗陶元亮，却愛三龍邴曼容。',64,'全唐诗/poet.song.61000.json','["聊爲五斗陶元亮，却愛三龍邴曼容。", "蕙帳曉空驚怨鶴，客衣夜薄感寒蛩。", "江邊朝露半紅葉，天際晚晴多碧峰。", "漠漠長空何處盡，雙鳬飛去曉雲重。"]'),
('6ac58a0a-0c0b-4769-bed1-a99c02e9c315','送董億朝奉','李復','宋','宋诗','song-poetry','','[]','北游汗漫遺玄珠，烟愁霧泣啼芙蕖。',64,'全唐诗/poet.song.61000.json','["北游汗漫遺玄珠，烟愁霧泣啼芙蕖。", "興來便脫上方屐，歸去重修繁露書。", "一夢百年依幻宅，五湖千里御風輿。", "家山芋栗應常熟，坐看朝三戲衆狙。"]'),
('ef97b698-ec6b-415d-a592-e26ef95231fa','送陽孝章戶曹','李復','宋','宋诗','song-poetry','','[]','前生問學仰前修，親髮星星祿始謀。',64,'全唐诗/poet.song.61000.json','["前生問學仰前修，親髮星星祿始謀。", "千里束書來北闕，一朝懷牒走南州。", "荷衣未改斑衣戲，斗米聊寬負米求。", "想見江神能世態，開帆風滿送歸舟。"]'),
('8cdbeb12-1499-4db8-9db7-31047214b7c5','送人從辟','李復','宋','宋诗','song-poetry','','[]','秋風蕭索塞雲黄，白髮青衫應辟章。',64,'全唐诗/poet.song.61000.json','["秋風蕭索塞雲黄，白髮青衫應辟章。", "曾說穰侯常畏客，今觀毛遂欲投囊。", "雁門舊障雲松盡，離石新城壠穀荒。", "想有高談開玉帳，尊前妍論灑珠光。"]'),
('24785073-ea79-4899-8088-b52fa8d05dd0','李無玷自左正言出守永州召爲吏曹外郎尚阻敘舊先貽此詩','李復','宋','宋诗','song-poetry','','[]','初伏青蒲拜皂囊，忽驅五馬下瀟湘。',64,'全唐诗/poet.song.61000.json','["初伏青蒲拜皂囊，忽驅五馬下瀟湘。", "入承上閤尚書牒，分掌中銓吏部郎。", "焚藁舊垣猶寂寞，拱樞列宿頓輝光。", "聞歸未便能傾倒，五日朝班得綴行。"]'),
('aca9ffb9-1e29-423a-9537-2280b8af6d7a','用周作韵送范忱夫舉歸','李復','宋','宋诗','song-poetry','','[]','白日高懸照九垓，天門欲上却飛回。',64,'全唐诗/poet.song.61000.json','["白日高懸照九垓，天門欲上却飛回。", "雖聞西蜀題橋去，未放東都走馬來。", "豐劍有神須會合，荆珉藴璞且徘徊。", "明年八翮乘風起，一振鵬程九萬開。"]'),
('dce79a45-a6e9-413c-a666-848adf1e914d','贈張萬戶征閩凱還','李復','宋','宋诗','song-poetry','','[]','瘴雨蠻烟遠蔽空，只將談笑蕩羣凶。',64,'全唐诗/poet.song.61000.json','["瘴雨蠻烟遠蔽空，只將談笑蕩羣凶。", "旌旗夜捲妖星殞，鼓角秋高殺氣雄。", "已喜張良還灞上，更須龔遂守閩中。", "凱歌聲動天顔喜，金虎三珠擬報功。"]'),
('b7fa72eb-c2e6-40ca-b6dc-bcaea7500edc','寄吏部王侍郎','李復','宋','宋诗','song-poetry','','[]','國門一別四經秋，新命恭承自冕旒。',64,'全唐诗/poet.song.61000.json','["國門一別四經秋，新命恭承自冕旒。", "碧落神仙來禁闥，青天雲霧隔皇州。", "孔鸞筆下鶱光翠，涇渭胸中有品流。", "聞說絲綸推世譽，佩聲好聽上鰲頭。"]'),
('49d98b63-e1f3-47ba-85e5-f3fa94a44252','答董天隠推官','李復','宋','宋诗','song-poetry','','[]','日月沄沄不可追，神奇腐臭略無遺。',64,'全唐诗/poet.song.61000.json','["日月沄沄不可追，神奇腐臭略無遺。", "一丘一壑能誰過，相煦相濡莫我知。", "强聒睢盱何所補，雄誇凌厲亦奚爲。", "秋來春去尋常事，安得乾坤獨爾私。"]'),
('8af495aa-c78a-4497-a7d1-792103889538','答潞城令谷大同','李復','宋','宋诗','song-poetry','','[]','蕭條寒邑古風深，應嘆光陰恨陸沉。',64,'全唐诗/poet.song.61000.json','["蕭條寒邑古風深，應嘆光陰恨陸沉。", "莫厭荒山輕廩粟，須思美政慰民心。", "門連露草常封印，吏散秋堂靜試琴。", "欲約仙鳬終未得，東城何日聽車音。"]'),
('93e40265-fde2-4857-abed-4e06c75d6d8e','酬張法掾翼求侍養歸','李復','宋','宋诗','song-poetry','','[]','少輕紈綺襲箕裘，力學從容與我謀。',64,'全唐诗/poet.song.61000.json','["少輕紈綺襲箕裘，力學從容與我謀。", "擇友卜商能勝賜，舞風曾點自殊由。", "去乘汴水春舟疾，行過龜山楚客留。", "千里有聲如寄我，須尋臨潏舊林丘。"]'),
('8a371c5f-816a-4026-a639-7d0d26e1f8f9','謁冷朝奉路逢王才元舍人同往','李復','宋','宋诗','song-poetry','','[]','曉路髯翁已我先，清時有味獨君偏。',64,'全唐诗/poet.song.61000.json','["曉路髯翁已我先，清時有味獨君偏。", "柳深門掩徑未掃，花落鳥啼人尚眠。", "顛倒著衣驚應客，咄嗟解榻遽張筵。", "雲開日影斜閶闔，悵望歸程急馬鞭。"]'),
('3e0f79b8-6921-4e75-a21a-35aa9272992f','答李成季賀授直秘閣','李復','宋','宋诗','song-poetry','','[]','絕域經秋自乞還，粉闈春得綴星班。',64,'全唐诗/poet.song.61000.json','["絕域經秋自乞還，粉闈春得綴星班。", "詔趨龍幄登文陛，恩捧芝函入道山。", "曲學豈知新說美，蒼顔難伴後生閒。", "聞君此地淹徊久，悵望當年未及攀。"]'),
('a5f87019-54c9-42f2-9cb4-0da73322ae01','酬李公寅留別','李復','宋','宋诗','song-poetry','','[]','歸風何急動征車，幾夕相逢意有餘。',64,'全唐诗/poet.song.61000.json','["歸風何急動征車，幾夕相逢意有餘。", "綠暗河橋冰泮後，雲藏山徑雪晴初。", "登門曾上千重峻，游刃將驚萬窾虛。", "他日再來寧可約，北鴻時付一行書。"]'),
('713208f6-5b3e-4a2d-88bd-7b121d78cbde','別夔州衆官','李復','宋','宋诗','song-poetry','','[]','半年漁浦巴城守，兩任雲臺太華宮。',64,'全唐诗/poet.song.61000.json','["半年漁浦巴城守，兩任雲臺太華宮。", "豈欲背時聊免俗，但能省事略成風。", "玉泉古剎須留客，峽水安流好向東。", "祖帳聯翩催棹急，臨溪洒淚落丹楓。"]'),
('3dcc6f3b-e49e-4f8a-9f3d-b896e5bd4dd0','衛奕其兄被劾得雪惠書及詩','李復','宋','宋诗','song-poetry','','[]','去歲書傳歎鶺鴒，新詩甚喜字縱橫。',64,'全唐诗/poet.song.61000.json','["去歲書傳歎鶺鴒，新詩甚喜字縱橫。", "龜雖有智猶罹網，雁爲能鳴得免烹。", "須信篋中多謗語，莫矜堂上有奇兵。", "滔滔天下常如此，無慕功名取次行。"]'),
('25c983b4-5b61-49e9-88e0-baa0c55d570c','寄朱約之','李復','宋','宋诗','song-poetry','','[]','子墨文章不自珍，連編大軸棄如塵。',64,'全唐诗/poet.song.61000.json','["子墨文章不自珍，連編大軸棄如塵。", "久收幽履安巖谷，但見高名出搢紳。", "欲寄遠書尋素舸，今逢佳士得朱輪。", "放談可講平生學，新傳行觀盡獲麟。"]'),
('433b7e46-383c-4508-adfc-e8b3c0f71cea','寄舊同遊','李復','宋','宋诗','song-poetry','','[]','去鄉甲子四十二，歸路山川九百三。',64,'全唐诗/poet.song.61000.json','["去鄉甲子四十二，歸路山川九百三。", "長河無鯉來東北，遠夢隨月轉西南。", "簷花雨落春獨酌，窗竹燈寒夜對談。", "石上精魂能閱世，欲尋前事興方酣。"]');
